/* AUTO-GENERATED — Mississippi Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["MS"] = {"code":"MS","name":"Mississippi","agency":"Mississippi DPS","agencyShort":"DPS","handbook":"https://www.driverservicebureau.dps.ms.gov/node/374","links":{},"en":[{"q":"On Mississippi highways, what is the maximum legal width of a commercial vehicle (excluding required safety devices and mirrors)?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"answer":1,"explanation":"Mississippi limits vehicle width to 8 feet 6 inches (102 inches); a load wider than that requires an oversize permit. Source: Miss. Code Ann. Sec. 63-5-13 (Outside width of vehicles); MDOT Office of Enforcement Permit rules.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, including any load, on Mississippi highways?","options":["14 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 6 inches"],"answer":3,"explanation":"No vehicle, unladen or with load, may exceed a height of 13 feet 6 inches in Mississippi. Source: Miss. Code Ann. Sec. 63-5-17 (Height of vehicles).","handbook":"","hbref":""},{"q":"In Mississippi, what is the maximum gross weight (without any tolerance) for a vehicle or combination operating without a special permit?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"answer":2,"explanation":"The maximum gross vehicle weight without a permit is 80,000 pounds (a 2% tolerance may apply on top of that). Source: Miss. Code Ann. Sec. 63-5-33; MDOT Mississippi Maximum Weight Laws.","handbook":"","hbref":""},{"q":"What is the maximum gross weight Mississippi allows on a single axle?","options":["24,000 pounds","22,400 pounds","18,000 pounds","20,000 pounds"],"answer":3,"explanation":"The gross weight on any one single axle may not exceed 20,000 pounds (exclusive of statutory tolerance). Source: Miss. Code Ann. Sec. 63-5-27 (Wheel and axle loads); MDOT Maximum Weight Laws.","handbook":"","hbref":""},{"q":"What is the maximum gross weight Mississippi allows on a tandem axle?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"The gross weight on any tandem axle may not exceed 34,000 pounds (exclusive of statutory tolerance). Source: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws.","handbook":"","hbref":""},{"q":"Under Mississippi law, how is a 'single axle' defined for weight purposes?","options":["Any two consecutive axles more than 40 inches apart","Two or more axles spaced exactly 96 inches apart","A single wheel and tire assembly on each side of the vehicle","Two or more wheels in one transverse plane, or within parallel planes 40 inches apart"],"answer":3,"explanation":"A single axle is an assembly of two or more wheels whose centers are in one transverse vertical plane, or that fall between two parallel transverse planes 40 inches apart, across the full width of the vehicle. Source: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws.","handbook":"","hbref":""},{"q":"How does Mississippi law define a 'tandem axle' for weight purposes?","options":["Two or more consecutive axles with centers more than 40 inches but not more than 96 inches apart","Two axles with centers exactly 40 inches apart","Any group of axles spanning more than 96 inches","Two axles where one is a driving axle and one is a steering axle"],"answer":0,"explanation":"A tandem axle is any two or more consecutive axles whose centers are more than 40 inches but not more than 96 inches apart, and no one axle of the group may exceed the single-axle limit. Source: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws.","handbook":"","hbref":""},{"q":"On Mississippi highways, what is the maximum length of a single (straight) truck?","options":["40 feet","45 feet","48 feet","53 feet"],"answer":0,"explanation":"No single vehicle (straight truck) may exceed an overall length of 40 feet in Mississippi. Source: Miss. Code Ann. Sec. 63-5-19 (Vehicle length limitations).","handbook":"","hbref":""},{"q":"What is the maximum length of a semitrailer operating in a truck-tractor/semitrailer combination in Mississippi?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"A semitrailer operating in a truck-tractor/semitrailer combination may not exceed 53 feet in Mississippi. Source: Miss. Code Ann. Sec. 63-5-19 (Vehicle length limitations).","handbook":"","hbref":""},{"q":"To determine the maximum weight on any group of two or more consecutive axles, Mississippi applies which standard?","options":["A flat 80,000-pound cap regardless of spacing","The Federal Bridge Formula (weight tied to axle spacing)","The 550-pounds-per-inch tire-width rule only","The harvest-permit tolerance schedule"],"answer":1,"explanation":"Mississippi uses the Federal Bridge Formula, so the allowable weight on a group of axles depends on the distance between the extreme axles of the group. Source: Miss. Code Ann. Sec. 63-5-29/63-5-33 weight tables; MDOT Maximum Weight Laws.","handbook":"","hbref":""},{"q":"Mississippi's maximum gross weight of 80,000 pounds may be exceeded by what statutory tolerance for a vehicle operating WITHOUT a harvest permit?","options":["10%","5%","1%","2%"],"answer":3,"explanation":"The maximum gross vehicle weight may not exceed 80,000 pounds plus a tolerance of not more than 2%. Source: Miss. Code Ann. Sec. 63-5-33.","handbook":"","hbref":""},{"q":"What weight tolerance does Mississippi allow a vehicle operating WITH a harvest permit, above its authorized gross, tandem, or axle weight?","options":["2%","5%","10%","15%"],"answer":2,"explanation":"A harvest-permit vehicle is allowed a tolerance not to exceed 10% above its authorized gross, tandem, or axle weight (subject to the 88,000-pound cap). Source: Miss. Code Ann. Sec. 63-5-33.","handbook":"","hbref":""},{"q":"Which Mississippi agency issues oversize/overweight (over-dimensional) permits?","options":["The Mississippi Department of Transportation, Office of Enforcement Permit Division","The Mississippi Department of Public Safety, Driver Services","The Mississippi State Tax Commission","The county sheriff in the county of origin"],"answer":0,"explanation":"Over-dimensional permits are issued by the MDOT Office of Enforcement, Permit Division, under authority of the Mississippi Transportation Commission. Source: MDOT Over-Dimensional Permit Rules (Sub-Part 6601, Chapter 03001); Miss. Code Ann. Sec. 65-1-8.","handbook":"","hbref":""},{"q":"In Mississippi, a Single Trip over-dimensional permit authorizes movement for a period not to exceed how long?","options":["24 hours","Three consecutive days","Seven consecutive days","Thirty days"],"answer":1,"explanation":"A Single Trip Permit authorizes the movement of a specific vehicle/load for a period not to exceed three (3) consecutive days. Source: MDOT Over-Dimensional Permit Rules, Sec. 213 (Definitions).","handbook":"","hbref":""},{"q":"A non-divisible load is generally required to obtain a Mississippi oversize permit once its width exceeds what dimension?","options":["8 feet 0 inches","8 feet 6 inches","10 feet 0 inches","12 feet 0 inches"],"answer":1,"explanation":"A permit is required to move a load exceeding the legal 8-foot-6-inch (102-inch) width limit. Source: Miss. Code Ann. Sec. 63-5-13; MDOT Office of Enforcement Permit rules.","handbook":"","hbref":""},{"q":"Under Mississippi over-dimensional permit rules, at what load width do stricter 'daylight hours' and escort requirements take effect?","options":["Greater than 12 feet wide","Greater than 10 feet wide","Greater than 14 feet wide","Greater than 16 feet wide"],"answer":0,"explanation":"For loads greater than 12 feet in width, 'daylight hours' tighten to 30 minutes after sunrise to 30 minutes before sunset and additional escort requirements apply. Source: MDOT Over-Dimensional Permit Rules, Sec. 200.","handbook":"","hbref":""},{"q":"Mississippi caps single- and tandem-axle weights so that the gross weight does not exceed how many pounds per inch of tire width (subject to the axle maximums)?","options":["650 pounds per inch","600 pounds per inch","500 pounds per inch","550 pounds per inch"],"answer":3,"explanation":"Single or tandem axle gross weight may not exceed 550 pounds per inch of tire width (with a tolerance up to 500 pounds), never exceeding the 20,000/34,000-pound axle maximums. Source: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws.","handbook":"","hbref":""},{"q":"On Mississippi state highways (excluding the Interstate system), a registered vehicle measuring more than 29 feet between its extreme axles is treated, for bridge-formula weight purposes, as if that axle group were how much longer?","options":["6 feet longer","12 feet longer","20 feet longer","29 feet longer"],"answer":1,"explanation":"Under the Sec. 63-5-34 state-highways-only provision, such a vehicle is considered to have its extreme axle group spaced 12 feet longer than its actual measurement (this does not apply on the federal Interstate system). Source: Miss. Code Ann. Sec. 63-5-34; MDOT Maximum Weight Laws.","handbook":"","hbref":""},{"q":"For two consecutive sets of tandem axles to each carry 34,000 pounds (without exceeding 80,000 pounds gross) in Mississippi, the distance between the first and last axles of the sets must be at least what?","options":["30 feet","34 feet","36 feet","40 feet"],"answer":2,"explanation":"Two consecutive sets of tandem axles may each carry 34,000 pounds provided the overall distance between the first and last axles is 36 feet or more, with total gross not exceeding 80,000 pounds except as allowed by Sec. 63-5-33. Source: MDOT Maximum Weight Laws (Table III note); Miss. Code Ann. Sec. 63-5-33.","handbook":"","hbref":""},{"q":"In Mississippi, what is the minimum gross vehicle weight rating (GVWR) threshold that places a single commercial vehicle into the Class A or Class B category?","options":["26,001 pounds or more","10,001 pounds or more","18,001 pounds or more","33,001 pounds or more"],"answer":0,"explanation":"Mississippi defines Class B as any single vehicle with a GVWR of 26,001 pounds or more, and Class A as a combination of vehicles with a GVWR of 26,001 pounds or more (towing a unit over 10,000 lbs). Source: Mississippi DPS Driver Service Bureau, CDL Classes A-D page; Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Which Mississippi CDL class is required to operate any combination of vehicles with a GVWR of 26,001 pounds or more, where the vehicle being towed has a GVWR in excess of 10,000 pounds?","options":["Class B","Class A","Class C","Class D"],"answer":1,"explanation":"Mississippi Class A covers combination vehicles of 26,001 lbs or more GVWR towing a unit with a GVWR over 10,000 lbs. Source: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"A Mississippi driver operates a single straight truck rated at 30,000 pounds GVWR that does not tow anything. Which CDL class does this require?","options":["Class A","Class C","Class B","No CDL is required"],"answer":2,"explanation":"A single vehicle of 26,001 lbs or more GVWR (not towing a unit over 10,000 lbs) is a Class B vehicle in Mississippi. Source: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Under Mississippi rules, a vehicle that does not meet the Class A or B weight thresholds still requires a Class C CDL if it is designed to transport how many people (including the driver)?","options":["8 or more","11 or more","24 or more","16 or more"],"answer":3,"explanation":"Mississippi Class C applies to a vehicle under the Class A/B weight thresholds that is designed to transport 16 or more passengers including the driver, or that carries placarded hazardous materials. Source: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Besides the 16-passenger rule, what other condition causes a smaller vehicle to require a Class C CDL in Mississippi?","options":["It is registered for commercial use","It transports hazardous materials in amounts requiring placarding","It crosses a state line","It is owned by a motor carrier"],"answer":1,"explanation":"A vehicle below the Class A/B weight limits requires a Class C CDL if it is used to transport hazardous materials in a quantity requiring placards. Source: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Which CDL endorsement is required in Mississippi to transport hazardous materials in placarded quantities?","options":["N endorsement","T endorsement","H endorsement","X endorsement only"],"answer":2,"explanation":"The H (HazMat) endorsement is required to haul placarded hazardous materials. The X endorsement is a combined HazMat-plus-Tank endorsement and is not required by drivers who only need HazMat. Source: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"In Mississippi, which endorsement authorizes a CDL holder to drive a tank vehicle (tanker)?","options":["T endorsement","P endorsement","S endorsement","N endorsement"],"answer":3,"explanation":"The N endorsement is the tank vehicle (tanker) endorsement. T is doubles/triples, P is passenger, and S is school bus. Source: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which Mississippi CDL endorsement is needed to pull double or triple trailers?","options":["T endorsement","N endorsement","H endorsement","P endorsement"],"answer":0,"explanation":"The T endorsement (doubles/triples) is required to tow double or triple trailers and is obtained by a knowledge test only. Source: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"What does the X endorsement on a Mississippi CDL represent?","options":["An expired endorsement pending renewal","An exemption from the medical certificate","A combination of HazMat (H) and Tank (N) endorsements","An out-of-state reciprocity endorsement"],"answer":2,"explanation":"Mississippi lists X as the combined HazMat-and-Tank endorsement, issued when a driver qualifies for both H and N. Source: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"To drive a school bus in Mississippi, which combination of endorsements must a CDL holder obtain?","options":["Only the S (school bus) endorsement","Only the P (passenger) endorsement","The T (doubles/triples) endorsement","Both the P (passenger) and S (school bus) endorsements"],"answer":3,"explanation":"Mississippi school bus drivers must hold both the Passenger (P) and School Bus (S) endorsements; the S endorsement builds on the P endorsement. Source: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.93.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Mississippi CDL valid only for intrastate (within-state) driving?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"Mississippi allows a CDL at age 18 for intrastate commerce only; interstate driving requires age 21. Source: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11.","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle across state lines (interstate) with a Mississippi CDL?","options":["18 years old","21 years old","19 years old","25 years old"],"answer":1,"explanation":"Drivers must be at least 21 to operate in interstate commerce and to hold HazMat or passenger endorsements for interstate work. Source: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 391.11.","handbook":"","hbref":""},{"q":"In Mississippi, what minimum age is required before a driver may receive a HazMat (H) or passenger (P) endorsement for interstate operation?","options":["18 years old","19 years old","23 years old","21 years old"],"answer":3,"explanation":"Mississippi requires a driver to be at least 21 to be issued HazMat or passenger endorsements for interstate commerce, consistent with federal rules. Source: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11.","handbook":"","hbref":""},{"q":"After obtaining a Commercial Learner Permit (CLP) in Mississippi, how long must a driver hold it before being allowed to take the CDL skills (road) test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Federal rule adopted by Mississippi requires the CLP to be held for a minimum of 14 days before the applicant may take the CDL skills test. Source: Mississippi CDL Manual; FMCSA 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is a Mississippi Commercial Learner Permit (CLP) valid before it must be renewed or the CDL obtained?","options":["30 days","180 days (6 months)","1 year","90 days"],"answer":1,"explanation":"A Mississippi CLP is valid for 180 days (six months); states may allow one renewal for an additional 180 days. Source: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Which endorsement is NOT permitted to be placed on a Mississippi Commercial Learner Permit (CLP)?","options":["The N (tank) endorsement, when the tank is empty","The P (passenger) endorsement","The H (HazMat) endorsement","The S (school bus) endorsement"],"answer":2,"explanation":"Federal rules adopted by Mississippi prohibit the HazMat (H) endorsement on a CLP; only P, S, and N endorsements may appear on a CLP, with restrictions. Source: Mississippi CDL Manual; FMCSA 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Where does a Mississippi applicant now complete the fingerprinting and TSA background check required for a HazMat (H) endorsement?","options":["Through the TSA Universal Enrollment Services provider (IdentoGO), not at the local DPS CDL station","At any local Mississippi DPS CDL station","At the FMCSA National Registry office","At the county circuit clerk's office"],"answer":0,"explanation":"Mississippi moved HazMat fingerprinting and enrollment to the TSA Universal Enrollment Services program (IdentoGO / universalenroll.dhs.gov); it is no longer done at local DPS CDL stations. Source: Mississippi DPS Driver Service Bureau, CDL HazMat Enrollment Program.","handbook":"","hbref":""},{"q":"Since February 7, 2022, first-time Mississippi CDL applicants must complete Entry-Level Driver Training (ELDT) provided by whom?","options":["Any Mississippi community college","The Mississippi DPS itself","An employer's in-house instructor of any kind","A provider listed on the FMCSA Training Provider Registry"],"answer":3,"explanation":"Effective February 7, 2022, first-time CDL applicants (and certain upgrades/endorsements) must complete ELDT from a provider listed on the FMCSA Training Provider Registry before the CDL test. Source: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR Part 380.","handbook":"","hbref":""},{"q":"When a Mississippi CDL applicant self-certifies their type of driving, which category indicates they operate in interstate commerce and must meet the federal DOT medical certificate requirements?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":1,"explanation":"Mississippi uses the four federal self-certification categories. Non-Excepted Interstate (NI) drivers operate across state lines and must hold a valid DOT medical examiner's certificate. Source: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which set of documents must a Mississippi CDL applicant present to satisfy identity/lawful presence, Social Security, and residency requirements?","options":["A high school diploma, a voter card, and one utility bill","A passport only, with no residency proof needed","An original birth certificate (or lawful-presence proof), Social Security number documentation, and two proofs of Mississippi residency","A vehicle title, an insurance card, and a fishing license"],"answer":2,"explanation":"Mississippi requires proof of identity/lawful presence (e.g., original birth certificate), Social Security number documentation, and two proofs of residency, plus a valid medical card, to apply for a CDL. Source: Mississippi DPS Driver Service Bureau, CDL applicant requirements.","handbook":"","hbref":""},{"q":"In Mississippi, what is the maximum blood/breath alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle?","options":["0.02","0.04","0.08","0.10"],"answer":1,"explanation":"Mississippi follows the federal CMV standard: it is unlawful to operate a commercial motor vehicle with an alcohol concentration of 0.04% or more. A reading of 0.04% or higher is grounds for a first major-offense disqualification. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51; Mississippi CDL Manual (DPS).","handbook":"","hbref":""},{"q":"A Mississippi CDL holder is convicted of a first offense of operating a CMV with a BAC of 0.04% while NOT carrying placarded hazardous materials. For how long is the driver disqualified from operating a CMV?","options":["6 months","1 year","3 years","Lifetime"],"answer":1,"explanation":"A first major offense (including driving a CMV with BAC 0.04% or more) results in a minimum 1-year CDL disqualification in Mississippi. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"If a Mississippi CDL holder commits a first major offense (such as DUI in a CMV) WHILE transporting placarded hazardous materials, the disqualification period increases to:","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"Under Mississippi and federal rules, a first major offense committed while transporting placarded hazardous materials carries a 3-year disqualification instead of the standard 1 year. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Mississippi CDL holder convicted of a SECOND major offense (for example, a second DUI in a CMV)?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second conviction for any major offense results in a lifetime CDL disqualification in Mississippi. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(3); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"In Mississippi, what happens to a CDL holder's commercial driving privilege if they refuse to submit to a chemical test of breath or blood when lawfully requested?","options":["A warning is issued with no disqualification","Disqualification for 30 days","Disqualification for 1 year","Disqualification for 90 days"],"answer":2,"explanation":"Refusal of chemical testing is treated as a major offense; under Mississippi's implied-consent law a CDL is disqualified for at least 1 year for a first refusal. Source: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Under Mississippi's implied-consent law, by operating any motor vehicle on a Mississippi highway a driver is deemed to have:","options":["Waived the right to an attorney","Given consent to a chemical test of breath, blood, or urine","Agreed to random roadside inspections","Accepted automatic license points"],"answer":1,"explanation":"Mississippi's implied-consent statute provides that any person who drives on the state's roads is deemed to have given consent to a chemical test to determine alcohol or drug concentration. Source: Miss. Code Ann. 63-11-5, 63-11-30; Mississippi CDL Manual (DPS).","handbook":"","hbref":""},{"q":"How many serious traffic violations (in separate incidents) within a 3-year period trigger a 60-day CDL disqualification in Mississippi?","options":["1","2","3","4"],"answer":1,"explanation":"Two serious traffic violations within a 3-year period (arising from separate incidents) result in a 60-day disqualification. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"In Mississippi, conviction of THREE serious traffic violations within a 3-year period results in a CDL disqualification of:","options":["60 days","90 days","120 days","1 year"],"answer":2,"explanation":"Three serious traffic violations within 3 years (separate incidents) result in a 120-day disqualification, which is served consecutively after any earlier 60-day disqualification. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a Mississippi CDL holder?","options":["Operating a CMV with BAC of 0.04% or more","Speeding 15 mph or more over the posted limit","Refusing a chemical test","Leaving the scene of an accident"],"answer":1,"explanation":"Speeding 15 mph or more over the limit is a serious traffic violation. The other three listed are major offenses carrying a 1-year (or longer) disqualification, not serious violations. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following is NOT counted as a serious traffic violation for a Mississippi CDL holder?","options":["Following the vehicle ahead too closely","Reckless driving","Making erratic or improper lane changes","Improperly parking an unattended CMV overnight"],"answer":3,"explanation":"Following too closely, reckless driving, and erratic/improper lane changes are all serious traffic violations. Routine parking of an unattended vehicle is not on the serious-violation list. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"A Mississippi CDL driver who texts or uses a hand-held mobile phone while driving a CMV commits what kind of violation?","options":["A non-reportable infraction","A serious traffic violation","A major offense","An out-of-service violation"],"answer":1,"explanation":"Texting or using a hand-held phone while driving a CMV is a serious traffic violation; two or three such serious violations within 3 years can lead to a 60- or 120-day disqualification. Source: 49 CFR 383.51(c), 392.80/392.82; Miss. Code Ann. 63-1-216; Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"A FIRST out-of-service order violation by a Mississippi CDL driver who is transporting placarded hazardous materials or 16 or more passengers carries a disqualification of:","options":["No less than 180 days, not more than 2 years","Exactly 180 days","No less than 60 days, not more than 1 year","Lifetime"],"answer":0,"explanation":"When a first out-of-service violation occurs while transporting placarded hazmat or carrying 16+ passengers, the disqualification is no less than 180 days and not more than 2 years. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(e); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"A Mississippi CDL driver convicted of a FIRST railroad-highway grade crossing violation while operating a CMV is disqualified for:","options":["No less than 30 days","No less than 60 days","No less than 120 days","1 year"],"answer":1,"explanation":"A first railroad-highway grade crossing violation results in a disqualification of no less than 60 days. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"What is the disqualification period for a Mississippi CDL driver's THIRD railroad-highway grade crossing violation within a 3-year period?","options":["120 days","6 months","1 year","Lifetime"],"answer":2,"explanation":"A third (or subsequent) railroad-grade-crossing violation within 3 years results in a disqualification of no less than 1 year. The progression is 60 days (first), 120 days (second), 1 year (third). Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"In Mississippi, a CDL holder who uses a commercial motor vehicle to commit a felony involving the manufacturing, distributing, or dispensing of a controlled substance is disqualified for:","options":["1 year","3 years","10 years","Lifetime, with no reinstatement"],"answer":3,"explanation":"Using a CMV in the commission of a felony involving controlled substances results in a lifetime disqualification that, unlike some lifetime disqualifications, cannot be reduced. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following is a MAJOR offense (1-year minimum disqualification) rather than a serious traffic violation in Mississippi?","options":["Following too closely","Leaving the scene of an accident involving a CMV","Speeding 15 mph over the limit","Improper lane change"],"answer":1,"explanation":"Leaving the scene of an accident involving a CMV is a major offense carrying a 1-year minimum disqualification. The other choices are serious traffic violations. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"In Mississippi, if a person refuses a chemical test while holding a CDL, the disqualification of the commercial privilege applies:","options":["Only if the driver was operating a CMV at the time","Only if the BAC later proves over 0.04%","Even if the refusal occurred while driving a personal (non-commercial) vehicle","Only after a second refusal"],"answer":2,"explanation":"A CDL holder is disqualified for refusing a chemical test even when the refusal occurs while operating a non-commercial vehicle; convictions and refusals in a personal vehicle still affect the CDL. Source: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51; Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"A Mississippi CDL driver receives a serious traffic violation in their PERSONAL vehicle that results in license suspension. How does this affect the CDL?","options":["It has no effect because it was not a CMV","It still counts toward CDL disqualification","It only counts if the driver was on duty","It only affects the hazmat endorsement"],"answer":1,"explanation":"Convictions and license actions in a personal vehicle count against the CDL; a suspension/revocation/cancellation of the driving privilege for certain serious violations leads to CDL disqualification. Source: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Under Mississippi's Move Over law, when you approach a stopped emergency or tow vehicle displaying flashing lights on a four-lane highway with two lanes going your direction, what must you do?","options":["Vacate the lane next to the stopped vehicle if it is safe to do so","Come to a complete stop until the stopped vehicle leaves","Sound your horn continuously while passing the vehicle","Maintain your speed and stay in your current lane"],"answer":0,"explanation":"Miss. Code 63-3-809 requires drivers on a roadway with at least four lanes (two or more in the same direction) to change into a lane not adjacent to the stationary emergency, recovery, or utility vehicle when safe. Source: Mississippi Code 63-3-809.","handbook":"","hbref":""},{"q":"Under Mississippi's Move Over law, if you cannot safely change lanes away from a stopped emergency vehicle that is displaying flashing lights, what are you required to do instead?","options":["Continue at the posted speed limit without changing anything","Stop in your lane and wait for an officer to wave you through","Slow down, proceed with caution, and be prepared to stop","Activate your hazard lights and pass at normal speed"],"answer":2,"explanation":"Miss. Code 63-3-809 directs a driver who cannot safely change lanes to reduce speed, proceed with due caution, and be prepared to stop. Source: Mississippi Code 63-3-809.","handbook":"","hbref":""},{"q":"In Mississippi, a violation of the Move Over law (63-3-809) that does NOT cause damage or injury is punishable by a fine of up to how much?","options":["Up to $100","Up to $250","Up to $500","Up to $1,000"],"answer":1,"explanation":"Miss. Code 63-3-809 sets a fine of up to $250 for a violation, rising to up to $1,000 if the violation causes property damage to the stationary vehicle or bodily injury to its occupants. Source: Mississippi Code 63-3-809.","handbook":"","hbref":""},{"q":"Besides authorized emergency vehicles, which of the following stopped vehicles displaying flashing warning lights does Mississippi's Move Over law (63-3-809) also protect?","options":["Only marked law enforcement vehicles","Only ambulances and fire apparatus","Recovery (tow) vehicles and utility service vehicles","Only vehicles owned by the state government"],"answer":2,"explanation":"Miss. Code 63-3-809 extends the move-over/slow-down duty to stationary authorized emergency vehicles as well as recovery (tow) and utility service vehicles using authorized flashing lights. Source: Mississippi Code 63-3-809.","handbook":"","hbref":""},{"q":"On most Mississippi interstate highways, the Mississippi Transportation Commission may set the maximum speed limit no higher than what value?","options":["65 mph","70 mph","75 mph","80 mph"],"answer":1,"explanation":"Miss. Code 63-3-501 caps the maximum speed the Transportation Commission may set on the Interstate Highway System and on four-or-more-lane controlled-access highways at 70 mph. Source: Mississippi Code 63-3-501.","handbook":"","hbref":""},{"q":"Under Mississippi Code 63-3-501, where a 70 mph limit is established on an interstate or four-lane U.S. highway, what MINIMUM speed applies to a vehicle that has a maximum speed restriction of 70 mph?","options":["30 mph","40 mph","45 mph","50 mph"],"answer":1,"explanation":"Miss. Code 63-3-501 establishes a 40 mph minimum speed for vehicles having a maximum speed restriction of 70 mph on such highways. Source: Mississippi Code 63-3-501.","handbook":"","hbref":""},{"q":"Under Mississippi law, when you stop a bus carrying passengers before crossing a railroad grade crossing, you must stop within how far from the nearest rail?","options":["Within 50 feet but not less than 15 feet","Within 25 feet but not less than 5 feet","Within 75 feet but not less than 25 feet","Within 100 feet but not less than 50 feet"],"answer":0,"explanation":"Miss. Code 63-3-1011 requires buses, vehicles carrying passengers for hire, school buses, and vehicles hauling explosives or flammable liquids to stop within 50 feet but not less than 15 feet from the nearest rail. Source: Mississippi Code 63-3-1011.","handbook":"","hbref":""},{"q":"According to the Mississippi CDL Manual, which commercial vehicles are always required to stop at railroad grade crossings?","options":["All commercial vehicles weighing over 10,000 pounds","Buses carrying passengers and vehicles hauling placarded hazardous materials","Only triple-trailer combinations","Any vehicle towing a trailer of any kind"],"answer":1,"explanation":"The Mississippi CDL Manual (mirroring 49 CFR 392.10 and Miss. Code 63-3-1011) requires buses carrying passengers and placarded hazmat vehicles to stop before crossing the tracks, then look and listen. Source: Mississippi CDL Manual / Miss. Code 63-3-1011.","handbook":"","hbref":""},{"q":"When required to stop at a railroad crossing in Mississippi, after stopping within the 15-to-50-foot zone the driver of a bus or placarded vehicle should cross the tracks how?","options":["Quickly, shifting up through the gears to clear the crossing fast","In a gear that allows completing the crossing without changing gears","In neutral, coasting across with the clutch depressed","Only after sounding the horn three times"],"answer":1,"explanation":"The Mississippi CDL Manual instructs drivers to cross in a gear that permits completing the crossing without shifting, and to not change gears while on the tracks. Source: Mississippi CDL Manual (railroad crossings).","handbook":"","hbref":""},{"q":"Under Mississippi's school bus law (Nathan's Law, 63-3-615), how close may a meeting or overtaking vehicle stop to a school bus that is loading or unloading children with its red lights flashing and stop arm out?","options":["Not less than 10 feet from the bus","Not less than 25 feet from the bus","Not less than 50 feet from the bus","Not less than 5 feet from the bus"],"answer":0,"explanation":"Miss. Code 63-3-615 requires meeting or overtaking drivers to stop not less than 10 feet from a school bus that is stopped to receive or discharge children. Source: Mississippi Code 63-3-615.","handbook":"","hbref":""},{"q":"On a Mississippi highway, under what condition does a driver NOT have to stop for a school bus that is stopped to load or unload children?","options":["Whenever the driver is traveling in the opposite direction on any two-lane road","When the bus is stopped on the opposing roadway of a divided highway of four or more lanes with at least two lanes in opposite directions","Whenever traffic is heavy and stopping would be inconvenient","When the driver is more than 100 feet from the bus"],"answer":1,"explanation":"Miss. Code 63-3-615 exempts a driver on a divided highway of four or more lanes (permitting at least two lanes of traffic in opposite directions) from stopping for a bus stopped in the opposing roadway. Source: Mississippi Code 63-3-615.","handbook":"","hbref":""},{"q":"Under Mississippi Code 63-3-615, the first-offense fine for illegally passing a stopped school bus is not less than what amount?","options":["Not less than $100","Not less than $200","Not less than $350","Not less than $1,000"],"answer":2,"explanation":"Miss. Code 63-3-615 sets a first-offense fine of not less than $350 nor more than $750 (and possible jail) for unlawfully passing a stopped school bus. Source: Mississippi Code 63-3-615.","handbook":"","hbref":""},{"q":"Under Mississippi's lane-use rules, a commercial vehicle proceeding slower than the normal speed of traffic must be driven where on a multilane highway?","options":["In the right-hand lane or as close as practicable to the right edge of the roadway","In the center lane at all times","In the left-hand lane to stay clear of merging traffic","In whichever lane has the least traffic"],"answer":0,"explanation":"Miss. Code 63-3-603 requires a vehicle going less than the normal speed of traffic to use the right-hand lane or stay as close as practicable to the right edge, except when passing or preparing for a left turn. Source: Mississippi Code 63-3-603.","handbook":"","hbref":""},{"q":"What does Mississippi Code 63-3-603 say about driving continuously in the far-left lane of a multilane roadway?","options":["It is allowed for trucks but prohibited for cars","It is prohibited whenever it impedes the flow of other traffic","It is required for all vehicles over 26,000 pounds","It is permitted at any time as long as you signal first"],"answer":1,"explanation":"Miss. Code 63-3-603 prohibits driving continuously in the outermost left lane of a multilane roadway whenever doing so impedes the flow of other traffic. Source: Mississippi Code 63-3-603.","handbook":"","hbref":""},{"q":"Per the Mississippi CDL Manual, when your commercial vehicle is stopped on the shoulder of a one-way or divided highway, where do you place your three warning triangles?","options":["At 10, 100, and 200 feet toward approaching traffic (all to the rear)","At 25 feet ahead, at the vehicle, and 25 feet behind","One at the vehicle and two side by side 50 feet behind","At 10, 100, and 200 feet both ahead of and behind the vehicle"],"answer":0,"explanation":"The Mississippi CDL Manual (per 49 CFR 392.22) directs placing triangles at 10, 100, and 200 feet toward approaching traffic on a one-way or divided highway. Source: Mississippi CDL Manual / 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Per the Mississippi CDL Manual, on a two-lane undivided road carrying traffic in both directions, where must warning devices be placed for a stopped commercial vehicle?","options":["All three within 10 feet behind the vehicle","Within 10 feet of the vehicle, plus 100 feet behind and 100 feet ahead","Only one device, 200 feet behind the vehicle","At 50 feet and 500 feet behind the vehicle"],"answer":1,"explanation":"The Mississippi CDL Manual (per 49 CFR 392.22) requires a device within 10 feet of the vehicle and devices about 100 feet behind and 100 feet ahead on a two-lane two-way road. Source: Mississippi CDL Manual / 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Per the Mississippi CDL Manual, after a commercial vehicle stops on a roadway or shoulder, within how many seconds must the driver set out emergency warning devices?","options":["Within 5 seconds","Within 10 minutes","Within 30 minutes","Within 1 hour"],"answer":1,"explanation":"The Mississippi CDL Manual (per 49 CFR 392.22) requires warning devices to be placed within 10 minutes of stopping; hazard flashers are used immediately and until the triangles are set. Source: Mississippi CDL Manual / 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Which Mississippi route, running diagonally across the state, prohibits commercial trucks (those over one-ton rated capacity) from using it?","options":["Interstate 55","U.S. Highway 49","The Natchez Trace Parkway","Interstate 20"],"answer":2,"explanation":"The Natchez Trace Parkway, a federally administered scenic route, bans commercial vehicles and trucks over one-ton rated capacity. Source: 36 CFR 7.43 / National Park Service.","handbook":"","hbref":""},{"q":"In Mississippi, what is the maximum legal vehicle width allowed on designated highways before an oversize permit is required?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"Mississippi's legal maximum width on designated highways is 8 feet 6 inches; loads wider than this require an oversize permit. Source: Mississippi DOT oversize/overweight permit rules.","handbook":"","hbref":""},{"q":"In Mississippi, what is the maximum legal gross vehicle weight on the interstate system before an overweight permit is required?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"answer":1,"explanation":"Mississippi follows the federal limit of 80,000 pounds maximum legal gross weight on the interstate system; exceeding it requires an overweight permit from MDOT. Source: Mississippi DOT overweight permit rules.","handbook":"","hbref":""},{"q":"Which Mississippi agency issues commercial driver licenses and administers CDL testing in the state?","options":["The Mississippi Department of Public Safety (DPS), through its Driver Service Bureau","The Mississippi Department of Transportation (MDOT)","The county Circuit Clerk's office where the driver resides","The Federal Motor Carrier Safety Administration (FMCSA)"],"answer":0,"explanation":"Mississippi CDLs are issued and CDL tests administered by the Mississippi Department of Public Safety (DPS) through its Driver Service Bureau. MDOT handles roads and permits, not licensing, and FMCSA sets federal standards but does not issue state licenses. Source: MS DPS Driver Service Bureau; Miss. Code Title 63, Chapter 1.","handbook":"","hbref":""},{"q":"What is the minimum passing score on the Mississippi CDL knowledge (written) exams?","options":["80%","70%","75%","90%"],"answer":0,"explanation":"Mississippi requires a minimum score of 80% on each required CDL knowledge exam, consistent with the federal AAMVA testing standard. Source: MS DPS / Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"Before a first-time Mississippi CDL applicant may take the required knowledge or skills tests, what training must be completed?","options":["Entry-Level Driver Training (ELDT) from an FMCSA-registered training provider","A defensive driving course approved by MDOT","A 40-hour classroom course at a community college","An apprenticeship logged with the Mississippi Trucking Association"],"answer":0,"explanation":"Since February 7, 2022, first-time CDL applicants must complete Entry-Level Driver Training (ELDT) from a provider listed on FMCSA's Training Provider Registry before taking the required skills or knowledge tests. Source: MS DPS Driver Service Bureau; FMCSA ELDT rule (49 CFR Part 380).","handbook":"","hbref":""},{"q":"How long must a Mississippi Commercial Learner's Permit (CLP) be held before the holder may take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 10 days","At least 60 days"],"answer":0,"explanation":"Mississippi follows the federal rule requiring a CLP to be held for a minimum of 14 days before the holder is eligible to take the CDL skills test. Source: MS DPS Driver Service Bureau; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"For how long is a Mississippi Commercial Learner's Permit (CLP) valid?","options":["6 months","1 year","30 days","90 days"],"answer":0,"explanation":"A Mississippi CLP is valid for 6 months (180 days), consistent with the federal maximum CLP validity period. Source: MS DPS Driver Service Bureau; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"The Mississippi CDL skills test consists of which three parts, performed in order?","options":["Pre-trip vehicle inspection, basic vehicle control, and on-road driving","Written knowledge test, air brakes test, and on-road driving","Pre-trip inspection, hazmat handling, and night driving","Basic vehicle control, coupling/uncoupling, and a written endorsement exam"],"answer":0,"explanation":"The Mississippi CDL skills test has three parts: the pre-trip vehicle inspection, the basic vehicle control skills test, and the on-road driving test. All three must be passed. Source: MS DPS / Mississippi CDL Manual.","handbook":"","hbref":""},{"q":"What is the term (validity period) of a Mississippi commercial driver license before it must be renewed?","options":["5 years, expiring on the licensee's birthday","4 years, expiring on the licensee's birthday","8 years, expiring on the licensee's birthday","2 years, tied to the medical certificate"],"answer":0,"explanation":"A Mississippi CDL is issued for a five-year term and expires at midnight on the licensee's birthday. Source: Miss. Code Ann. Sec. 63-1-47 (and Sec. 63-1-211).","handbook":"","hbref":""},{"q":"How early before its expiration date may a Mississippi CDL holder renew the license?","options":["Any time within 6 months before expiration","Only within 30 days before expiration","Any time within 90 days before expiration","Only on or after the expiration date"],"answer":0,"explanation":"Mississippi allows renewal any time within six (6) months before the license's expiration upon application and payment of the required fee, unless reexamination is required. Source: Miss. Code Ann. Sec. 63-1-47.","handbook":"","hbref":""},{"q":"When a CDL applicant self-certifies their type of driving with Mississippi DPS, how many self-certification categories are available to choose from?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"There are four self-certification categories: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, and Excepted Intrastate. The applicant must choose exactly one. Source: MS DPS Driver Service Bureau Self-Certification; 49 CFR 383.71(b).","handbook":"","hbref":""},{"q":"Which self-certification category in Mississippi applies to a driver who operates across state lines and is required to meet all federal medical qualification standards?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":0,"explanation":"Non-Excepted Interstate (NI) drivers operate in interstate commerce, must meet all federal DOT medical requirements, and must keep a current medical examiner's certificate on file. Source: MS DPS Self-Certification categories; 49 CFR 383.71(b).","handbook":"","hbref":""},{"q":"A Mississippi driver who self-certifies as Non-Excepted Interstate must keep what on file with DPS to maintain a valid CDL?","options":["A current DOT medical examiner's certificate","A current commercial general liability insurance certificate","A renewed CLP every six months","An MDOT oversize/overweight permit"],"answer":0,"explanation":"Non-Excepted Interstate (and Non-Excepted Intrastate) drivers must maintain a current DOT medical examiner's certificate on record with DPS; failure causes a downgrade. Source: MS DPS Medical Certification Requirements; 49 CFR 383.71/383.73.","handbook":"","hbref":""},{"q":"Effective June 23, 2025, how is a CDL driver's DOT medical examination result transmitted to the Mississippi DPS?","options":["The certified medical examiner electronically submits it to FMCSA's National Registry, which transmits it to DPS","The driver mails a paper copy of Form MCSA-5876 to DPS headquarters","The driver uploads a scanned copy through the DPS online portal","The employer faxes a copy to the local DPS driver license station"],"answer":0,"explanation":"Under the FMCSA final rule effective June 23, 2025, certified medical examiners submit exam results electronically to the National Registry, which transmits them to the state; Mississippi posts the result directly to the driver record. Source: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule.","handbook":"","hbref":""},{"q":"After the June 23, 2025 federal change, may a Mississippi driver license station accept a paper or scanned copy of the Medical Examiner's Certificate (Form MCSA-5876)?","options":["No; paper and scanned copies are no longer accepted, as results come electronically from the National Registry","Yes; paper copies remain the primary method of submission","Yes, but only if notarized within 15 days of the exam","Yes, but only for intrastate (NA) drivers"],"answer":0,"explanation":"As of June 23, 2025, DPS stations no longer accept physical or scanned MCSA-5876 copies; the medical exam result must be received electronically from FMCSA's National Registry. Source: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule.","handbook":"","hbref":""},{"q":"Under the FMCSA rule that Mississippi follows, by when must a certified medical examiner upload a CDL driver's exam result to the National Registry?","options":["By the end of the next calendar day after the exam","Within 30 days of the exam","Within 14 days of the exam","By the end of the same business week"],"answer":0,"explanation":"Under the rule effective June 23, 2025, the certified medical examiner must electronically upload examination results to the National Registry by midnight of the next calendar day following the examination. Source: FMCSA Medical Examiner's Certification Integration final rule, applied by MS DPS.","handbook":"","hbref":""},{"q":"What happens to a Mississippi CDL if a non-excepted driver lets their DOT medical certification lapse and does not update it?","options":["DPS downgrades the CDL, removing commercial driving privileges until certification is restored","The CDL is permanently revoked and cannot be reinstated","Nothing changes until the next 5-year renewal","The driver is automatically reclassified as Excepted Interstate"],"answer":0,"explanation":"A non-excepted driver who fails to keep medical certification current is changed to \"not-certified,\" and the state downgrades the CDL, removing commercial privileges until valid certification is again on file. Source: MS DPS Medical Certification Requirements; 49 CFR 383.73.","handbook":"","hbref":""},{"q":"Which documents are typically required when applying for a new Mississippi CDL at a DPS office?","options":["Proof of identity/birth, Social Security number, and two proofs of Mississippi residency","A passport only, with no other documentation needed","A high school diploma and three personal references","A vehicle title and proof of commercial auto insurance only"],"answer":0,"explanation":"A new CDL applicant must present proof of identity (such as a birth certificate), proof of the Social Security number, and two proofs of Mississippi residency, plus pass the required exams. Source: MS DPS Driver Service Bureau new CDL requirements.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Mississippi CDL limited to intrastate (within-state) commercial driving?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"A driver may obtain a CDL for intrastate operation at 18, but must be 21 for interstate operation and for transporting hazardous materials. Source: MS DPS / Mississippi CDL Manual; 49 CFR 383.3 / 391.11.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Mississippi CDL for interstate driving or for transporting placarded hazardous materials?","options":["21 years old","18 years old","23 years old","19 years old"],"answer":0,"explanation":"Federal rules adopted by Mississippi require a driver to be at least 21 to operate in interstate commerce and to transport placarded hazardous materials. Source: MS DPS / Mississippi CDL Manual; 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Who may legally administer the Mississippi CDL skills (road) test besides DPS examiners?","options":["State-approved Third-Party Testers/examiners","Any licensed CDL holder with two years' experience","The applicant's prospective employer's safety manager","Any FMCSA-registered ELDT classroom instructor"],"answer":0,"explanation":"Mississippi permits the CDL skills test to be given either by DPS examiners or by state-approved Third-Party Testers from the DPS-maintained list. Source: MS DPS Driver Service Bureau (Third-Party Tester program); 49 CFR 383.75.","handbook":"","hbref":""},{"q":"A Mississippi applicant fails only the on-road portion of the CDL skills test but passes the pre-trip inspection and basic control portions. What is the general result?","options":["The applicant must retake the on-road portion and does not yet receive the CDL","The applicant automatically receives a restricted intrastate CDL","All three skills portions must be retaken from the beginning","The applicant is issued the CDL because two of three portions passed"],"answer":0,"explanation":"All three skills components (pre-trip inspection, basic vehicle control, and on-road driving) must be passed to be issued a CDL; failing any one part means it must be retaken and the CDL is not issued until all are passed. Source: MS DPS / Mississippi CDL Manual; 49 CFR 383.113.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимально допустимая по закону ширина коммерческого транспортного средства на дорогах Миссисипи (без учёта обязательных устройств безопасности и зеркал)?","options":["8 футов 0 дюймов (96 дюймов)","8 футов 6 дюймов (102 дюйма)","9 футов 0 дюймов (108 дюймов)","10 футов 0 дюймов (120 дюймов)"],"explanation":"В Миссисипи ширина транспортного средства ограничена 8 футами 6 дюймами (102 дюйма); груз шире этого требует разрешения на негабарит. Источник: Miss. Code Ann. Sec. 63-5-13 (наружная ширина транспортных средств); правила выдачи разрешений MDOT Office of Enforcement."},"1":{"q":"Какова максимально допустимая по закону высота транспортного средства, включая любой груз, на дорогах Миссисипи?","options":["14 футов 6 дюймов","14 футов 0 дюймов","12 футов 6 дюймов","13 футов 6 дюймов"],"explanation":"Ни одно транспортное средство, порожнее или с грузом, не может превышать высоту 13 футов 6 дюймов в Миссисипи. Источник: Miss. Code Ann. Sec. 63-5-17 (высота транспортных средств)."},"2":{"q":"Какова в Миссисипи максимальная полная масса (без какого-либо допуска) для транспортного средства или автопоезда, работающего без специального разрешения?","options":["73 280 фунтов","76 000 фунтов","80 000 фунтов","88 000 фунтов"],"explanation":"Максимальная полная масса транспортного средства без разрешения составляет 80 000 фунтов (сверх этого может применяться допуск в 2%). Источник: Miss. Code Ann. Sec. 63-5-33; MDOT Mississippi Maximum Weight Laws."},"3":{"q":"Какую максимальную полную нагрузку Миссисипи допускает на одиночную ось?","options":["24 000 фунтов","22 400 фунтов","18 000 фунтов","20 000 фунтов"],"explanation":"Полная нагрузка на любую одиночную ось не может превышать 20 000 фунтов (без учёта установленного законом допуска). Источник: Miss. Code Ann. Sec. 63-5-27 (нагрузки на колёса и оси); MDOT Maximum Weight Laws."},"4":{"q":"Какую максимальную полную нагрузку Миссисипи допускает на сдвоенную ось (тандем)?","options":["32 000 фунтов","34 000 фунтов","36 000 фунтов","40 000 фунтов"],"explanation":"Полная нагрузка на любую сдвоенную ось (тандем) не может превышать 34 000 фунтов (без учёта установленного законом допуска). Источник: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"5":{"q":"Как закон Миссисипи определяет «одиночную ось» для целей определения нагрузки?","options":["Любые две последовательные оси, расположенные на расстоянии более 40 дюймов друг от друга","Две или более осей, расположенных ровно на 96 дюймов друг от друга","Один узел из колеса и шины с каждой стороны транспортного средства","Два или более колёс в одной поперечной плоскости или в пределах параллельных плоскостей, отстоящих на 40 дюймов"],"explanation":"Одиночная ось — это узел из двух или более колёс, центры которых находятся в одной поперечной вертикальной плоскости или попадают между двумя параллельными поперечными плоскостями, отстоящими на 40 дюймов друг от друга, по всей ширине транспортного средства. Источник: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"6":{"q":"Как закон Миссисипи определяет «сдвоенную ось» (тандем) для целей определения нагрузки?","options":["Две или более последовательные оси с центрами, отстоящими более чем на 40 дюймов, но не более чем на 96 дюймов","Две оси с центрами, отстоящими ровно на 40 дюймов","Любая группа осей протяжённостью более 96 дюймов","Две оси, одна из которых ведущая, а другая управляемая"],"explanation":"Сдвоенная ось (тандем) — это любые две или более последовательные оси, центры которых отстоят более чем на 40 дюймов, но не более чем на 96 дюймов друг от друга, и ни одна ось этой группы не может превышать предел для одиночной оси. Источник: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"7":{"q":"Какова на дорогах Миссисипи максимальная длина одиночного (рамного) грузовика?","options":["40 футов","45 футов","48 футов","53 фута"],"explanation":"Ни одно одиночное транспортное средство (рамный грузовик) не может превышать общую длину 40 футов в Миссисипи. Источник: Miss. Code Ann. Sec. 63-5-19 (ограничения длины транспортного средства)."},"8":{"q":"Какова максимальная длина полуприцепа, работающего в составе автопоезда тягач/полуприцеп в Миссисипи?","options":["48 футов","53 фута","57 футов","60 футов"],"explanation":"Полуприцеп, работающий в составе автопоезда тягач/полуприцеп, не может превышать 53 фута в Миссисипи. Источник: Miss. Code Ann. Sec. 63-5-19 (ограничения длины транспортного средства)."},"9":{"q":"Для определения максимальной нагрузки на любую группу из двух или более последовательных осей Миссисипи применяет какой стандарт?","options":["Фиксированный предел в 80 000 фунтов независимо от расстояния между осями","Федеральную мостовую формулу (Federal Bridge Formula) — нагрузка зависит от расстояния между осями","Только правило 550 фунтов на дюйм ширины шины","График допусков для уборочного разрешения"],"explanation":"Миссисипи использует Федеральную мостовую формулу (Federal Bridge Formula), поэтому допустимая нагрузка на группу осей зависит от расстояния между крайними осями группы. Источник: весовые таблицы Miss. Code Ann. Sec. 63-5-29/63-5-33; MDOT Maximum Weight Laws."},"10":{"q":"Максимальная полная масса в Миссисипи в 80 000 фунтов может быть превышена на какой установленный законом допуск для транспортного средства, работающего БЕЗ уборочного разрешения (harvest permit)?","options":["10%","5%","1%","2%"],"explanation":"Максимальная полная масса транспортного средства не может превышать 80 000 фунтов плюс допуск не более 2%. Источник: Miss. Code Ann. Sec. 63-5-33."},"11":{"q":"Какой весовой допуск Миссисипи разрешает транспортному средству, работающему С уборочным разрешением (harvest permit), сверх его разрешённой полной, тандемной или осевой массы?","options":["2%","5%","10%","15%"],"explanation":"Транспортному средству с уборочным разрешением допускается допуск не более 10% сверх его разрешённой полной, тандемной или осевой массы (при условии предела в 88 000 фунтов). Источник: Miss. Code Ann. Sec. 63-5-33."},"12":{"q":"Какое ведомство Миссисипи выдаёт разрешения на негабаритные/тяжеловесные (сверхгабаритные) перевозки?","options":["Mississippi Department of Transportation, Office of Enforcement Permit Division","Mississippi Department of Public Safety, Driver Services","Mississippi State Tax Commission","Шериф округа в округе отправления"],"explanation":"Разрешения на сверхгабаритные перевозки выдаются MDOT Office of Enforcement, Permit Division, в рамках полномочий Mississippi Transportation Commission. Источник: MDOT Over-Dimensional Permit Rules (Sub-Part 6601, Chapter 03001); Miss. Code Ann. Sec. 65-1-8."},"13":{"q":"В Миссисипи разрешение на сверхгабаритную одиночную поездку (Single Trip) разрешает перемещение на срок, не превышающий сколько?","options":["24 часа","Три дня подряд","Семь дней подряд","Тридцать дней"],"explanation":"Разрешение на одиночную поездку (Single Trip Permit) разрешает перемещение конкретного транспортного средства/груза на срок, не превышающий трёх (3) дней подряд. Источник: MDOT Over-Dimensional Permit Rules, Sec. 213 (Определения)."},"14":{"q":"Неделимый груз, как правило, обязан получить разрешение на негабарит в Миссисипи, как только его ширина превышает какой размер?","options":["8 футов 0 дюймов","8 футов 6 дюймов","10 футов 0 дюймов","12 футов 0 дюймов"],"explanation":"Разрешение требуется для перемещения груза, превышающего законный предел ширины в 8 футов 6 дюймов (102 дюйма). Источник: Miss. Code Ann. Sec. 63-5-13; правила выдачи разрешений MDOT Office of Enforcement."},"15":{"q":"Согласно правилам Миссисипи о сверхгабаритных разрешениях, при какой ширине груза вступают в силу более строгие требования «светлого времени суток» и требования сопровождения?","options":["Шире 12 футов","Шире 10 футов","Шире 14 футов","Шире 16 футов"],"explanation":"Для грузов шириной более 12 футов «светлое время суток» сужается до периода с 30 минут после восхода солнца до 30 минут до заката, и применяются дополнительные требования сопровождения. Источник: MDOT Over-Dimensional Permit Rules, Sec. 200."},"16":{"q":"Миссисипи ограничивает нагрузки на одиночную и сдвоенную (тандем) оси так, чтобы полная нагрузка не превышала сколько фунтов на дюйм ширины шины (при условии соблюдения максимумов на ось)?","options":["650 фунтов на дюйм","600 фунтов на дюйм","500 фунтов на дюйм","550 фунтов на дюйм"],"explanation":"Полная нагрузка на одиночную или сдвоенную ось не может превышать 550 фунтов на дюйм ширины шины (с допуском до 500 фунтов), никогда не превышая максимумов на ось в 20 000/34 000 фунтов. Источник: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"17":{"q":"На дорогах штата Миссисипи (за исключением системы межштатных автомагистралей Interstate) зарегистрированное транспортное средство с расстоянием более 29 футов между его крайними осями рассматривается, для целей весового расчёта по мостовой формуле, как если бы эта группа осей была насколько длиннее?","options":["На 6 футов длиннее","На 12 футов длиннее","На 20 футов длиннее","На 29 футов длиннее"],"explanation":"Согласно положению Sec. 63-5-34, применимому только к дорогам штата, такое транспортное средство считается имеющим расстояние между крайними осями группы на 12 футов больше его фактического измерения (это не применяется к федеральной системе Interstate). Источник: Miss. Code Ann. Sec. 63-5-34; MDOT Maximum Weight Laws."},"18":{"q":"Чтобы два последовательных комплекта сдвоенных осей (тандемов) могли каждый нести по 34 000 фунтов (не превышая 80 000 фунтов полной массы) в Миссисипи, расстояние между первой и последней осями этих комплектов должно составлять не менее чего?","options":["30 футов","34 фута","36 футов","40 футов"],"explanation":"Два последовательных комплекта сдвоенных осей (тандемов) могут каждый нести по 34 000 фунтов при условии, что общее расстояние между первой и последней осями составляет 36 футов или более, при общей полной массе, не превышающей 80 000 фунтов, за исключением случаев, допускаемых Sec. 63-5-33. Источник: MDOT Maximum Weight Laws (примечание к Table III); Miss. Code Ann. Sec. 63-5-33."},"19":{"q":"Каков в Миссисипи минимальный порог полной массы транспортного средства (GVWR), при котором одиночное коммерческое транспортное средство относится к категории Class A или Class B?","options":["26 001 фунт или более","10 001 фунт или более","18 001 фунт или более","33 001 фунт или более"],"explanation":"Миссисипи определяет Class B как любое одиночное транспортное средство с GVWR 26 001 фунт или более, а Class A — как автопоезд с GVWR 26 001 фунт или более (буксирующий единицу свыше 10 000 фунтов). Источник: Mississippi DPS Driver Service Bureau, страница CDL Classes A-D; Mississippi CDL Manual."},"20":{"q":"Какой класс CDL в Миссисипи требуется для управления любым автопоездом с GVWR 26 001 фунт или более, где буксируемое транспортное средство имеет GVWR свыше 10 000 фунтов?","options":["Class B","Class A","Class C","Class D"],"explanation":"Class A в Миссисипи охватывает автопоезда с GVWR 26 001 фунт или более, буксирующие единицу с GVWR свыше 10 000 фунтов. Источник: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"21":{"q":"Водитель в Миссисипи управляет одиночным рамным грузовиком с номинальной GVWR 30 000 фунтов, который ничего не буксирует. Какой класс CDL для этого требуется?","options":["Class A","Class C","Class B","CDL не требуется"],"explanation":"Одиночное транспортное средство с GVWR 26 001 фунт или более (не буксирующее единицу свыше 10 000 фунтов) является транспортным средством Class B в Миссисипи. Источник: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"22":{"q":"Согласно правилам Миссисипи, транспортное средство, не достигающее весовых порогов Class A или B, всё же требует CDL класса Class C, если оно предназначено для перевозки скольких человек (включая водителя)?","options":["8 или более","11 или более","24 или более","16 или более"],"explanation":"Class C в Миссисипи применяется к транспортному средству ниже весовых порогов Class A/B, которое предназначено для перевозки 16 или более пассажиров, включая водителя, или которое перевозит опасные материалы, требующие плакатов (placard). Источник: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"23":{"q":"Помимо правила о 16 пассажирах, какое ещё условие приводит к тому, что меньшее транспортное средство требует CDL класса Class C в Миссисипи?","options":["Оно зарегистрировано для коммерческого использования","Оно перевозит опасные материалы в количествах, требующих плакатов (placard)","Оно пересекает границу штата","Оно принадлежит автоперевозчику"],"explanation":"Транспортное средство ниже весовых пределов Class A/B требует CDL класса Class C, если оно используется для перевозки опасных материалов в количестве, требующем плакатов (placard). Источник: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"24":{"q":"Какой эндорсмент (endorsement) CDL требуется в Миссисипи для перевозки опасных материалов в количествах, требующих плакатов (placard)?","options":["Эндорсмент N","Эндорсмент T","Эндорсмент H","Только эндорсмент X"],"explanation":"Эндорсмент H (HazMat) требуется для перевозки опасных материалов, требующих плакатов (placard). Эндорсмент X — это совмещённый эндорсмент HazMat плюс цистерна, и он не требуется водителям, которым нужен только HazMat. Источник: Mississippi DPS Driver Service Bureau, список эндорсментов CDL; FMCSA 49 CFR 383.93."},"25":{"q":"Какой эндорсмент в Миссисипи разрешает держателю CDL управлять транспортным средством-цистерной (танкером)?","options":["Эндорсмент T","Эндорсмент P","Эндорсмент S","Эндорсмент N"],"explanation":"Эндорсмент N — это эндорсмент для транспортного средства-цистерны (танкера). T — это сдвоенные/строенные прицепы, P — пассажирский, S — школьный автобус. Источник: Mississippi DPS Driver Service Bureau, список эндорсментов CDL; FMCSA 49 CFR 383.93."},"26":{"q":"Какой эндорсмент CDL в Миссисипи необходим для буксировки сдвоенных или строенных прицепов?","options":["Эндорсмент T","Эндорсмент N","Эндорсмент H","Эндорсмент P"],"explanation":"Эндорсмент T (сдвоенные/строенные) требуется для буксировки сдвоенных или строенных прицепов и получается только по результатам теоретического теста. Источник: Mississippi DPS Driver Service Bureau, список эндорсментов CDL; FMCSA 49 CFR 383.93."},"27":{"q":"Что обозначает эндорсмент X на CDL в Миссисипи?","options":["Просроченный эндорсмент, ожидающий продления","Освобождение от медицинского сертификата","Сочетание эндорсментов HazMat (H) и цистерны (N)","Эндорсмент взаимного признания из другого штата"],"explanation":"Миссисипи указывает X как совмещённый эндорсмент HazMat и цистерны, выдаваемый, когда водитель квалифицируется для обоих эндорсментов — H и N. Источник: Mississippi DPS Driver Service Bureau, список эндорсментов CDL; FMCSA 49 CFR 383.93."},"28":{"q":"Чтобы управлять школьным автобусом в Миссисипи, какое сочетание эндорсментов должен получить держатель CDL?","options":["Только эндорсмент S (школьный автобус)","Только эндорсмент P (пассажирский)","Эндорсмент T (сдвоенные/строенные)","Оба эндорсмента: P (пассажирский) и S (школьный автобус)"],"explanation":"Водители школьных автобусов в Миссисипи должны иметь оба эндорсмента: пассажирский (P) и школьного автобуса (S); эндорсмент S надстраивается над эндорсментом P. Источник: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.93."},"29":{"q":"Каков минимальный возраст для получения CDL в Миссисипи, действительного только для вождения внутри штата (intrastate)?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Миссисипи разрешает CDL в возрасте 18 лет только для торговли внутри штата (intrastate); для межштатного вождения требуется возраст 21 год. Источник: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"30":{"q":"Каков минимальный возраст, требуемый для управления коммерческим транспортным средством через границы штатов (interstate) с CDL Миссисипи?","options":["18 лет","21 год","19 лет","25 лет"],"explanation":"Водителям должно быть не менее 21 года для работы в межштатной торговле и для получения эндорсментов HazMat или пассажирского для межштатной работы. Источник: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 391.11."},"31":{"q":"Какой минимальный возраст требуется в Миссисипи, прежде чем водитель может получить эндорсмент HazMat (H) или пассажирский (P) для межштатной работы?","options":["18 лет","19 лет","23 года","21 год"],"explanation":"Миссисипи требует, чтобы водителю было не менее 21 года для получения эндорсментов HazMat или пассажирского для межштатной торговли, в соответствии с федеральными правилами. Источник: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"32":{"q":"После получения коммерческого ученического разрешения (CLP) в Миссисипи, сколько времени водитель должен владеть им, прежде чем ему будет разрешено сдавать экзамен на навыки вождения (дорожный тест) CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Федеральное правило, принятое Миссисипи, требует владеть CLP минимум 14 дней, прежде чем кандидат сможет сдавать экзамен на навыки CDL. Источник: Mississippi CDL Manual; FMCSA 49 CFR 383.25."},"33":{"q":"Сколько времени действует коммерческое ученическое разрешение (CLP) Миссисипи, прежде чем его необходимо продлить или получить CDL?","options":["30 дней","180 дней (6 месяцев)","1 год","90 дней"],"explanation":"CLP в Миссисипи действителен 180 дней (шесть месяцев); штаты могут разрешить одно продление ещё на 180 дней. Источник: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.25."},"34":{"q":"Какой эндорсмент НЕ разрешается размещать на коммерческом ученическом разрешении (CLP) в Миссисипи?","options":["Эндорсмент N (цистерна), когда цистерна пустая","Эндорсмент P (пассажирский)","Эндорсмент H (HazMat)","Эндорсмент S (школьный автобус)"],"explanation":"Федеральные правила, принятые Миссисипи, запрещают эндорсмент HazMat (H) на CLP; на CLP могут присутствовать только эндорсменты P, S и N, с ограничениями. Источник: Mississippi CDL Manual; FMCSA 49 CFR 383.25."},"35":{"q":"Где теперь кандидат в Миссисипи проходит снятие отпечатков пальцев и проверку благонадёжности TSA, требуемые для эндорсмента HazMat (H)?","options":["Через провайдера TSA Universal Enrollment Services (IdentoGO), а не на местной станции CDL DPS","На любой местной станции CDL Mississippi DPS","В офисе FMCSA National Registry","В офисе окружного секретаря суда (circuit clerk)"],"explanation":"Миссисипи перенёс снятие отпечатков пальцев и регистрацию для HazMat в программу TSA Universal Enrollment Services (IdentoGO / universalenroll.dhs.gov); это больше не делается на местных станциях CDL DPS. Источник: Mississippi DPS Driver Service Bureau, CDL HazMat Enrollment Program."},"36":{"q":"С 7 февраля 2022 года кандидаты, впервые получающие CDL в Миссисипи, должны пройти обучение водителей начального уровня (ELDT), предоставляемое кем?","options":["Любым общественным колледжем Миссисипи","Самим Mississippi DPS","Штатным инструктором работодателя любого рода","Провайдером, включённым в FMCSA Training Provider Registry"],"explanation":"С 7 февраля 2022 года кандидаты, впервые получающие CDL (а также при определённых повышениях/эндорсментах), должны пройти ELDT у провайдера, включённого в FMCSA Training Provider Registry, до сдачи теста CDL. Источник: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR Part 380."},"37":{"q":"Когда кандидат на CDL в Миссисипи самостоятельно сертифицирует свой тип вождения, какая категория указывает, что он работает в межштатной торговле и должен соответствовать федеральным требованиям DOT о медицинском сертификате?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Миссисипи использует четыре федеральные категории самосертификации. Водители Non-Excepted Interstate (NI) работают через границы штатов и должны иметь действительный медицинский сертификат DOT (DOT medical examiner's certificate). Источник: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.71."},"38":{"q":"Какой набор документов должен предъявить кандидат на CDL в Миссисипи, чтобы выполнить требования по подтверждению личности/законного присутствия, номера социального страхования и проживания?","options":["Аттестат об окончании средней школы, карточку избирателя и один счёт за коммунальные услуги","Только паспорт, без необходимости подтверждения проживания","Оригинал свидетельства о рождении (или доказательство законного присутствия), документ с номером социального страхования и два подтверждения проживания в Миссисипи","Свидетельство о праве собственности на транспортное средство, страховую карту и лицензию на рыбную ловлю"],"explanation":"Миссисипи требует подтверждение личности/законного присутствия (например, оригинал свидетельства о рождении), документ с номером социального страхования и два подтверждения проживания, а также действительную медицинскую карту, для подачи заявления на CDL. Источник: Mississippi DPS Driver Service Bureau, требования к кандидатам на CDL."},"39":{"q":"Какова в Миссисипи максимальная концентрация алкоголя в крови/выдыхаемом воздухе (BAC), при которой лицо может законно управлять коммерческим транспортным средством?","options":["0.02","0.04","0.08","0.10"],"explanation":"Миссисипи следует федеральному стандарту для коммерческих ТС: управлять коммерческим транспортным средством с концентрацией алкоголя 0.04% или более незаконно. Показатель 0.04% или выше является основанием для дисквалификации за первое тяжкое нарушение. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51; Mississippi CDL Manual (DPS)."},"40":{"q":"Держатель CDL в Миссисипи осуждён за первое нарушение — управление коммерческим ТС с BAC 0.04%, при этом он НЕ перевозил опасные материалы, требующие плакатов (placard). На какой срок водитель дисквалифицируется от управления коммерческим ТС?","options":["6 месяцев","1 год","3 года","Пожизненно"],"explanation":"Первое тяжкое нарушение (включая управление коммерческим ТС с BAC 0.04% или более) влечёт минимальную дисквалификацию CDL на 1 год в Миссисипи. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"41":{"q":"Если держатель CDL в Миссисипи совершает первое тяжкое нарушение (например, вождение в нетрезвом виде на коммерческом ТС) ВО ВРЕМЯ перевозки опасных материалов, требующих плакатов (placard), срок дисквалификации увеличивается до:","options":["1 года","2 лет","3 лет","5 лет"],"explanation":"Согласно правилам Миссисипи и федеральным правилам, первое тяжкое нарушение, совершённое во время перевозки опасных материалов, требующих плакатов (placard), влечёт дисквалификацию на 3 года вместо стандартного 1 года. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual."},"42":{"q":"Каков срок дисквалификации для держателя CDL в Миссисипи, осуждённого за ВТОРОЕ тяжкое нарушение (например, второе вождение в нетрезвом виде на коммерческом ТС)?","options":["3 года","5 лет","10 лет","Пожизненно"],"explanation":"Второе осуждение за любое тяжкое нарушение влечёт пожизненную дисквалификацию CDL в Миссисипи. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(3); Mississippi CDL Manual."},"43":{"q":"Что происходит в Миссисипи с правом коммерческого вождения держателя CDL, если он отказывается пройти химический тест выдыхаемого воздуха или крови при законном требовании?","options":["Выдаётся предупреждение без дисквалификации","Дисквалификация на 30 дней","Дисквалификация на 1 год","Дисквалификация на 90 дней"],"explanation":"Отказ от химического тестирования рассматривается как тяжкое нарушение; согласно закону Миссисипи о подразумеваемом согласии CDL дисквалифицируется не менее чем на 1 год за первый отказ. Источник: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"44":{"q":"Согласно закону Миссисипи о подразумеваемом согласии, управляя любым транспортным средством на дороге Миссисипи, водитель считается:","options":["Отказавшимся от права на адвоката","Давшим согласие на химический тест выдыхаемого воздуха, крови или мочи","Согласившимся на случайные придорожные проверки","Принявшим автоматические штрафные баллы за права"],"explanation":"Закон Миссисипи о подразумеваемом согласии предусматривает, что любое лицо, управляющее транспортным средством на дорогах штата, считается давшим согласие на химический тест для определения концентрации алкоголя или наркотиков. Источник: Miss. Code Ann. 63-11-5, 63-11-30; Mississippi CDL Manual (DPS)."},"45":{"q":"Сколько серьёзных нарушений ПДД (в отдельных инцидентах) в течение 3-летнего периода влекут дисквалификацию CDL на 60 дней в Миссисипи?","options":["1","2","3","4"],"explanation":"Два серьёзных нарушения ПДД в течение 3-летнего периода (возникшие из отдельных инцидентов) влекут дисквалификацию на 60 дней. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"46":{"q":"В Миссисипи осуждение за ТРИ серьёзных нарушения ПДД в течение 3-летнего периода влечёт дисквалификацию CDL на:","options":["60 дней","90 дней","120 дней","1 год"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет (отдельные инциденты) влекут дисквалификацию на 120 дней, которая отбывается последовательно после любой предыдущей 60-дневной дисквалификации. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"47":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение ПДД для держателя CDL в Миссисипи?","options":["Управление коммерческим ТС с BAC 0.04% или более","Превышение скорости на 15 mph или более сверх установленного предела","Отказ от химического теста","Оставление места происшествия"],"explanation":"Превышение скорости на 15 mph или более сверх предела является серьёзным нарушением ПДД. Остальные три перечисленных — это тяжкие нарушения, влекущие дисквалификацию на 1 год (или более), а не серьёзные нарушения. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"48":{"q":"Что из перечисленного НЕ засчитывается как серьёзное нарушение ПДД для держателя CDL в Миссисипи?","options":["Слишком близкое следование за впереди идущим транспортным средством","Безрассудное вождение (reckless driving)","Беспорядочное или неправильное перестроение по полосам","Неправильная парковка оставленного без присмотра коммерческого ТС на ночь"],"explanation":"Слишком близкое следование, безрассудное вождение и беспорядочное/неправильное перестроение по полосам — всё это серьёзные нарушения ПДД. Обычная парковка оставленного без присмотра транспортного средства не входит в список серьёзных нарушений. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"49":{"q":"Водитель CDL в Миссисипи, который пишет сообщения или пользуется ручным мобильным телефоном во время управления коммерческим ТС, совершает какое нарушение?","options":["Незарегистрируемое правонарушение","Серьёзное нарушение ПДД","Тяжкое нарушение","Нарушение приказа о выводе из эксплуатации (out-of-service)"],"explanation":"Написание сообщений или использование ручного телефона во время управления коммерческим ТС является серьёзным нарушением ПДД; два или три таких серьёзных нарушения в течение 3 лет могут привести к дисквалификации на 60 или 120 дней. Источник: 49 CFR 383.51(c), 392.80/392.82; Miss. Code Ann. 63-1-216; Mississippi CDL Manual."},"50":{"q":"ПЕРВОЕ нарушение приказа о выводе из эксплуатации (out-of-service) водителем CDL в Миссисипи, который перевозит опасные материалы, требующие плакатов (placard), или 16 и более пассажиров, влечёт дисквалификацию на:","options":["Не менее 180 дней, не более 2 лет","Ровно 180 дней","Не менее 60 дней, не более 1 года","Пожизненно"],"explanation":"Когда первое нарушение приказа о выводе из эксплуатации происходит во время перевозки опасных материалов, требующих плакатов (placard), или 16+ пассажиров, дисквалификация составляет не менее 180 дней и не более 2 лет. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(e); Mississippi CDL Manual."},"51":{"q":"Водитель CDL в Миссисипи, осуждённый за ПЕРВОЕ нарушение на железнодорожном переезде во время управления коммерческим ТС, дисквалифицируется на:","options":["Не менее 30 дней","Не менее 60 дней","Не менее 120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде влечёт дисквалификацию не менее чем на 60 дней. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual."},"52":{"q":"Каков срок дисквалификации за ТРЕТЬЕ нарушение на железнодорожном переезде водителем CDL в Миссисипи в течение 3-летнего периода?","options":["120 дней","6 месяцев","1 год","Пожизненно"],"explanation":"Третье (или последующее) нарушение на железнодорожном переезде в течение 3 лет влечёт дисквалификацию не менее чем на 1 год. Прогрессия такова: 60 дней (первое), 120 дней (второе), 1 год (третье). Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual."},"53":{"q":"В Миссисипи держатель CDL, использующий коммерческое транспортное средство для совершения тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, дисквалифицируется на:","options":["1 год","3 года","10 лет","Пожизненно, без восстановления"],"explanation":"Использование коммерческого ТС при совершении тяжкого преступления (felony), связанного с контролируемыми веществами, влечёт пожизненную дисквалификацию, которая, в отличие от некоторых пожизненных дисквалификаций, не может быть сокращена. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"54":{"q":"Что из перечисленного является ТЯЖКИМ нарушением (минимальная дисквалификация 1 год), а не серьёзным нарушением ПДД в Миссисипи?","options":["Слишком близкое следование","Оставление места происшествия с участием коммерческого ТС","Превышение скорости на 15 mph сверх предела","Неправильное перестроение по полосе"],"explanation":"Оставление места происшествия с участием коммерческого ТС является тяжким нарушением с минимальной дисквалификацией на 1 год. Остальные варианты — серьёзные нарушения ПДД. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"55":{"q":"В Миссисипи, если лицо отказывается от химического теста, имея CDL, дисквалификация коммерческого права применяется:","options":["Только если водитель в этот момент управлял коммерческим ТС","Только если BAC впоследствии окажется выше 0.04%","Даже если отказ произошёл во время управления личным (некоммерческим) транспортным средством","Только после второго отказа"],"explanation":"Держатель CDL дисквалифицируется за отказ от химического теста, даже когда отказ происходит во время управления некоммерческим транспортным средством; осуждения и отказы в личном транспортном средстве всё равно влияют на CDL. Источник: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51; Mississippi CDL Manual."},"56":{"q":"Водитель CDL в Миссисипи получает серьёзное нарушение ПДД на своём ЛИЧНОМ транспортном средстве, что приводит к приостановлению прав. Как это влияет на CDL?","options":["Это не имеет последствий, поскольку это было не коммерческое ТС","Это всё равно засчитывается в счёт дисквалификации CDL","Это засчитывается, только если водитель был при исполнении служебных обязанностей","Это влияет только на эндорсмент HazMat"],"explanation":"Осуждения и действия в отношении прав на личном транспортном средстве засчитываются в счёт CDL; приостановление/аннулирование/отзыв права на вождение за определённые серьёзные нарушения ведёт к дисквалификации CDL. Источник: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual."},"57":{"q":"Согласно закону Миссисипи об уступке дороги (Move Over law), когда вы приближаетесь к остановившемуся аварийному или эвакуационному автомобилю с включёнными мигающими огнями на четырёхполосном шоссе, где в вашем направлении идут две полосы, что вы обязаны сделать?","options":["Освободить полосу рядом с остановившимся автомобилем, если это безопасно","Полностью остановиться и ждать, пока остановившийся автомобиль не уедет","Непрерывно сигналить, проезжая мимо автомобиля","Сохранять свою скорость и оставаться в текущей полосе"],"explanation":"Miss. Code 63-3-809 требует, чтобы водители на дороге, имеющей не менее четырёх полос (две или более в одном направлении), перестроились в полосу, не примыкающую к неподвижному аварийному, восстановительному или коммунальному автомобилю, когда это безопасно. Источник: Mississippi Code 63-3-809."},"58":{"q":"Согласно закону Миссисипи об уступке дороги (Move Over law), если вы не можете безопасно перестроиться от остановившегося аварийного автомобиля с включёнными мигающими огнями, что вы обязаны сделать вместо этого?","options":["Продолжать движение с разрешённой скоростью, ничего не меняя","Остановиться в своей полосе и ждать, пока сотрудник не пропустит вас взмахом руки","Снизить скорость, двигаться с осторожностью и быть готовым остановиться","Включить аварийную сигнализацию и проехать с обычной скоростью"],"explanation":"Miss. Code 63-3-809 предписывает водителю, который не может безопасно перестроиться, снизить скорость, двигаться с должной осторожностью и быть готовым остановиться. Источник: Mississippi Code 63-3-809."},"59":{"q":"В Миссисипи нарушение закона об уступке дороги (63-3-809), которое НЕ повлекло за собой ущерб или травму, наказывается штрафом в размере до какой суммы?","options":["До $100","До $250","До $500","До $1,000"],"explanation":"Miss. Code 63-3-809 устанавливает штраф до $250 за нарушение, который возрастает до $1,000, если нарушение повлекло за собой материальный ущерб неподвижному автомобилю или телесные повреждения его пассажирам. Источник: Mississippi Code 63-3-809."},"60":{"q":"Помимо уполномоченных аварийных автомобилей, какие из следующих остановившихся автомобилей с включёнными мигающими предупреждающими огнями также защищает закон Миссисипи об уступке дороги (63-3-809)?","options":["Только обозначенные автомобили правоохранительных органов","Только машины скорой помощи и пожарную технику","Восстановительные (эвакуационные) автомобили и коммунальные служебные автомобили","Только автомобили, принадлежащие правительству штата"],"explanation":"Miss. Code 63-3-809 распространяет обязанность по перестроению/снижению скорости на неподвижные уполномоченные аварийные автомобили, а также на восстановительные (эвакуационные) и коммунальные служебные автомобили с включёнными разрешёнными мигающими огнями. Источник: Mississippi Code 63-3-809."},"61":{"q":"На большинстве межштатных автомагистралей Миссисипи Транспортная комиссия Миссисипи может устанавливать максимальное ограничение скорости не выше какого значения?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Miss. Code 63-3-501 ограничивает максимальную скорость, которую Транспортная комиссия может устанавливать на системе межштатных автомагистралей и на автомагистралях с контролируемым доступом, имеющих четыре или более полос, значением 70 mph. Источник: Mississippi Code 63-3-501."},"62":{"q":"Согласно Mississippi Code 63-3-501, там где на межштатной или четырёхполосной автомагистрали США установлено ограничение 70 mph, какая МИНИМАЛЬНАЯ скорость применяется к автомобилю, у которого есть ограничение максимальной скорости 70 mph?","options":["30 mph","40 mph","45 mph","50 mph"],"explanation":"Miss. Code 63-3-501 устанавливает минимальную скорость 40 mph для автомобилей, имеющих ограничение максимальной скорости 70 mph на таких автомагистралях. Источник: Mississippi Code 63-3-501."},"63":{"q":"Согласно закону Миссисипи, когда вы останавливаете автобус с пассажирами перед пересечением железнодорожного переезда, вы должны остановиться на каком расстоянии от ближайшего рельса?","options":["В пределах 50 футов, но не ближе 15 футов","В пределах 25 футов, но не ближе 5 футов","В пределах 75 футов, но не ближе 25 футов","В пределах 100 футов, но не ближе 50 футов"],"explanation":"Miss. Code 63-3-1011 требует, чтобы автобусы, автомобили, перевозящие пассажиров за плату, школьные автобусы и автомобили, перевозящие взрывчатые вещества или легковоспламеняющиеся жидкости, останавливались в пределах 50 футов, но не ближе 15 футов от ближайшего рельса. Источник: Mississippi Code 63-3-1011."},"64":{"q":"Согласно руководству Mississippi CDL Manual, какие коммерческие автомобили всегда обязаны останавливаться на железнодорожных переездах?","options":["Все коммерческие автомобили весом более 10,000 фунтов","Автобусы, перевозящие пассажиров, и автомобили, перевозящие опасные материалы с табличками (placard)","Только составы с тремя прицепами","Любой автомобиль, буксирующий прицеп любого типа"],"explanation":"Mississippi CDL Manual (отражая 49 CFR 392.10 и Miss. Code 63-3-1011) требует, чтобы автобусы с пассажирами и автомобили с табличками опасных грузов останавливались перед пересечением путей, а затем смотрели и слушали. Источник: Mississippi CDL Manual / Miss. Code 63-3-1011."},"65":{"q":"Когда требуется остановиться на железнодорожном переезде в Миссисипи, после остановки в зоне от 15 до 50 футов водитель автобуса или автомобиля с табличками опасных грузов должен пересекать пути каким образом?","options":["Быстро, переключаясь на повышенные передачи, чтобы быстро освободить переезд","На передаче, которая позволяет завершить пересечение без переключения передач","На нейтрали, накатом с выжатым сцеплением","Только после трёхкратного звукового сигнала"],"explanation":"Mississippi CDL Manual предписывает водителям пересекать пути на передаче, которая позволяет завершить пересечение без переключения, и не переключать передачи, находясь на путях. Источник: Mississippi CDL Manual (железнодорожные переезды)."},"66":{"q":"Согласно закону Миссисипи о школьных автобусах (Закон Натана, Nathan's Law, 63-3-615), насколько близко встречный или обгоняющий автомобиль может остановиться к школьному автобусу, который производит посадку или высадку детей с включёнными красными мигающими огнями и выдвинутым знаком \"стоп\"?","options":["Не ближе 10 футов от автобуса","Не ближе 25 футов от автобуса","Не ближе 50 футов от автобуса","Не ближе 5 футов от автобуса"],"explanation":"Miss. Code 63-3-615 требует, чтобы встречные или обгоняющие водители останавливались не ближе 10 футов от школьного автобуса, который остановился для посадки или высадки детей. Источник: Mississippi Code 63-3-615."},"67":{"q":"На автомагистрали Миссисипи при каком условии водитель НЕ обязан останавливаться перед школьным автобусом, который остановился для посадки или высадки детей?","options":["Всякий раз, когда водитель движется в противоположном направлении по любой двухполосной дороге","Когда автобус остановился на встречной проезжей части разделённой автомагистрали с четырьмя или более полосами, имеющей не менее двух полос в противоположных направлениях","Всякий раз, когда движение интенсивное и остановка была бы неудобной","Когда водитель находится более чем в 100 футах от автобуса"],"explanation":"Miss. Code 63-3-615 освобождает водителя на разделённой автомагистрали с четырьмя или более полосами (допускающей не менее двух полос движения в противоположных направлениях) от обязанности останавливаться перед автобусом, остановившимся на встречной проезжей части. Источник: Mississippi Code 63-3-615."},"68":{"q":"Согласно Mississippi Code 63-3-615, штраф за первое нарушение за незаконный проезд мимо остановившегося школьного автобуса составляет не менее какой суммы?","options":["Не менее $100","Не менее $200","Не менее $350","Не менее $1,000"],"explanation":"Miss. Code 63-3-615 устанавливает штраф за первое нарушение не менее $350 и не более $750 (а также возможное тюремное заключение) за незаконный проезд мимо остановившегося школьного автобуса. Источник: Mississippi Code 63-3-615."},"69":{"q":"Согласно правилам Миссисипи об использовании полос, где должен двигаться коммерческий автомобиль, движущийся медленнее обычной скорости потока, на многополосной автомагистрали?","options":["В правой полосе или как можно ближе к правому краю проезжей части","Постоянно в центральной полосе","В левой полосе, чтобы держаться подальше от вливающегося потока","В любой полосе, где меньше всего движения"],"explanation":"Miss. Code 63-3-603 требует, чтобы автомобиль, движущийся медленнее обычной скорости потока, использовал правую полосу или держался как можно ближе к правому краю, за исключением случаев обгона или подготовки к левому повороту. Источник: Mississippi Code 63-3-603."},"70":{"q":"Что говорит Mississippi Code 63-3-603 о постоянном движении в крайней левой полосе многополосной проезжей части?","options":["Это разрешено для грузовиков, но запрещено для легковых автомобилей","Это запрещено всякий раз, когда мешает потоку остального движения","Это обязательно для всех автомобилей весом более 26,000 фунтов","Это разрешено в любое время при условии, что вы сначала подадите сигнал"],"explanation":"Miss. Code 63-3-603 запрещает постоянное движение в крайней левой полосе многополосной проезжей части всякий раз, когда это мешает потоку остального движения. Источник: Mississippi Code 63-3-603."},"71":{"q":"Согласно Mississippi CDL Manual, когда ваш коммерческий автомобиль остановился на обочине дороги с односторонним движением или разделённой автомагистрали, где вы размещаете три предупреждающих треугольника?","options":["На 10, 100 и 200 футах в сторону приближающегося потока (все позади)","На 25 футах впереди, у автомобиля и на 25 футах позади","Один у автомобиля и два рядом на 50 футах позади","На 10, 100 и 200 футах как впереди, так и позади автомобиля"],"explanation":"Mississippi CDL Manual (согласно 49 CFR 392.22) предписывает размещать треугольники на 10, 100 и 200 футах в сторону приближающегося потока на дороге с односторонним движением или разделённой автомагистрали. Источник: Mississippi CDL Manual / 49 CFR 392.22."},"72":{"q":"Согласно Mississippi CDL Manual, на двухполосной неразделённой дороге с движением в обоих направлениях, где должны быть размещены предупреждающие устройства для остановившегося коммерческого автомобиля?","options":["Все три в пределах 10 футов позади автомобиля","В пределах 10 футов от автомобиля, плюс 100 футов позади и 100 футов впереди","Только одно устройство, на 200 футах позади автомобиля","На 50 футах и 500 футах позади автомобиля"],"explanation":"Mississippi CDL Manual (согласно 49 CFR 392.22) требует устройство в пределах 10 футов от автомобиля, а также устройства примерно на 100 футах позади и 100 футах впереди на двухполосной дороге с двусторонним движением. Источник: Mississippi CDL Manual / 49 CFR 392.22."},"73":{"q":"Согласно Mississippi CDL Manual, после того как коммерческий автомобиль остановился на проезжей части или обочине, в течение скольких секунд водитель должен выставить аварийные предупреждающие устройства?","options":["В течение 5 секунд","В течение 10 минут","В течение 30 минут","В течение 1 часа"],"explanation":"Mississippi CDL Manual (согласно 49 CFR 392.22) требует, чтобы предупреждающие устройства были размещены в течение 10 минут после остановки; аварийная сигнализация используется немедленно и до тех пор, пока не выставлены треугольники. Источник: Mississippi CDL Manual / 49 CFR 392.22."},"74":{"q":"Какой маршрут в Миссисипи, пролегающий по диагонали через штат, запрещает использование коммерческими грузовиками (с номинальной грузоподъёмностью более одной тонны)?","options":["Interstate 55","U.S. Highway 49","The Natchez Trace Parkway","Interstate 20"],"explanation":"The Natchez Trace Parkway, живописный маршрут федерального управления, запрещает движение коммерческих автомобилей и грузовиков с номинальной грузоподъёмностью более одной тонны. Источник: 36 CFR 7.43 / National Park Service."},"75":{"q":"В Миссисипи какова максимальная разрешённая законом ширина автомобиля на установленных автомагистралях до того, как потребуется разрешение на негабаритный груз?","options":["8 футов 0 дюймов","8 футов 6 дюймов","9 футов 0 дюймов","10 футов 0 дюймов"],"explanation":"Максимальная разрешённая законом ширина в Миссисипи на установленных автомагистралях составляет 8 футов 6 дюймов; грузы шире этого требуют разрешения на негабаритный груз. Источник: правила Mississippi DOT для разрешений на негабаритные/перегруженные грузы."},"76":{"q":"В Миссисипи каков максимальный разрешённый законом полный вес автомобиля в системе межштатных автомагистралей до того, как потребуется разрешение на перегруз?","options":["73,280 фунтов","80,000 фунтов","88,000 фунтов","100,000 фунтов"],"explanation":"Миссисипи следует федеральному пределу в 80,000 фунтов максимального разрешённого законом полного веса в системе межштатных автомагистралей; превышение требует разрешения на перегруз от MDOT. Источник: правила Mississippi DOT для разрешений на перегруз."},"77":{"q":"Какое агентство Миссисипи выдаёт коммерческие водительские удостоверения и проводит тестирование на CDL в штате?","options":["The Mississippi Department of Public Safety (DPS), через своё Driver Service Bureau","The Mississippi Department of Transportation (MDOT)","Офис окружного секретаря суда (Circuit Clerk) по месту жительства водителя","The Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"CDL Миссисипи выдаются, а тесты на CDL проводятся Mississippi Department of Public Safety (DPS) через его Driver Service Bureau. MDOT занимается дорогами и разрешениями, а не лицензированием, а FMCSA устанавливает федеральные стандарты, но не выдаёт лицензии штата. Источник: MS DPS Driver Service Bureau; Miss. Code Title 63, Chapter 1."},"78":{"q":"Каков минимальный проходной балл на экзаменах на знание (письменных) для CDL в Миссисипи?","options":["80%","70%","75%","90%"],"explanation":"Миссисипи требует минимальный балл 80% на каждом обязательном экзамене на знание для CDL, что соответствует федеральному стандарту тестирования AAMVA. Источник: MS DPS / Mississippi CDL Manual."},"79":{"q":"Прежде чем впервые подающий заявление на CDL в Миссисипи сможет сдать обязательные тесты на знание или навыки, какое обучение должно быть завершено?","options":["Entry-Level Driver Training (ELDT) от поставщика обучения, зарегистрированного в FMCSA","Курс безопасного вождения, одобренный MDOT","40-часовой аудиторный курс в общественном колледже","Стажировка, зарегистрированная в Mississippi Trucking Association"],"explanation":"С 7 февраля 2022 года впервые подающие заявление на CDL должны пройти Entry-Level Driver Training (ELDT) от поставщика, указанного в реестре поставщиков обучения FMCSA (Training Provider Registry), прежде чем сдавать обязательные тесты на навыки или знания. Источник: MS DPS Driver Service Bureau; правило FMCSA ELDT (49 CFR Part 380)."},"80":{"q":"Как долго необходимо удерживать Mississippi Commercial Learner's Permit (CLP), прежде чем его обладатель сможет сдать тест на навыки для CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 10 дней","Не менее 60 дней"],"explanation":"Миссисипи следует федеральному правилу, требующему удерживать CLP минимум 14 дней, прежде чем его обладатель получит право сдавать тест на навыки для CDL. Источник: MS DPS Driver Service Bureau; 49 CFR 383.25."},"81":{"q":"В течение какого срока действует Mississippi Commercial Learner's Permit (CLP)?","options":["6 месяцев","1 год","30 дней","90 дней"],"explanation":"CLP Миссисипи действителен в течение 6 месяцев (180 дней), что соответствует федеральному максимальному сроку действия CLP. Источник: MS DPS Driver Service Bureau; 49 CFR 383.25."},"82":{"q":"Тест на навыки для CDL в Миссисипи состоит из каких трёх частей, выполняемых по порядку?","options":["Предрейсовый осмотр автомобиля, базовое управление автомобилем и вождение по дороге","Письменный тест на знание, тест на пневматические тормоза и вождение по дороге","Предрейсовый осмотр, обращение с опасными грузами и вождение ночью","Базовое управление автомобилем, сцепка/расцепка и письменный экзамен на разрешение (endorsement)"],"explanation":"Тест на навыки для CDL в Миссисипи состоит из трёх частей: предрейсового осмотра автомобиля, теста на базовое управление автомобилем и теста на вождение по дороге. Все три должны быть сданы. Источник: MS DPS / Mississippi CDL Manual."},"83":{"q":"Каков срок действия (период действия) коммерческого водительского удостоверения Миссисипи, прежде чем его необходимо продлить?","options":["5 лет, истекает в день рождения обладателя лицензии","4 года, истекает в день рождения обладателя лицензии","8 лет, истекает в день рождения обладателя лицензии","2 года, привязано к медицинскому сертификату"],"explanation":"CDL Миссисипи выдаётся на пятилетний срок и истекает в полночь в день рождения обладателя лицензии. Источник: Miss. Code Ann. Sec. 63-1-47 (и Sec. 63-1-211)."},"84":{"q":"За сколько времени до даты истечения срока обладатель CDL Миссисипи может продлить лицензию?","options":["В любое время в течение 6 месяцев до истечения срока","Только в течение 30 дней до истечения срока","В любое время в течение 90 дней до истечения срока","Только в день истечения срока или после него"],"explanation":"Миссисипи разрешает продление в любое время в течение шести (6) месяцев до истечения срока действия лицензии при подаче заявления и уплате необходимого сбора, если не требуется повторное освидетельствование. Источник: Miss. Code Ann. Sec. 63-1-47."},"85":{"q":"Когда заявитель на CDL самостоятельно сертифицирует свой тип вождения в Mississippi DPS, сколько категорий самосертификации доступно для выбора?","options":["Четыре","Две","Три","Пять"],"explanation":"Существуют четыре категории самосертификации: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate и Excepted Intrastate. Заявитель должен выбрать ровно одну. Источник: MS DPS Driver Service Bureau Self-Certification; 49 CFR 383.71(b)."},"86":{"q":"Какая категория самосертификации в Миссисипи применяется к водителю, который работает с пересечением границ штатов и обязан соответствовать всем федеральным медицинским квалификационным стандартам?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Водители Non-Excepted Interstate (NI) работают в межштатной торговле, должны соответствовать всем федеральным медицинским требованиям DOT и должны хранить действующий сертификат медицинского эксперта в деле. Источник: MS DPS Self-Certification categories; 49 CFR 383.71(b)."},"87":{"q":"Водитель Миссисипи, который самостоятельно сертифицируется как Non-Excepted Interstate, что должен хранить в деле в DPS, чтобы поддерживать действительный CDL?","options":["Действующий сертификат медицинского эксперта DOT","Действующий сертификат страхования общей гражданской ответственности","Продлённый CLP каждые шесть месяцев","Разрешение MDOT на негабаритный/перегруженный груз"],"explanation":"Водители Non-Excepted Interstate (и Non-Excepted Intrastate) должны хранить действующий сертификат медицинского эксперта DOT в учётной записи в DPS; невыполнение этого приводит к понижению категории. Источник: MS DPS Medical Certification Requirements; 49 CFR 383.71/383.73."},"88":{"q":"С 23 июня 2025 года, как результат медицинского обследования DOT водителя CDL передаётся в Mississippi DPS?","options":["Сертифицированный медицинский эксперт электронно подаёт его в National Registry FMCSA, который передаёт его в DPS","Водитель отправляет по почте бумажную копию формы Form MCSA-5876 в штаб-квартиру DPS","Водитель загружает отсканированную копию через онлайн-портал DPS","Работодатель отправляет по факсу копию в местную станцию выдачи водительских удостоверений DPS"],"explanation":"Согласно окончательному правилу FMCSA, вступившему в силу 23 июня 2025 года, сертифицированные медицинские эксперты подают результаты обследования электронно в National Registry, который передаёт их в штат; Миссисипи вносит результат непосредственно в учётную запись водителя. Источник: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule."},"89":{"q":"После федерального изменения от 23 июня 2025 года, может ли станция выдачи водительских удостоверений Миссисипи принять бумажную или отсканированную копию сертификата медицинского эксперта (форма Form MCSA-5876)?","options":["Нет; бумажные и отсканированные копии больше не принимаются, так как результаты поступают электронно из National Registry","Да; бумажные копии остаются основным способом подачи","Да, но только если они нотариально заверены в течение 15 дней после обследования","Да, но только для внутриштатных (NA) водителей"],"explanation":"По состоянию на 23 июня 2025 года станции DPS больше не принимают физические или отсканированные копии MCSA-5876; результат медицинского обследования должен поступать электронно из National Registry FMCSA. Источник: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule."},"90":{"q":"Согласно правилу FMCSA, которому следует Миссисипи, к какому сроку сертифицированный медицинский эксперт должен загрузить результат обследования водителя CDL в National Registry?","options":["К концу следующего календарного дня после обследования","В течение 30 дней после обследования","В течение 14 дней после обследования","К концу той же рабочей недели"],"explanation":"Согласно правилу, вступившему в силу 23 июня 2025 года, сертифицированный медицинский эксперт должен электронно загрузить результаты обследования в National Registry до полуночи следующего календарного дня после обследования. Источник: FMCSA Medical Examiner's Certification Integration final rule, применяемое MS DPS."},"91":{"q":"Что происходит с CDL Миссисипи, если non-excepted водитель допускает истечение срока своей медицинской сертификации DOT и не обновляет её?","options":["DPS понижает категорию CDL, отменяя права на коммерческое вождение до восстановления сертификации","CDL аннулируется навсегда и не может быть восстановлен","Ничего не меняется до следующего 5-летнего продления","Водитель автоматически переклассифицируется в Excepted Interstate"],"explanation":"Non-excepted водитель, который не поддерживает медицинскую сертификацию действующей, переводится в статус \"not-certified\", и штат понижает категорию CDL, отменяя коммерческие права до тех пор, пока действующая сертификация снова не будет в деле. Источник: MS DPS Medical Certification Requirements; 49 CFR 383.73."},"92":{"q":"Какие документы обычно требуются при подаче заявления на новый CDL Миссисипи в офисе DPS?","options":["Подтверждение личности/рождения, номер социального страхования (Social Security) и два подтверждения проживания в Миссисипи","Только паспорт, без какой-либо другой документации","Аттестат об окончании средней школы и три личные рекомендации","Только свидетельство о праве собственности на автомобиль и подтверждение коммерческого автострахования"],"explanation":"Заявитель на новый CDL должен предъявить подтверждение личности (например, свидетельство о рождении), подтверждение номера социального страхования и два подтверждения проживания в Миссисипи, а также сдать обязательные экзамены. Источник: MS DPS Driver Service Bureau new CDL requirements."},"93":{"q":"Каков минимальный возраст для получения CDL Миссисипи, ограниченного внутриштатным (в пределах штата) коммерческим вождением?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Водитель может получить CDL для внутриштатной работы в 18 лет, но должен быть 21 года для межштатной работы и для перевозки опасных материалов. Источник: MS DPS / Mississippi CDL Manual; 49 CFR 383.3 / 391.11."},"94":{"q":"Каков минимальный возраст для получения CDL Миссисипи для межштатного вождения или для перевозки опасных материалов с табличками (placard)?","options":["21 год","18 лет","23 года","19 лет"],"explanation":"Федеральные правила, принятые Миссисипи, требуют, чтобы водителю было не менее 21 года для работы в межштатной торговле и для перевозки опасных материалов с табличками. Источник: MS DPS / Mississippi CDL Manual; 49 CFR 391.11."},"95":{"q":"Кто может по закону проводить тест на навыки (дорожный) для CDL Миссисипи, помимо экзаменаторов DPS?","options":["Утверждённые штатом сторонние тестировщики/экзаменаторы (Third-Party Testers)","Любой обладатель CDL с двухлетним опытом","Менеджер по безопасности потенциального работодателя заявителя","Любой зарегистрированный в FMCSA аудиторный инструктор ELDT"],"explanation":"Миссисипи разрешает проводить тест на навыки для CDL либо экзаменаторам DPS, либо утверждённым штатом сторонним тестировщикам (Third-Party Testers) из списка, который ведёт DPS. Источник: MS DPS Driver Service Bureau (Third-Party Tester program); 49 CFR 383.75."},"96":{"q":"Заявитель в Миссисипи проваливает только дорожную часть теста на навыки для CDL, но сдаёт части предрейсового осмотра и базового управления. Каков общий результат?","options":["Заявитель должен пересдать дорожную часть и пока не получает CDL","Заявитель автоматически получает ограниченный внутриштатный CDL","Все три части теста на навыки должны быть пересданы с самого начала","Заявителю выдаётся CDL, поскольку две из трёх частей сданы"],"explanation":"Все три компонента теста на навыки (предрейсовый осмотр, базовое управление автомобилем и вождение по дороге) должны быть сданы для выдачи CDL; провал любой одной части означает, что её необходимо пересдать, и CDL не выдаётся, пока не сданы все. Источник: MS DPS / Mississippi CDL Manual; 49 CFR 383.113."}},"tr":{"0":{"q":"Mississippi karayollarında bir ticari aracın (gerekli güvenlik donanımları ve aynalar hariç) yasal azami genişliği nedir?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"Mississippi araç genişliğini 8 feet 6 inches (102 inches) ile sınırlar; bundan daha geniş bir yük büyük boy (oversize) izni gerektirir. Kaynak: Miss. Code Ann. Sec. 63-5-13 (Araçların dış genişliği); MDOT Office of Enforcement izin kuralları."},"1":{"q":"Mississippi karayollarında bir aracın, yük dahil, yasal azami yüksekliği nedir?","options":["14 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 6 inches"],"explanation":"Mississippi'de hiçbir araç, yüklü olsun ya da olmasın, 13 feet 6 inches yüksekliği aşamaz. Kaynak: Miss. Code Ann. Sec. 63-5-17 (Araçların yüksekliği)."},"2":{"q":"Mississippi'de özel bir izin olmadan çalışan bir araç veya kombinasyon için (herhangi bir tolerans olmaksızın) azami brüt ağırlık nedir?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"İzinsiz azami brüt araç ağırlığı 80,000 pounds'tur (bunun üzerine %2'lik bir tolerans uygulanabilir). Kaynak: Miss. Code Ann. Sec. 63-5-33; MDOT Mississippi Maximum Weight Laws."},"3":{"q":"Mississippi'nin tek bir aksta izin verdiği azami brüt ağırlık nedir?","options":["24,000 pounds","22,400 pounds","18,000 pounds","20,000 pounds"],"explanation":"Tek bir aks üzerindeki brüt ağırlık 20,000 pounds'u aşamaz (yasal tolerans hariç). Kaynak: Miss. Code Ann. Sec. 63-5-27 (Tekerlek ve aks yükleri); MDOT Maximum Weight Laws."},"4":{"q":"Mississippi'nin bir tandem aksta izin verdiği azami brüt ağırlık nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Herhangi bir tandem aks üzerindeki brüt ağırlık 34,000 pounds'u aşamaz (yasal tolerans hariç). Kaynak: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"5":{"q":"Mississippi yasalarına göre, ağırlık amaçları bakımından 'tek aks' nasıl tanımlanır?","options":["Birbirini izleyen ve aralarında 40 inches'ten fazla mesafe bulunan herhangi iki aks","Tam olarak 96 inches aralıkla yerleştirilmiş iki veya daha fazla aks","Aracın her iki yanında tek bir tekerlek ve lastik takımı","Tek bir enine düzlemde bulunan ya da 40 inches aralıklı iki paralel düzlem arasında kalan iki veya daha fazla tekerlek"],"explanation":"Tek aks, merkezleri tek bir enine dikey düzlemde bulunan veya aracın tüm genişliği boyunca 40 inches aralıklı iki paralel enine düzlem arasında kalan iki veya daha fazla tekerlekten oluşan bir takımdır. Kaynak: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"6":{"q":"Mississippi yasaları, ağırlık amaçları bakımından 'tandem aks'ı nasıl tanımlar?","options":["Merkezleri arasında 40 inches'ten fazla ancak 96 inches'ten fazla olmayan, birbirini izleyen iki veya daha fazla aks","Merkezleri arasında tam olarak 40 inches bulunan iki aks","96 inches'ten fazla yer kaplayan herhangi bir aks grubu","Biri tahrik aksı, diğeri direksiyon aksı olan iki aks"],"explanation":"Tandem aks, merkezleri arasında 40 inches'ten fazla ancak 96 inches'ten fazla olmayan, birbirini izleyen iki veya daha fazla akstır ve gruptaki hiçbir aks tek aks sınırını aşamaz. Kaynak: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"7":{"q":"Mississippi karayollarında tek (düz) bir kamyonun azami uzunluğu nedir?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"Mississippi'de hiçbir tek araç (düz kamyon) 40 feet toplam uzunluğu aşamaz. Kaynak: Miss. Code Ann. Sec. 63-5-19 (Araç uzunluğu sınırlamaları)."},"8":{"q":"Mississippi'de bir çekici/yarı römork kombinasyonunda çalışan bir yarı römorkun azami uzunluğu nedir?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"Bir çekici/yarı römork kombinasyonunda çalışan bir yarı römork, Mississippi'de 53 feet'i aşamaz. Kaynak: Miss. Code Ann. Sec. 63-5-19 (Araç uzunluğu sınırlamaları)."},"9":{"q":"Birbirini izleyen iki veya daha fazla akstan oluşan herhangi bir grup üzerindeki azami ağırlığı belirlemek için Mississippi hangi standardı uygular?","options":["Aks aralığından bağımsız sabit 80,000 pound üst sınır","Federal Köprü Formülü (ağırlık aks aralığına bağlıdır)","Yalnızca lastik genişliği başına 550 pound kuralı","Hasat izni tolerans çizelgesi"],"explanation":"Mississippi Federal Köprü Formülü'nü kullanır; bu nedenle bir aks grubuna izin verilen ağırlık, gruptaki en uçtaki akslar arasındaki mesafeye bağlıdır. Kaynak: Miss. Code Ann. Sec. 63-5-29/63-5-33 ağırlık tabloları; MDOT Maximum Weight Laws."},"10":{"q":"Mississippi'nin 80,000 pound olan azami brüt ağırlığı, hasat izni OLMADAN çalışan bir araç için hangi yasal toleransla aşılabilir?","options":["%10","%5","%1","%2"],"explanation":"Azami brüt araç ağırlığı, 80,000 pounds artı en fazla %2'lik bir toleransı aşamaz. Kaynak: Miss. Code Ann. Sec. 63-5-33."},"11":{"q":"Mississippi, hasat izni İLE çalışan bir araca, yetkilendirilmiş brüt, tandem veya aks ağırlığının üzerinde hangi ağırlık toleransını tanır?","options":["%2","%5","%10","%15"],"explanation":"Hasat izinli bir araca, yetkilendirilmiş brüt, tandem veya aks ağırlığının üzerinde %10'u aşmayan bir tolerans tanınır (88,000 pound üst sınırına tabidir). Kaynak: Miss. Code Ann. Sec. 63-5-33."},"12":{"q":"Mississippi'de büyük boy/aşırı yük (over-dimensional) izinlerini hangi kurum verir?","options":["Mississippi Department of Transportation, Office of Enforcement Permit Division","Mississippi Department of Public Safety, Driver Services","Mississippi State Tax Commission","Çıkış yapılan ilçenin şerifi"],"explanation":"Over-dimensional izinler, Mississippi Transportation Commission yetkisi altında MDOT Office of Enforcement, Permit Division tarafından verilir. Kaynak: MDOT Over-Dimensional Permit Rules (Sub-Part 6601, Chapter 03001); Miss. Code Ann. Sec. 65-1-8."},"13":{"q":"Mississippi'de Tek Sefer (Single Trip) over-dimensional izni, en fazla ne kadarlık bir süre için hareketi yetkilendirir?","options":["24 hours","Üst üste üç gün","Üst üste yedi gün","Otuz gün"],"explanation":"Tek Sefer İzni, belirli bir aracın/yükün hareketini üst üste üç (3) günü aşmayan bir süre için yetkilendirir. Kaynak: MDOT Over-Dimensional Permit Rules, Sec. 213 (Tanımlar)."},"14":{"q":"Bölünemez bir yük, genişliği hangi boyutu aştığında genellikle Mississippi büyük boy izni almak zorundadır?","options":["8 feet 0 inches","8 feet 6 inches","10 feet 0 inches","12 feet 0 inches"],"explanation":"Yasal 8-foot-6-inch (102-inch) genişlik sınırını aşan bir yükü hareket ettirmek için izin gereklidir. Kaynak: Miss. Code Ann. Sec. 63-5-13; MDOT Office of Enforcement izin kuralları."},"15":{"q":"Mississippi over-dimensional izin kuralları kapsamında, hangi yük genişliğinde daha katı 'gün ışığı saatleri' ve refakat (escort) gereklilikleri yürürlüğe girer?","options":["12 feet'ten fazla genişlik","10 feet'ten fazla genişlik","14 feet'ten fazla genişlik","16 feet'ten fazla genişlik"],"explanation":"12 feet'ten daha geniş yükler için 'gün ışığı saatleri' gün doğumundan 30 dakika sonrasından gün batımından 30 dakika öncesine daralır ve ek refakat gereklilikleri uygulanır. Kaynak: MDOT Over-Dimensional Permit Rules, Sec. 200."},"16":{"q":"Mississippi, tek ve tandem aks ağırlıklarını, brüt ağırlık lastik genişliğinin inç'i başına kaç pound'u aşmayacak şekilde sınırlar (aks maksimumlarına tabidir)?","options":["650 pounds per inch","600 pounds per inch","500 pounds per inch","550 pounds per inch"],"explanation":"Tek veya tandem aks brüt ağırlığı, lastik genişliğinin inç'i başına 550 pounds'u aşamaz (500 pounds'a kadar tolerans ile) ve hiçbir zaman 20,000/34,000-pound aks maksimumlarını geçemez. Kaynak: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"17":{"q":"Mississippi eyalet karayollarında (Interstate sistemi hariç), en uç aksları arasında 29 feet'ten fazla mesafe ölçülen tescilli bir araç, köprü formülü ağırlık amaçları bakımından, o aks grubu ne kadar daha uzunmuş gibi muamele görür?","options":["6 feet daha uzun","12 feet daha uzun","20 feet daha uzun","29 feet daha uzun"],"explanation":"Sec. 63-5-34 yalnızca eyalet karayollarına ilişkin hüküm uyarınca, böyle bir aracın en uç aks grubu, gerçek ölçümünden 12 feet daha uzun aralıklı kabul edilir (bu, federal Interstate sisteminde uygulanmaz). Kaynak: Miss. Code Ann. Sec. 63-5-34; MDOT Maximum Weight Laws."},"18":{"q":"Mississippi'de birbirini izleyen iki tandem aks takımının her birinin 34,000 pounds taşıması için (80,000 pounds brüt ağırlığı aşmadan), takımların ilk ve son aksları arasındaki mesafe en az ne olmalıdır?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"Birbirini izleyen iki tandem aks takımı, ilk ve son akslar arasındaki toplam mesafe 36 feet veya daha fazla olması koşuluyla ve Sec. 63-5-33'te izin verilenler dışında toplam brüt 80,000 pounds'u aşmamak kaydıyla, her biri 34,000 pounds taşıyabilir. Kaynak: MDOT Maximum Weight Laws (Tablo III notu); Miss. Code Ann. Sec. 63-5-33."},"19":{"q":"Mississippi'de, tek bir ticari aracı Class A veya Class B kategorisine sokan asgari brüt araç ağırlık derecesi (GVWR) eşiği nedir?","options":["26,001 pounds veya daha fazla","10,001 pounds veya daha fazla","18,001 pounds veya daha fazla","33,001 pounds veya daha fazla"],"explanation":"Mississippi, Class B'yi GVWR'si 26,001 pounds veya daha fazla olan herhangi bir tek araç, Class A'yı ise GVWR'si 26,001 pounds veya daha fazla olan bir araç kombinasyonu (10,000 lbs üzeri bir birim çeken) olarak tanımlar. Kaynak: Mississippi DPS Driver Service Bureau, CDL Classes A-D sayfası; Mississippi CDL Manual."},"20":{"q":"GVWR'si 26,001 pounds veya daha fazla olan ve çekilen aracın GVWR'si 10,000 pounds'u aşan herhangi bir araç kombinasyonunu kullanmak için hangi Mississippi CDL sınıfı gereklidir?","options":["Class B","Class A","Class C","Class D"],"explanation":"Mississippi Class A, GVWR'si 10,000 lbs üzerinde bir birim çeken, 26,001 lbs veya daha fazla GVWR'ye sahip kombinasyon araçlarını kapsar. Kaynak: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"21":{"q":"Bir Mississippi sürücüsü, hiçbir şey çekmeyen 30,000 pounds GVWR dereceli tek bir düz kamyon kullanmaktadır. Bu hangi CDL sınıfını gerektirir?","options":["Class A","Class C","Class B","CDL gerekli değildir"],"explanation":"26,001 lbs veya daha fazla GVWR'ye sahip tek bir araç (10,000 lbs üzeri bir birim çekmiyorsa) Mississippi'de bir Class B aracıdır. Kaynak: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"22":{"q":"Mississippi kurallarına göre, Class A veya B ağırlık eşiklerini karşılamayan bir araç, sürücü dahil kaç kişiyi taşımak üzere tasarlanmışsa yine de Class C CDL gerektirir?","options":["8 veya daha fazla","11 veya daha fazla","24 veya daha fazla","16 veya daha fazla"],"explanation":"Mississippi Class C, Class A/B ağırlık eşiklerinin altında olup sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış ya da plakart (placard) gerektiren tehlikeli maddeler taşıyan araçlar için geçerlidir. Kaynak: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"23":{"q":"16 yolcu kuralının yanı sıra, Mississippi'de daha küçük bir aracın Class C CDL gerektirmesine hangi başka koşul yol açar?","options":["Ticari kullanım için tescilli olması","Plakart gerektiren miktarlarda tehlikeli madde taşıması","Bir eyalet sınırını geçmesi","Bir taşıma şirketine ait olması"],"explanation":"Class A/B ağırlık sınırlarının altındaki bir araç, plakart gerektiren miktarda tehlikeli madde taşımak için kullanılıyorsa Class C CDL gerektirir. Kaynak: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"24":{"q":"Mississippi'de plakart gerektiren miktarlarda tehlikeli madde taşımak için hangi CDL onay belgesi (endorsement) gereklidir?","options":["N onayı","T onayı","H onayı","Yalnızca X onayı"],"explanation":"Plakart gerektiren tehlikeli maddeleri taşımak için H (HazMat) onayı gereklidir. X onayı, birleşik bir HazMat-artı-Tank onayıdır ve yalnızca HazMat'a ihtiyaç duyan sürücüler için gerekli değildir. Kaynak: Mississippi DPS Driver Service Bureau, CDL onay listesi; FMCSA 49 CFR 383.93."},"25":{"q":"Mississippi'de, hangi onay bir CDL sahibinin bir tank aracı (tanker) sürmesine yetki verir?","options":["T onayı","P onayı","S onayı","N onayı"],"explanation":"N onayı tank aracı (tanker) onayıdır. T çift/üçlü (doubles/triples), P yolcu (passenger) ve S okul otobüsüdür (school bus). Kaynak: Mississippi DPS Driver Service Bureau, CDL onay listesi; FMCSA 49 CFR 383.93."},"26":{"q":"Çift veya üçlü römork çekmek için hangi Mississippi CDL onayı gereklidir?","options":["T onayı","N onayı","H onayı","P onayı"],"explanation":"Çift veya üçlü römork çekmek için T onayı (doubles/triples) gereklidir ve yalnızca bir bilgi (knowledge) testi ile alınır. Kaynak: Mississippi DPS Driver Service Bureau, CDL onay listesi; FMCSA 49 CFR 383.93."},"27":{"q":"Bir Mississippi CDL'sindeki X onayı neyi temsil eder?","options":["Yenileme bekleyen süresi dolmuş bir onay","Tıbbi sertifikadan muafiyet","HazMat (H) ve Tank (N) onaylarının bir kombinasyonu","Eyalet dışı karşılıklılık (reciprocity) onayı"],"explanation":"Mississippi, X'i birleşik HazMat ve Tank onayı olarak listeler ve bir sürücü hem H hem de N için nitelikli olduğunda verilir. Kaynak: Mississippi DPS Driver Service Bureau, CDL onay listesi; FMCSA 49 CFR 383.93."},"28":{"q":"Mississippi'de okul otobüsü kullanmak için, bir CDL sahibinin hangi onay kombinasyonunu alması gerekir?","options":["Yalnızca S (okul otobüsü) onayı","Yalnızca P (yolcu) onayı","T (çift/üçlü) onayı","Hem P (yolcu) hem de S (okul otobüsü) onayları"],"explanation":"Mississippi okul otobüsü sürücüleri hem Yolcu (P) hem de Okul Otobüsü (S) onaylarını taşımalıdır; S onayı P onayının üzerine eklenir. Kaynak: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.93."},"29":{"q":"Yalnızca eyalet içi (intrastate) sürüş için geçerli bir Mississippi CDL'si almak için asgari yaş nedir?","options":["18 yaş","21 yaş","19 yaş","16 yaş"],"explanation":"Mississippi, yalnızca eyalet içi ticaret için 18 yaşında CDL'ye izin verir; eyaletler arası (interstate) sürüş 21 yaş gerektirir. Kaynak: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"30":{"q":"Bir Mississippi CDL'si ile eyalet sınırlarını aşarak (interstate) ticari bir motorlu araç kullanmak için gereken asgari yaş nedir?","options":["18 yaş","21 yaş","19 yaş","25 yaş"],"explanation":"Sürücüler, eyaletler arası ticarette çalışmak ve eyaletler arası iş için HazMat veya yolcu onaylarına sahip olmak için en az 21 yaşında olmalıdır. Kaynak: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 391.11."},"31":{"q":"Mississippi'de, bir sürücünün eyaletler arası çalışma için HazMat (H) veya yolcu (P) onayı alabilmesi için gereken asgari yaş nedir?","options":["18 yaş","19 yaş","23 yaş","21 yaş"],"explanation":"Mississippi, federal kurallara uygun olarak, eyaletler arası ticaret için HazMat veya yolcu onayı verilmesi için sürücünün en az 21 yaşında olmasını gerektirir. Kaynak: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"32":{"q":"Mississippi'de bir Ticari Öğrenci Belgesi (CLP) aldıktan sonra, bir sürücünün CDL beceri (yol) testine girmesine izin verilmeden önce belgeyi ne kadar süre elinde tutması gerekir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Mississippi tarafından benimsenen federal kural, başvuru sahibinin CDL beceri testine girebilmesi için CLP'nin en az 14 gün tutulmasını gerektirir. Kaynak: Mississippi CDL Manual; FMCSA 49 CFR 383.25."},"33":{"q":"Bir Mississippi Ticari Öğrenci Belgesi (CLP), yenilenmesi veya CDL'nin alınması gerekene kadar ne kadar süre geçerlidir?","options":["30 gün","180 gün (6 ay)","1 yıl","90 gün"],"explanation":"Bir Mississippi CLP'si 180 gün (altı ay) geçerlidir; eyaletler ek 180 gün için bir kez yenilemeye izin verebilir. Kaynak: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.25."},"34":{"q":"Bir Mississippi Ticari Öğrenci Belgesi'ne (CLP) hangi onayın eklenmesine izin verilmez?","options":["Tank boşken N (tank) onayı","P (yolcu) onayı","H (HazMat) onayı","S (okul otobüsü) onayı"],"explanation":"Mississippi tarafından benimsenen federal kurallar, bir CLP üzerinde HazMat (H) onayını yasaklar; bir CLP üzerinde yalnızca P, S ve N onayları, kısıtlamalarla birlikte yer alabilir. Kaynak: Mississippi CDL Manual; FMCSA 49 CFR 383.25."},"35":{"q":"Bir Mississippi başvuru sahibi, HazMat (H) onayı için gereken parmak izi alımı ve TSA arka plan kontrolünü artık nerede tamamlar?","options":["Yerel DPS CDL istasyonunda değil, TSA Universal Enrollment Services sağlayıcısı (IdentoGO) aracılığıyla","Herhangi bir yerel Mississippi DPS CDL istasyonunda","FMCSA National Registry ofisinde","İlçe sulh mahkemesi katibinin ofisinde"],"explanation":"Mississippi, HazMat parmak izi alımını ve kaydı TSA Universal Enrollment Services programına (IdentoGO / universalenroll.dhs.gov) taşımıştır; bu artık yerel DPS CDL istasyonlarında yapılmamaktadır. Kaynak: Mississippi DPS Driver Service Bureau, CDL HazMat Enrollment Program."},"36":{"q":"7 Şubat 2022'den bu yana, ilk kez Mississippi CDL başvurusunda bulunanlar, Giriş Düzeyi Sürücü Eğitimini (ELDT) kim tarafından sağlanmak üzere tamamlamalıdır?","options":["Herhangi bir Mississippi community college","Mississippi DPS'in kendisi","Herhangi bir türden işveren içi eğitmen","FMCSA Training Provider Registry'de listelenen bir sağlayıcı"],"explanation":"7 Şubat 2022'den itibaren, ilk kez CDL başvurusunda bulunanlar (ve belirli yükseltmeler/onaylar), CDL testinden önce FMCSA Training Provider Registry'de listelenen bir sağlayıcıdan ELDT'yi tamamlamalıdır. Kaynak: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR Part 380."},"37":{"q":"Bir Mississippi CDL başvuru sahibi sürüş türünü kendi beyan ederken (self-certify), hangi kategori eyaletler arası ticarette çalıştıklarını ve federal DOT tıbbi sertifika gerekliliklerini karşılamaları gerektiğini gösterir?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Mississippi dört federal öz beyan kategorisini kullanır. Non-Excepted Interstate (NI) sürücüler eyalet sınırlarını aşarak çalışır ve geçerli bir DOT tıbbi muayene sertifikası taşımalıdır. Kaynak: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.71."},"38":{"q":"Bir Mississippi CDL başvuru sahibi, kimlik/yasal mevcudiyet, Sosyal Güvenlik ve ikamet gerekliliklerini karşılamak için hangi belge setini ibraz etmelidir?","options":["Bir lise diploması, bir seçmen kartı ve bir fatura","İkamet kanıtı gerekmeden yalnızca bir pasaport","Orijinal bir doğum belgesi (veya yasal mevcudiyet kanıtı), Sosyal Güvenlik numarası belgesi ve iki Mississippi ikamet kanıtı","Bir araç ruhsatı, bir sigorta kartı ve bir balıkçılık ruhsatı"],"explanation":"Mississippi, CDL başvurusu için kimlik/yasal mevcudiyet kanıtı (örneğin orijinal doğum belgesi), Sosyal Güvenlik numarası belgesi ve iki ikamet kanıtının yanı sıra geçerli bir tıbbi kart gerektirir. Kaynak: Mississippi DPS Driver Service Bureau, CDL başvuru gereklilikleri."},"39":{"q":"Mississippi'de, bir kişinin yasal olarak ticari bir motorlu araç kullanabileceği azami kan/nefes alkol konsantrasyonu (BAC) nedir?","options":["0.02","0.04","0.08","0.10"],"explanation":"Mississippi federal CMV standardını izler: ticari bir motorlu aracı 0.04% veya daha yüksek bir alkol konsantrasyonuyla kullanmak yasa dışıdır. 0.04% veya daha yüksek bir okuma, ilk ağır suç (major-offense) diskalifiyesi için gerekçe oluşturur. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51; Mississippi CDL Manual (DPS)."},"40":{"q":"Bir Mississippi CDL sahibi, plakart gerektiren tehlikeli maddeler taşımazken bir CMV'yi 0.04% BAC ile kullanmaktan ilk kez mahkum oluyor. Sürücü ne kadar süre CMV kullanmaktan diskalifiye edilir?","options":["6 ay","1 yıl","3 yıl","Ömür boyu"],"explanation":"İlk ağır suç (0.04% veya daha yüksek BAC ile CMV kullanmak dahil), Mississippi'de asgari 1 yıllık CDL diskalifiyesiyle sonuçlanır. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"41":{"q":"Bir Mississippi CDL sahibi, plakart gerektiren tehlikeli maddeler taşırken ilk ağır suçu (örneğin bir CMV'de DUI) işlerse, diskalifiye süresi şuna yükselir:","options":["1 yıl","2 yıl","3 yıl","5 yıl"],"explanation":"Mississippi ve federal kurallar kapsamında, plakart gerektiren tehlikeli maddeler taşınırken işlenen ilk ağır suç, standart 1 yıl yerine 3 yıllık bir diskalifiye gerektirir. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual."},"42":{"q":"İKİNCİ bir ağır suçtan (örneğin bir CMV'de ikinci bir DUI) mahkum olan bir Mississippi CDL sahibi için diskalifiye süresi nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"Herhangi bir ağır suçtan ikinci kez mahkumiyet, Mississippi'de ömür boyu CDL diskalifiyesiyle sonuçlanır. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(3); Mississippi CDL Manual."},"43":{"q":"Mississippi'de, bir CDL sahibi yasal olarak talep edildiğinde nefes veya kan kimyasal testine girmeyi reddederse ticari sürüş ayrıcalığına ne olur?","options":["Diskalifiye olmadan bir uyarı verilir","30 gün diskalifiye","1 yıl diskalifiye","90 gün diskalifiye"],"explanation":"Kimyasal testin reddedilmesi bir ağır suç olarak değerlendirilir; Mississippi'nin örtük rıza (implied-consent) yasası kapsamında ilk ret için bir CDL en az 1 yıl diskalifiye edilir. Kaynak: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"44":{"q":"Mississippi'nin örtük rıza yasası kapsamında, bir Mississippi karayolunda herhangi bir motorlu araç kullanan bir sürücünün şunu yapmış sayılır:","options":["Avukat hakkından feragat etmiş","Nefes, kan veya idrarın kimyasal testine rıza göstermiş","Rastgele yol kenarı denetimlerini kabul etmiş","Otomatik ehliyet puanlarını kabul etmiş"],"explanation":"Mississippi'nin örtük rıza yasası, eyaletin yollarında araç kullanan herhangi bir kişinin alkol veya uyuşturucu konsantrasyonunu belirlemek için kimyasal bir teste rıza vermiş sayılacağını öngörür. Kaynak: Miss. Code Ann. 63-11-5, 63-11-30; Mississippi CDL Manual (DPS)."},"45":{"q":"Mississippi'de 3 yıllık bir dönemde (ayrı olaylardan kaynaklanan) kaç ciddi trafik ihlali 60 günlük bir CDL diskalifiyesini tetikler?","options":["1","2","3","4"],"explanation":"3 yıllık bir dönemde iki ciddi trafik ihlali (ayrı olaylardan kaynaklanan) 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"46":{"q":"Mississippi'de, 3 yıllık bir dönemde ÜÇ ciddi trafik ihlalinden mahkumiyet, şu CDL diskalifiyesiyle sonuçlanır:","options":["60 gün","90 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde üç ciddi trafik ihlali (ayrı olaylar) 120 günlük bir diskalifiye ile sonuçlanır ve bu, daha önceki herhangi bir 60 günlük diskalifiyeden sonra ardışık olarak uygulanır. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"47":{"q":"Aşağıdakilerden hangisi bir Mississippi CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["0.04% veya daha yüksek BAC ile bir CMV kullanmak","Belirlenen hız sınırının 15 mph veya daha fazla üzerinde hız yapmak","Kimyasal testi reddetmek","Kaza yerini terk etmek"],"explanation":"Sınırın 15 mph veya daha fazla üzerinde hız yapmak ciddi bir trafik ihlalidir. Listelenen diğer üçü, ciddi ihlaller değil, 1 yıl (veya daha uzun) diskalifiye getiren ağır suçlardır. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"48":{"q":"Aşağıdakilerden hangisi bir Mississippi CDL sahibi için ciddi bir trafik ihlali olarak SAYILMAZ?","options":["Öndeki araca çok yakın takip etmek","Dikkatsiz araç kullanmak (reckless driving)","Düzensiz veya uygunsuz şerit değiştirme yapmak","Gözetimsiz bir CMV'yi geceleyin uygunsuz park etmek"],"explanation":"Çok yakın takip, dikkatsiz araç kullanma ve düzensiz/uygunsuz şerit değiştirme ihlallerinin tümü ciddi trafik ihlalleridir. Gözetimsiz bir aracın rutin park edilmesi ciddi ihlal listesinde yer almaz. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"49":{"q":"Bir CMV kullanırken mesaj atan veya elde tutulan bir cep telefonu kullanan bir Mississippi CDL sürücüsü ne tür bir ihlal işlemiş olur?","options":["Raporlanamayan bir kabahat","Ciddi bir trafik ihlali","Bir ağır suç","Bir hizmet dışı (out-of-service) ihlali"],"explanation":"Bir CMV kullanırken mesaj atmak veya elde tutulan bir telefon kullanmak ciddi bir trafik ihlalidir; 3 yıl içinde iki veya üç böyle ciddi ihlal, 60 veya 120 günlük bir diskalifiyeye yol açabilir. Kaynak: 49 CFR 383.51(c), 392.80/392.82; Miss. Code Ann. 63-1-216; Mississippi CDL Manual."},"50":{"q":"Plakart gerektiren tehlikeli maddeler veya 16 ya da daha fazla yolcu taşıyan bir Mississippi CDL sürücüsü tarafından işlenen İLK hizmet dışı emri ihlali, şu diskalifiyeyi getirir:","options":["180 günden az olmamak, 2 yıldan fazla olmamak üzere","Tam olarak 180 gün","60 günden az olmamak, 1 yıldan fazla olmamak üzere","Ömür boyu"],"explanation":"İlk hizmet dışı ihlali, plakart gerektiren tehlikeli madde taşınırken veya 16+ yolcu taşınırken meydana geldiğinde, diskalifiye 180 günden az ve 2 yıldan fazla değildir. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(e); Mississippi CDL Manual."},"51":{"q":"Bir CMV kullanırken İLK demiryolu-karayolu hemzemin geçit ihlalinden mahkum olan bir Mississippi CDL sürücüsü, şu süre için diskalifiye edilir:","options":["30 günden az olmamak üzere","60 günden az olmamak üzere","120 günden az olmamak üzere","1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, 60 günden az olmayan bir diskalifiye ile sonuçlanır. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual."},"52":{"q":"Bir Mississippi CDL sürücüsünün 3 yıllık bir dönemde ÜÇÜNCÜ demiryolu-karayolu hemzemin geçit ihlali için diskalifiye süresi nedir?","options":["120 gün","6 ay","1 yıl","Ömür boyu"],"explanation":"3 yıl içinde üçüncü (veya sonraki) bir demiryolu hemzemin geçit ihlali, 1 yıldan az olmayan bir diskalifiye ile sonuçlanır. İlerleme şöyledir: 60 gün (birinci), 120 gün (ikinci), 1 yıl (üçüncü). Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual."},"53":{"q":"Mississippi'de, kontrollü bir maddenin üretimi, dağıtımı veya temini içeren bir suçu işlemek için ticari bir motorlu araç kullanan bir CDL sahibi, şu süre için diskalifiye edilir:","options":["1 yıl","3 yıl","10 yıl","Yeniden hak kazanma olmaksızın ömür boyu"],"explanation":"Kontrollü maddelerle ilgili bir suçun işlenmesinde bir CMV kullanmak, bazı ömür boyu diskalifiyelerin aksine azaltılamayan ömür boyu bir diskalifiye ile sonuçlanır. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"54":{"q":"Aşağıdakilerden hangisi Mississippi'de ciddi bir trafik ihlali yerine bir AĞIR suçtur (asgari 1 yıl diskalifiye)?","options":["Çok yakın takip","Bir CMV içeren kaza yerini terk etmek","Sınırın 15 mph üzerinde hız yapmak","Uygunsuz şerit değiştirme"],"explanation":"Bir CMV içeren kaza yerini terk etmek, asgari 1 yıl diskalifiye getiren bir ağır suçtur. Diğer seçenekler ciddi trafik ihlalleridir. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"55":{"q":"Mississippi'de, bir CDL sahibi bir kimyasal testi reddederse, ticari ayrıcalığın diskalifiyesi şu durumda uygulanır:","options":["Yalnızca sürücü o sırada bir CMV kullanıyorsa","Yalnızca BAC daha sonra 0.04% üzerinde çıkarsa","Ret, kişisel (ticari olmayan) bir araç kullanırken gerçekleşmiş olsa bile","Yalnızca ikinci bir retten sonra"],"explanation":"Bir CDL sahibi, ret ticari olmayan bir araç kullanırken gerçekleşse bile bir kimyasal testi reddetmekten diskalifiye edilir; kişisel bir araçtaki mahkumiyetler ve retler de CDL'yi etkiler. Kaynak: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51; Mississippi CDL Manual."},"56":{"q":"Bir Mississippi CDL sürücüsü, KİŞİSEL aracında ehliyet askıya alınmasıyla sonuçlanan ciddi bir trafik ihlali alıyor. Bu CDL'yi nasıl etkiler?","options":["Bir CMV olmadığı için hiçbir etkisi yoktur","Yine de CDL diskalifiyesine sayılır","Yalnızca sürücü görev başındaysa sayılır","Yalnızca hazmat onayını etkiler"],"explanation":"Kişisel bir araçtaki mahkumiyetler ve ehliyet işlemleri CDL'ye karşı sayılır; belirli ciddi ihlaller için sürüş ayrıcalığının askıya alınması/iptali/feshi CDL diskalifiyesine yol açar. Kaynak: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual."},"57":{"q":"Mississippi'nin Kenara Çekil (Move Over) yasası uyarınca, kendi yönünüzde iki şeridi olan dört şeritli bir karayolunda, ikaz lambaları yanıp sönen, durmuş bir acil durum veya çekici aracına yaklaştığınızda ne yapmanız gerekir?","options":["Güvenliyse, durmuş aracın yanındaki şeritten çıkın","Durmuş araç ayrılana kadar tamamen durun","Aracın yanından geçerken kornanızı sürekli çalın","Hızınızı koruyun ve mevcut şeridinizde kalın"],"explanation":"Miss. Code 63-3-809, en az dört şeritli (aynı yönde iki veya daha fazla şerit olan) bir karayolundaki sürücülerin, güvenli olduğunda durmuş acil durum, kurtarma veya hizmet aracına bitişik olmayan bir şeride geçmesini gerektirir. Kaynak: Mississippi Code 63-3-809."},"58":{"q":"Mississippi'nin Kenara Çekil (Move Over) yasası uyarınca, ikaz lambaları yanıp sönen, durmuş bir acil durum aracından güvenli bir şekilde uzağa şerit değiştiremiyorsanız, bunun yerine ne yapmanız gerekir?","options":["Hiçbir şey değiştirmeden, belirlenen hız sınırında devam edin","Şeridinizde durup bir memurun sizi geçmeniz için işaret etmesini bekleyin","Yavaşlayın, dikkatli ilerleyin ve durmaya hazır olun","Dörtlü ikaz lambalarınızı yakıp normal hızda geçin"],"explanation":"Miss. Code 63-3-809, güvenli bir şekilde şerit değiştiremeyen bir sürücünün hızını azaltmasını, gerekli dikkatle ilerlemesini ve durmaya hazır olmasını öngörür. Kaynak: Mississippi Code 63-3-809."},"59":{"q":"Mississippi'de, hasara veya yaralanmaya yol açMAYAN bir Kenara Çekil (Move Over) yasası ihlali (63-3-809), en fazla ne kadar para cezasıyla cezalandırılır?","options":["En fazla $100","En fazla $250","En fazla $500","En fazla $1,000"],"explanation":"Miss. Code 63-3-809, bir ihlal için en fazla $250 para cezası belirler; ihlal durmuş araçta maddi hasara veya içindekilerde bedensel yaralanmaya yol açarsa bu ceza en fazla $1,000'a yükselir. Kaynak: Mississippi Code 63-3-809."},"60":{"q":"Yetkili acil durum araçlarının yanı sıra, yanıp sönen ikaz lambaları gösteren, durmuş aşağıdaki araçlardan hangisini Mississippi'nin Kenara Çekil (Move Over) yasası (63-3-809) da korur?","options":["Sadece işaretli kolluk kuvveti araçları","Sadece ambulanslar ve itfaiye araçları","Kurtarma (çekici) araçları ve altyapı hizmet araçları","Sadece eyalet hükümetine ait araçlar"],"explanation":"Miss. Code 63-3-809, kenara çekilme/yavaşlama yükümlülüğünü, durmuş yetkili acil durum araçlarının yanı sıra yetkili yanıp sönen lambalar kullanan kurtarma (çekici) ve altyapı hizmet araçlarını da kapsayacak şekilde genişletir. Kaynak: Mississippi Code 63-3-809."},"61":{"q":"Mississippi eyaletler arası karayollarının çoğunda, Mississippi Ulaştırma Komisyonu maksimum hız sınırını hangi değerden daha yüksek belirleyemez?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Miss. Code 63-3-501, Ulaştırma Komisyonunun Eyaletler Arası Karayolu Sistemi'nde ve dört veya daha fazla şeritli kontrollü erişimli karayollarında belirleyebileceği maksimum hızı 70 mph ile sınırlar. Kaynak: Mississippi Code 63-3-501."},"62":{"q":"Mississippi Code 63-3-501 uyarınca, bir eyaletler arası karayolunda veya dört şeritli bir A.B.D. karayolunda 70 mph sınırı belirlendiğinde, maksimum hız kısıtlaması 70 mph olan bir araca hangi MİNİMUM hız uygulanır?","options":["30 mph","40 mph","45 mph","50 mph"],"explanation":"Miss. Code 63-3-501, bu tür karayollarında maksimum hız kısıtlaması 70 mph olan araçlar için 40 mph minimum hız belirler. Kaynak: Mississippi Code 63-3-501."},"63":{"q":"Mississippi yasaları uyarınca, bir demiryolu hemzemin geçidini geçmeden önce yolcu taşıyan bir otobüsü durdurduğunuzda, en yakın raydan ne kadar mesafe içinde durmalısınız?","options":["50 feet içinde ancak 15 feet'ten az olmamak üzere","25 feet içinde ancak 5 feet'ten az olmamak üzere","75 feet içinde ancak 25 feet'ten az olmamak üzere","100 feet içinde ancak 50 feet'ten az olmamak üzere"],"explanation":"Miss. Code 63-3-1011, otobüslerin, ücret karşılığı yolcu taşıyan araçların, okul otobüslerinin ve patlayıcı veya yanıcı sıvı taşıyan araçların en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak üzere durmasını gerektirir. Kaynak: Mississippi Code 63-3-1011."},"64":{"q":"Mississippi CDL Kılavuzuna göre, hangi ticari araçların demiryolu hemzemin geçitlerinde her zaman durması gerekir?","options":["10,000 pounds'tan ağır tüm ticari araçlar","Yolcu taşıyan otobüsler ve plakart işaretli tehlikeli madde taşıyan araçlar","Sadece üç römorklu kombinasyonlar","Herhangi bir türde römork çeken her araç"],"explanation":"Mississippi CDL Kılavuzu (49 CFR 392.10 ve Miss. Code 63-3-1011'i yansıtarak), yolcu taşıyan otobüslerin ve plakart işaretli tehlikeli madde araçlarının rayları geçmeden önce durmasını, ardından bakıp dinlemesini gerektirir. Kaynak: Mississippi CDL Manual / Miss. Code 63-3-1011."},"65":{"q":"Mississippi'de bir demiryolu geçidinde durmanız gerektiğinde, 15 ila 50 feet'lik bölge içinde durduktan sonra, bir otobüs veya plakart işaretli araç sürücüsü rayları nasıl geçmelidir?","options":["Geçidi hızlıca temizlemek için vites büyüterek hızla","Vites değiştirmeden geçişi tamamlamaya olanak veren bir viteste","Boşta, debriyaj basılı halde kayarak","Sadece kornayı üç kez çaldıktan sonra"],"explanation":"Mississippi CDL Kılavuzu, sürücülere vites değiştirmeden geçişi tamamlamaya olanak veren bir viteste geçmelerini ve raylar üzerindeyken vites değiştirmemelerini talimat verir. Kaynak: Mississippi CDL Manual (demiryolu geçitleri)."},"66":{"q":"Mississippi'nin okul otobüsü yasası (Nathan's Law, 63-3-615) uyarınca, kırmızı lambaları yanıp sönen ve dur kolu açık halde çocukları bindiren veya indiren bir okul otobüsüne karşı yönden gelen veya onu geçen bir araç ne kadar yakına durabilir?","options":["Otobüsten 10 feet'ten az olmamak üzere","Otobüsten 25 feet'ten az olmamak üzere","Otobüsten 50 feet'ten az olmamak üzere","Otobüsten 5 feet'ten az olmamak üzere"],"explanation":"Miss. Code 63-3-615, karşı yönden gelen veya geçen sürücülerin, çocukları bindirmek veya indirmek için durmuş bir okul otobüsünden 10 feet'ten az olmamak üzere durmasını gerektirir. Kaynak: Mississippi Code 63-3-615."},"67":{"q":"Bir Mississippi karayolunda, bir sürücü hangi koşulda çocukları bindirmek veya indirmek için durmuş bir okul otobüsü için durmak zorunda DEĞİLDİR?","options":["Sürücü herhangi bir çift şeritli yolda ters yönde seyahat ettiğinde her zaman","Otobüs, en az iki şeridi ters yönlerde olan, dört veya daha fazla şeritli bölünmüş bir karayolunun karşı yöndeki yolunda durduğunda","Trafik yoğun olduğunda ve durmak elverişsiz olacağında her zaman","Sürücü otobüsten 100 feet'ten fazla uzakta olduğunda"],"explanation":"Miss. Code 63-3-615, dört veya daha fazla şeritli bölünmüş bir karayolunda (en az iki şeridin ters yönlerde trafiğe izin verdiği), karşı yöndeki yolda durmuş bir otobüs için durması gereken sürücüyü bu yükümlülükten muaf tutar. Kaynak: Mississippi Code 63-3-615."},"68":{"q":"Mississippi Code 63-3-615 uyarınca, durmuş bir okul otobüsünü yasa dışı şekilde geçmenin ilk ihlal cezası ne kadardan az değildir?","options":["$100'dan az değil","$200'dan az değil","$350'dan az değil","$1,000'dan az değil"],"explanation":"Miss. Code 63-3-615, durmuş bir okul otobüsünü yasa dışı şekilde geçmek için ilk ihlal cezasını $350'dan az, $750'dan fazla olmamak üzere (ve olası hapis cezasıyla) belirler. Kaynak: Mississippi Code 63-3-615."},"69":{"q":"Mississippi'nin şerit kullanım kuralları uyarınca, normal trafik hızından daha yavaş ilerleyen bir ticari araç, çok şeritli bir karayolunda nerede sürülmelidir?","options":["Sağ şeritte veya yolun sağ kenarına mümkün olduğunca yakın","Her zaman orta şeritte","Katılan trafikten uzak durmak için sol şeritte","Trafiğin en az olduğu şeritte"],"explanation":"Miss. Code 63-3-603, normal trafik hızından daha yavaş giden bir aracın, geçiş yaparken veya sola dönüşe hazırlanırken hariç, sağ şeridi kullanmasını veya yolun sağ kenarına mümkün olduğunca yakın kalmasını gerektirir. Kaynak: Mississippi Code 63-3-603."},"70":{"q":"Mississippi Code 63-3-603, çok şeritli bir yolun en sol şeridinde sürekli sürmek hakkında ne söyler?","options":["Kamyonlar için izinlidir ancak otomobiller için yasaktır","Diğer trafiğin akışını engellediğinde yasaktır","26,000 pounds üzerindeki tüm araçlar için zorunludur","Önce sinyal verdiğiniz sürece her zaman izinlidir"],"explanation":"Miss. Code 63-3-603, çok şeritli bir yolun en dıştaki sol şeridinde sürekli sürmeyi, bunu yapmak diğer trafiğin akışını engellediğinde yasaklar. Kaynak: Mississippi Code 63-3-603."},"71":{"q":"Mississippi CDL Kılavuzuna göre, ticari aracınız tek yönlü veya bölünmüş bir karayolunun banketinde durduğunda, üç ikaz üçgeninizi nereye yerleştirirsiniz?","options":["Yaklaşan trafiğe doğru 10, 100 ve 200 feet'te (hepsi arkaya doğru)","25 feet önde, araçta ve 25 feet arkada","Biri araçta ve ikisi yan yana 50 feet arkada","Aracın hem önünde hem arkasında 10, 100 ve 200 feet'te"],"explanation":"Mississippi CDL Kılavuzu (49 CFR 392.22 uyarınca), tek yönlü veya bölünmüş bir karayolunda üçgenlerin yaklaşan trafiğe doğru 10, 100 ve 200 feet'te yerleştirilmesini yönlendirir. Kaynak: Mississippi CDL Manual / 49 CFR 392.22."},"72":{"q":"Mississippi CDL Kılavuzuna göre, her iki yönde trafik taşıyan çift şeritli bölünmemiş bir yolda, durmuş bir ticari araç için ikaz cihazları nereye yerleştirilmelidir?","options":["Üçünün hepsi aracın 10 feet arkasında","Aracın 10 feet içinde, artı 100 feet arkada ve 100 feet önde","Sadece bir cihaz, aracın 200 feet arkasında","Aracın 50 feet ve 500 feet arkasında"],"explanation":"Mississippi CDL Kılavuzu (49 CFR 392.22 uyarınca), çift şeritli iki yönlü bir yolda aracın 10 feet içinde bir cihaz ve yaklaşık 100 feet arkada ve 100 feet önde cihazlar gerektirir. Kaynak: Mississippi CDL Manual / 49 CFR 392.22."},"73":{"q":"Mississippi CDL Kılavuzuna göre, bir ticari araç bir yolda veya bankette durduktan sonra, sürücü acil durum ikaz cihazlarını kaç saniye içinde yerleştirmelidir?","options":["5 saniye içinde","10 dakika içinde","30 dakika içinde","1 saat içinde"],"explanation":"Mississippi CDL Kılavuzu (49 CFR 392.22 uyarınca), ikaz cihazlarının durduktan sonraki 10 dakika içinde yerleştirilmesini gerektirir; dörtlü ikaz lambaları hemen ve üçgenler yerleştirilene kadar kullanılır. Kaynak: Mississippi CDL Manual / 49 CFR 392.22."},"74":{"q":"Eyaleti çapraz olarak geçen hangi Mississippi güzergahı, ticari kamyonların (bir tonluk anma kapasitesinin üzerindekilerin) kullanımını yasaklar?","options":["Interstate 55","U.S. Highway 49","Natchez Trace Parkway","Interstate 20"],"explanation":"Federal olarak yönetilen manzaralı bir güzergah olan Natchez Trace Parkway, ticari araçları ve bir tonluk anma kapasitesinin üzerindeki kamyonları yasaklar. Kaynak: 36 CFR 7.43 / National Park Service."},"75":{"q":"Mississippi'de, bir aşırı boyut izni gerekmeden önce belirlenmiş karayollarında izin verilen maksimum yasal araç genişliği nedir?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Mississippi'nin belirlenmiş karayollarındaki yasal maksimum genişliği 8 feet 6 inches'tır; bundan daha geniş yükler bir aşırı boyut izni gerektirir. Kaynak: Mississippi DOT aşırı boyut/aşırı ağırlık izin kuralları."},"76":{"q":"Mississippi'de, bir aşırı ağırlık izni gerekmeden önce eyaletler arası karayolu sistemindeki maksimum yasal brüt araç ağırlığı nedir?","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"Mississippi, eyaletler arası karayolu sistemindeki 80,000 pounds maksimum yasal brüt ağırlık federal sınırını takip eder; bunu aşmak MDOT'tan bir aşırı ağırlık izni gerektirir. Kaynak: Mississippi DOT aşırı ağırlık izin kuralları."},"77":{"q":"Eyalette ticari sürücü ehliyetlerini düzenleyen ve CDL testlerini yöneten Mississippi kurumu hangisidir?","options":["Mississippi Department of Public Safety (DPS), Driver Service Bureau aracılığıyla","Mississippi Department of Transportation (MDOT)","Sürücünün ikamet ettiği ilçenin Circuit Clerk ofisi","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"Mississippi CDL'leri, Mississippi Department of Public Safety (DPS) tarafından Driver Service Bureau aracılığıyla düzenlenir ve CDL testleri bu kurum tarafından yönetilir. MDOT yolları ve izinleri yönetir, ehliyetlendirmeyi değil; FMCSA federal standartları belirler ancak eyalet ehliyetleri düzenlemez. Kaynak: MS DPS Driver Service Bureau; Miss. Code Title 63, Chapter 1."},"78":{"q":"Mississippi CDL bilgi (yazılı) sınavlarında minimum geçme puanı nedir?","options":["80%","70%","75%","90%"],"explanation":"Mississippi, federal AAMVA test standardıyla tutarlı olarak, her bir gerekli CDL bilgi sınavında minimum 80% puan gerektirir. Kaynak: MS DPS / Mississippi CDL Manual."},"79":{"q":"İlk kez başvuran bir Mississippi CDL adayı, gerekli bilgi veya beceri testlerine girmeden önce hangi eğitimi tamamlamış olmalıdır?","options":["FMCSA kayıtlı bir eğitim sağlayıcısından Entry-Level Driver Training (ELDT)","MDOT tarafından onaylanmış bir defansif sürüş kursu","Bir community college'da 40 saatlik bir sınıf içi kurs","Mississippi Trucking Association'a kaydedilmiş bir çıraklık"],"explanation":"7 Şubat 2022'den itibaren, ilk kez başvuran CDL adayları, gerekli beceri veya bilgi testlerine girmeden önce FMCSA'nın Training Provider Registry'sinde listelenen bir sağlayıcıdan Entry-Level Driver Training (ELDT) tamamlamalıdır. Kaynak: MS DPS Driver Service Bureau; FMCSA ELDT rule (49 CFR Part 380)."},"80":{"q":"Bir Mississippi Commercial Learner's Permit (CLP), sahibinin CDL beceri testine girebilmesinden önce ne kadar süre elde tutulmalıdır?","options":["En az 14 days","En az 30 days","En az 10 days","En az 60 days"],"explanation":"Mississippi, sahibinin CDL beceri testine girmeye uygun olmasından önce bir CLP'nin minimum 14 days elde tutulmasını gerektiren federal kuralı takip eder. Kaynak: MS DPS Driver Service Bureau; 49 CFR 383.25."},"81":{"q":"Bir Mississippi Commercial Learner's Permit (CLP) ne kadar süre geçerlidir?","options":["6 months","1 year","30 days","90 days"],"explanation":"Bir Mississippi CLP, federal maksimum CLP geçerlilik süresiyle tutarlı olarak 6 months (180 days) geçerlidir. Kaynak: MS DPS Driver Service Bureau; 49 CFR 383.25."},"82":{"q":"Mississippi CDL beceri testi, sırayla gerçekleştirilen hangi üç bölümden oluşur?","options":["Sefer öncesi araç muayenesi, temel araç kontrolü ve yolda sürüş","Yazılı bilgi testi, hava frenleri testi ve yolda sürüş","Sefer öncesi muayene, tehlikeli madde elleçleme ve gece sürüşü","Temel araç kontrolü, bağlama/ayırma ve yazılı bir onay sınavı"],"explanation":"Mississippi CDL beceri testinin üç bölümü vardır: sefer öncesi araç muayenesi, temel araç kontrol beceri testi ve yolda sürüş testi. Üçünün de geçilmesi gerekir. Kaynak: MS DPS / Mississippi CDL Manual."},"83":{"q":"Bir Mississippi ticari sürücü ehliyetinin yenilenmesi gerekmeden önceki geçerlilik süresi (süre) nedir?","options":["5 years, ehliyet sahibinin doğum gününde sona erer","4 years, ehliyet sahibinin doğum gününde sona erer","8 years, ehliyet sahibinin doğum gününde sona erer","2 years, tıbbi sertifikaya bağlı"],"explanation":"Bir Mississippi CDL beş yıllık bir süre için düzenlenir ve ehliyet sahibinin doğum gününde gece yarısı sona erer. Kaynak: Miss. Code Ann. Sec. 63-1-47 (ve Sec. 63-1-211)."},"84":{"q":"Bir Mississippi CDL sahibi, ehliyetini sona erme tarihinden ne kadar önce yenileyebilir?","options":["Sona ermeden önceki 6 months içinde herhangi bir zaman","Sadece sona ermeden önceki 30 days içinde","Sona ermeden önceki 90 days içinde herhangi bir zaman","Sadece sona erme tarihinde veya sonrasında"],"explanation":"Mississippi, yeniden muayene gerekmedikçe, başvuru ve gerekli ücretin ödenmesi üzerine, ehliyetin sona ermesinden önceki altı (6) months içinde herhangi bir zaman yenilemeye izin verir. Kaynak: Miss. Code Ann. Sec. 63-1-47."},"85":{"q":"Bir CDL adayı, sürüş türünü Mississippi DPS'e kendi beyan ettiğinde, seçebileceği kaç öz beyan kategorisi mevcuttur?","options":["Dört","İki","Üç","Beş"],"explanation":"Dört öz beyan kategorisi vardır: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate ve Excepted Intrastate. Adayın tam olarak birini seçmesi gerekir. Kaynak: MS DPS Driver Service Bureau Self-Certification; 49 CFR 383.71(b)."},"86":{"q":"Mississippi'de hangi öz beyan kategorisi, eyalet sınırları ötesinde faaliyet gösteren ve tüm federal tıbbi yeterlilik standartlarını karşılaması gereken bir sürücüye uygulanır?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Interstate (NI) sürücüler eyaletler arası ticarette faaliyet gösterir, tüm federal DOT tıbbi gerekliliklerini karşılamalı ve dosyalarında güncel bir tıbbi muayene sertifikası bulundurmalıdır. Kaynak: MS DPS Self-Certification categories; 49 CFR 383.71(b)."},"87":{"q":"Non-Excepted Interstate olarak öz beyanda bulunan bir Mississippi sürücüsü, geçerli bir CDL'yi sürdürmek için DPS'te dosyada ne bulundurmalıdır?","options":["Güncel bir DOT tıbbi muayene sertifikası","Güncel bir ticari genel sorumluluk sigortası sertifikası","Her altı ayda bir yenilenen bir CLP","Bir MDOT aşırı boyut/aşırı ağırlık izni"],"explanation":"Non-Excepted Interstate (ve Non-Excepted Intrastate) sürücüler, DPS kayıtlarında güncel bir DOT tıbbi muayene sertifikası bulundurmalıdır; bunun yapılmaması bir derece düşürülmesine yol açar. Kaynak: MS DPS Medical Certification Requirements; 49 CFR 383.71/383.73."},"88":{"q":"23 Haziran 2025'ten itibaren geçerli olmak üzere, bir CDL sürücüsünün DOT tıbbi muayene sonucu Mississippi DPS'e nasıl iletilir?","options":["Sertifikalı tıbbi muayene yetkilisi bunu elektronik olarak FMCSA'nın National Registry'sine sunar, o da DPS'e iletir","Sürücü Form MCSA-5876'nın bir kağıt kopyasını DPS merkezine postalar","Sürücü taranmış bir kopyayı DPS çevrimiçi portalı üzerinden yükler","İşveren yerel DPS sürücü ehliyeti istasyonuna bir kopya faksla gönderir"],"explanation":"23 Haziran 2025'te yürürlüğe giren FMCSA nihai kuralı uyarınca, sertifikalı tıbbi muayene yetkilileri muayene sonuçlarını elektronik olarak National Registry'ye sunar, o da bunları eyalete iletir; Mississippi sonucu doğrudan sürücü kaydına işler. Kaynak: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule."},"89":{"q":"23 Haziran 2025 federal değişikliğinden sonra, bir Mississippi sürücü ehliyeti istasyonu Medical Examiner's Certificate'in (Form MCSA-5876) kağıt veya taranmış bir kopyasını kabul edebilir mi?","options":["Hayır; sonuçlar elektronik olarak National Registry'den geldiği için kağıt ve taranmış kopyalar artık kabul edilmez","Evet; kağıt kopyalar birincil sunum yöntemi olmaya devam eder","Evet, ancak yalnızca muayeneden sonraki 15 days içinde noter onaylıysa","Evet, ancak yalnızca eyalet içi (NA) sürücüler için"],"explanation":"23 Haziran 2025 itibarıyla, DPS istasyonları artık fiziksel veya taranmış MCSA-5876 kopyalarını kabul etmez; tıbbi muayene sonucu FMCSA'nın National Registry'sinden elektronik olarak alınmalıdır. Kaynak: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule."},"90":{"q":"Mississippi'nin takip ettiği FMCSA kuralı uyarınca, sertifikalı bir tıbbi muayene yetkilisi bir CDL sürücüsünün muayene sonucunu National Registry'ye en geç ne zamana kadar yüklemelidir?","options":["Muayeneden sonraki takvim gününün sonuna kadar","Muayeneden sonraki 30 days içinde","Muayeneden sonraki 14 days içinde","Aynı iş haftasının sonuna kadar"],"explanation":"23 Haziran 2025'te yürürlüğe giren kural uyarınca, sertifikalı tıbbi muayene yetkilisi, muayene sonuçlarını muayeneyi takip eden takvim gününün gece yarısına kadar elektronik olarak National Registry'ye yüklemelidir. Kaynak: FMCSA Medical Examiner's Certification Integration final rule, MS DPS tarafından uygulanır."},"91":{"q":"Muaf olmayan (non-excepted) bir sürücü DOT tıbbi sertifikasının süresinin dolmasına izin verir ve güncellemezse, bir Mississippi CDL'ye ne olur?","options":["DPS, sertifikasyon yeniden sağlanana kadar ticari sürüş ayrıcalıklarını kaldırarak CDL'nin derecesini düşürür","CDL kalıcı olarak iptal edilir ve yeniden tesis edilemez","Bir sonraki 5 yıllık yenilemeye kadar hiçbir şey değişmez","Sürücü otomatik olarak Excepted Interstate olarak yeniden sınıflandırılır"],"explanation":"Tıbbi sertifikasyonunu güncel tutmayan, muaf olmayan bir sürücü \"sertifikasız\" olarak değiştirilir ve eyalet, geçerli sertifikasyon yeniden dosyada bulunana kadar ticari ayrıcalıkları kaldırarak CDL'nin derecesini düşürür. Kaynak: MS DPS Medical Certification Requirements; 49 CFR 383.73."},"92":{"q":"Bir DPS ofisinde yeni bir Mississippi CDL'ye başvururken genellikle hangi belgeler gereklidir?","options":["Kimlik/doğum kanıtı, Social Security numarası ve iki Mississippi ikamet kanıtı","Başka belge gerekmeden yalnızca bir pasaport","Bir lise diploması ve üç kişisel referans","Yalnızca bir araç tapusu ve ticari otomobil sigortası kanıtı"],"explanation":"Yeni bir CDL adayı, kimlik kanıtı (doğum belgesi gibi), Social Security numarasının kanıtı ve iki Mississippi ikamet kanıtı sunmalı, ayrıca gerekli sınavları geçmelidir. Kaynak: MS DPS Driver Service Bureau new CDL requirements."},"93":{"q":"Eyalet içi (eyalet sınırları içinde) ticari sürüşle sınırlı bir Mississippi CDL almak için minimum yaş nedir?","options":["18 yaş","21 yaş","19 yaş","16 yaş"],"explanation":"Bir sürücü, eyalet içi faaliyet için 18 yaşında bir CDL alabilir, ancak eyaletler arası faaliyet ve tehlikeli madde taşımacılığı için 21 yaşında olmalıdır. Kaynak: MS DPS / Mississippi CDL Manual; 49 CFR 383.3 / 391.11."},"94":{"q":"Eyaletler arası sürüş veya plakart işaretli tehlikeli madde taşımacılığı için bir Mississippi CDL almak için minimum yaş nedir?","options":["21 yaş","18 yaş","23 yaş","19 yaş"],"explanation":"Mississippi tarafından benimsenen federal kurallar, bir sürücünün eyaletler arası ticarette faaliyet göstermek ve plakart işaretli tehlikeli madde taşımak için en az 21 yaşında olmasını gerektirir. Kaynak: MS DPS / Mississippi CDL Manual; 49 CFR 391.11."},"95":{"q":"DPS muayene görevlilerinin yanı sıra, Mississippi CDL beceri (yol) testini yasal olarak kim uygulayabilir?","options":["Eyalet tarafından onaylanmış Third-Party Tester'lar/muayene görevlileri","İki yıllık deneyime sahip herhangi bir ehliyetli CDL sahibi","Adayın olası işvereninin güvenlik müdürü","FMCSA kayıtlı herhangi bir ELDT sınıf eğitmeni"],"explanation":"Mississippi, CDL beceri testinin ya DPS muayene görevlileri tarafından ya da DPS'in tuttuğu listeden eyalet tarafından onaylanmış Third-Party Tester'lar tarafından verilmesine izin verir. Kaynak: MS DPS Driver Service Bureau (Third-Party Tester program); 49 CFR 383.75."},"96":{"q":"Bir Mississippi adayı CDL beceri testinin yalnızca yolda sürüş bölümünde başarısız olur, ancak sefer öncesi muayene ve temel kontrol bölümlerini geçer. Genel sonuç ne olur?","options":["Aday yolda sürüş bölümünü tekrar etmeli ve henüz CDL'yi almaz","Aday otomatik olarak kısıtlı bir eyalet içi CDL alır","Üç beceri bölümünün hepsi baştan tekrar edilmelidir","Üç bölümden ikisi geçildiği için adaya CDL verilir"],"explanation":"Bir CDL verilmesi için üç beceri bileşeninin de (sefer öncesi muayene, temel araç kontrolü ve yolda sürüş) geçilmesi gerekir; herhangi bir bölümde başarısız olmak, o bölümün tekrar edilmesi gerektiği ve tümü geçilene kadar CDL'nin verilmediği anlamına gelir. Kaynak: MS DPS / Mississippi CDL Manual; 49 CFR 383.113."}},"es":{"0":{"q":"En las carreteras de Misisipi, ¿cuál es el ancho máximo legal de un vehículo comercial (excluyendo los dispositivos de seguridad requeridos y los espejos)?","options":["8 pies 0 pulgadas (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","9 pies 0 pulgadas (108 pulgadas)","10 pies 0 pulgadas (120 pulgadas)"],"explanation":"Misisipi limita el ancho del vehículo a 8 pies 6 pulgadas (102 pulgadas); una carga más ancha que eso requiere un permiso de sobredimensión. Fuente: Miss. Code Ann. Sec. 63-5-13 (Ancho exterior de los vehículos); reglas de permisos de la Oficina de Cumplimiento de MDOT."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, incluyendo cualquier carga, en las carreteras de Misisipi?","options":["14 pies 6 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas","13 pies 6 pulgadas"],"explanation":"Ningún vehículo, vacío o con carga, puede exceder una altura de 13 pies 6 pulgadas en Misisipi. Fuente: Miss. Code Ann. Sec. 63-5-17 (Altura de los vehículos)."},"2":{"q":"En Misisipi, ¿cuál es el peso bruto máximo (sin ninguna tolerancia) para un vehículo o combinación que opera sin un permiso especial?","options":["73,280 libras","76,000 libras","80,000 libras","88,000 libras"],"explanation":"El peso bruto vehicular máximo sin permiso es de 80,000 libras (puede aplicar una tolerancia del 2% adicional). Fuente: Miss. Code Ann. Sec. 63-5-33; Leyes de Peso Máximo de Misisipi de MDOT."},"3":{"q":"¿Cuál es el peso bruto máximo que Misisipi permite sobre un eje sencillo?","options":["24,000 libras","22,400 libras","18,000 libras","20,000 libras"],"explanation":"El peso bruto sobre cualquier eje sencillo no puede exceder las 20,000 libras (sin contar la tolerancia legal). Fuente: Miss. Code Ann. Sec. 63-5-27 (Cargas de rueda y eje); Leyes de Peso Máximo de MDOT."},"4":{"q":"¿Cuál es el peso bruto máximo que Misisipi permite sobre un eje en tándem?","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"El peso bruto sobre cualquier eje en tándem no puede exceder las 34,000 libras (sin contar la tolerancia legal). Fuente: Miss. Code Ann. Sec. 63-5-27; Leyes de Peso Máximo de MDOT."},"5":{"q":"Según la ley de Misisipi, ¿cómo se define un 'eje sencillo' para efectos de peso?","options":["Cualquier par de ejes consecutivos separados por más de 40 pulgadas","Dos o más ejes separados exactamente 96 pulgadas","Un solo conjunto de rueda y llanta a cada lado del vehículo","Dos o más ruedas en un mismo plano transversal, o dentro de planos paralelos separados 40 pulgadas"],"explanation":"Un eje sencillo es un conjunto de dos o más ruedas cuyos centros están en un mismo plano vertical transversal, o que caen entre dos planos transversales paralelos separados 40 pulgadas, a lo ancho de todo el vehículo. Fuente: Miss. Code Ann. Sec. 63-5-27; Leyes de Peso Máximo de MDOT."},"6":{"q":"¿Cómo define la ley de Misisipi un 'eje en tándem' para efectos de peso?","options":["Dos o más ejes consecutivos con centros separados por más de 40 pulgadas pero no más de 96 pulgadas","Dos ejes con centros separados exactamente 40 pulgadas","Cualquier grupo de ejes que abarque más de 96 pulgadas","Dos ejes donde uno es eje de tracción y otro es eje de dirección"],"explanation":"Un eje en tándem es cualquier par o más de ejes consecutivos cuyos centros están separados por más de 40 pulgadas pero no más de 96 pulgadas, y ningún eje del grupo puede exceder el límite del eje sencillo. Fuente: Miss. Code Ann. Sec. 63-5-27; Leyes de Peso Máximo de MDOT."},"7":{"q":"En las carreteras de Misisipi, ¿cuál es la longitud máxima de un camión sencillo (recto)?","options":["40 pies","45 pies","48 pies","53 pies"],"explanation":"Ningún vehículo sencillo (camión recto) puede exceder una longitud total de 40 pies en Misisipi. Fuente: Miss. Code Ann. Sec. 63-5-19 (Limitaciones de longitud de vehículos)."},"8":{"q":"¿Cuál es la longitud máxima de un semirremolque que opera en una combinación de tractocamión/semirremolque en Misisipi?","options":["48 pies","53 pies","57 pies","60 pies"],"explanation":"Un semirremolque que opera en una combinación de tractocamión/semirremolque no puede exceder los 53 pies en Misisipi. Fuente: Miss. Code Ann. Sec. 63-5-19 (Limitaciones de longitud de vehículos)."},"9":{"q":"Para determinar el peso máximo sobre cualquier grupo de dos o más ejes consecutivos, ¿qué estándar aplica Misisipi?","options":["Un tope fijo de 80,000 libras sin importar el espaciamiento","La Fórmula Federal de Puentes (el peso ligado al espaciamiento de los ejes)","Únicamente la regla de 550 libras por pulgada de ancho de llanta","El calendario de tolerancias del permiso de cosecha"],"explanation":"Misisipi usa la Fórmula Federal de Puentes, por lo que el peso permitido sobre un grupo de ejes depende de la distancia entre los ejes extremos del grupo. Fuente: tablas de peso de Miss. Code Ann. Sec. 63-5-29/63-5-33; Leyes de Peso Máximo de MDOT."},"10":{"q":"El peso bruto máximo de 80,000 libras de Misisipi puede excederse mediante qué tolerancia legal para un vehículo que opera SIN un permiso de cosecha?","options":["10%","5%","1%","2%"],"explanation":"El peso bruto vehicular máximo no puede exceder las 80,000 libras más una tolerancia no mayor al 2%. Fuente: Miss. Code Ann. Sec. 63-5-33."},"11":{"q":"¿Qué tolerancia de peso permite Misisipi a un vehículo que opera CON un permiso de cosecha, por encima de su peso bruto, en tándem o de eje autorizado?","options":["2%","5%","10%","15%"],"explanation":"A un vehículo con permiso de cosecha se le permite una tolerancia que no exceda el 10% por encima de su peso bruto, en tándem o de eje autorizado (sujeto al tope de 88,000 libras). Fuente: Miss. Code Ann. Sec. 63-5-33."},"12":{"q":"¿Cuál agencia de Misisipi emite los permisos de sobredimensión/sobrepeso (sobredimensionales)?","options":["El Departamento de Transporte de Misisipi, División de Permisos de la Oficina de Cumplimiento","El Departamento de Seguridad Pública de Misisipi, Servicios al Conductor","La Comisión de Impuestos del Estado de Misisipi","El alguacil del condado de origen"],"explanation":"Los permisos sobredimensionales son emitidos por la División de Permisos de la Oficina de Cumplimiento de MDOT, bajo la autoridad de la Comisión de Transporte de Misisipi. Fuente: Reglas de Permisos Sobredimensionales de MDOT (Sub-Part 6601, Chapter 03001); Miss. Code Ann. Sec. 65-1-8."},"13":{"q":"En Misisipi, un permiso sobredimensional de Viaje Único autoriza el movimiento por un período que no exceda cuánto tiempo?","options":["24 horas","Tres días consecutivos","Siete días consecutivos","Treinta días"],"explanation":"Un Permiso de Viaje Único autoriza el movimiento de un vehículo/carga específico por un período que no exceda tres (3) días consecutivos. Fuente: Reglas de Permisos Sobredimensionales de MDOT, Sec. 213 (Definiciones)."},"14":{"q":"Por lo general, se requiere que una carga no divisible obtenga un permiso de sobredimensión de Misisipi una vez que su ancho excede qué dimensión?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","10 pies 0 pulgadas","12 pies 0 pulgadas"],"explanation":"Se requiere un permiso para mover una carga que exceda el límite legal de ancho de 8 pies 6 pulgadas (102 pulgadas). Fuente: Miss. Code Ann. Sec. 63-5-13; reglas de permisos de la Oficina de Cumplimiento de MDOT."},"15":{"q":"Bajo las reglas de permisos sobredimensionales de Misisipi, ¿a qué ancho de carga entran en vigor los requisitos más estrictos de 'horas de luz diurna' y de escolta?","options":["Más de 12 pies de ancho","Más de 10 pies de ancho","Más de 14 pies de ancho","Más de 16 pies de ancho"],"explanation":"Para cargas de más de 12 pies de ancho, las 'horas de luz diurna' se restringen a 30 minutos después del amanecer hasta 30 minutos antes del atardecer y aplican requisitos adicionales de escolta. Fuente: Reglas de Permisos Sobredimensionales de MDOT, Sec. 200."},"16":{"q":"Misisipi limita los pesos de ejes sencillos y en tándem de modo que el peso bruto no exceda cuántas libras por pulgada de ancho de llanta (sujeto a los máximos de eje)?","options":["650 libras por pulgada","600 libras por pulgada","500 libras por pulgada","550 libras por pulgada"],"explanation":"El peso bruto de un eje sencillo o en tándem no puede exceder las 550 libras por pulgada de ancho de llanta (con una tolerancia de hasta 500 libras), sin exceder nunca los máximos de eje de 20,000/34,000 libras. Fuente: Miss. Code Ann. Sec. 63-5-27; Leyes de Peso Máximo de MDOT."},"17":{"q":"En las carreteras estatales de Misisipi (excluyendo el sistema interestatal), un vehículo registrado que mide más de 29 pies entre sus ejes extremos es tratado, para efectos de peso de la fórmula de puentes, como si ese grupo de ejes fuera cuánto más largo?","options":["6 pies más largo","12 pies más largo","20 pies más largo","29 pies más largo"],"explanation":"Bajo la disposición exclusiva para carreteras estatales de la Sec. 63-5-34, se considera que dicho vehículo tiene su grupo de ejes extremos espaciado 12 pies más largo que su medida real (esto no aplica en el sistema interestatal federal). Fuente: Miss. Code Ann. Sec. 63-5-34; Leyes de Peso Máximo de MDOT."},"18":{"q":"Para que dos conjuntos consecutivos de ejes en tándem lleven cada uno 34,000 libras (sin exceder las 80,000 libras de peso bruto) en Misisipi, la distancia entre el primero y el último eje de los conjuntos debe ser de al menos cuánto?","options":["30 pies","34 pies","36 pies","40 pies"],"explanation":"Dos conjuntos consecutivos de ejes en tándem pueden llevar cada uno 34,000 libras siempre que la distancia total entre el primero y el último eje sea de 36 pies o más, con un peso bruto total que no exceda las 80,000 libras salvo lo permitido por la Sec. 63-5-33. Fuente: Leyes de Peso Máximo de MDOT (nota de la Tabla III); Miss. Code Ann. Sec. 63-5-33."},"19":{"q":"En Misisipi, ¿cuál es el umbral mínimo de calificación de peso bruto vehicular (GVWR) que coloca a un solo vehículo comercial en la categoría de Clase A o Clase B?","options":["26,001 libras o más","10,001 libras o más","18,001 libras o más","33,001 libras o más"],"explanation":"Misisipi define la Clase B como cualquier vehículo sencillo con un GVWR de 26,001 libras o más, y la Clase A como una combinación de vehículos con un GVWR de 26,001 libras o más (que remolca una unidad de más de 10,000 lbs). Fuente: Mississippi DPS Driver Service Bureau, página de Clases A-D del CDL; Manual CDL de Misisipi."},"20":{"q":"¿Cuál clase de CDL de Misisipi se requiere para operar cualquier combinación de vehículos con un GVWR de 26,001 libras o más, donde el vehículo remolcado tiene un GVWR superior a 10,000 libras?","options":["Clase B","Clase A","Clase C","Clase D"],"explanation":"La Clase A de Misisipi cubre vehículos en combinación de 26,001 lbs o más de GVWR que remolcan una unidad con un GVWR superior a 10,000 lbs. Fuente: Mississippi DPS Driver Service Bureau, Clases A-D del CDL; Manual CDL de Misisipi."},"21":{"q":"Un conductor de Misisipi opera un camión recto sencillo con calificación de 30,000 libras de GVWR que no remolca nada. ¿Cuál clase de CDL requiere esto?","options":["Clase A","Clase C","Clase B","No se requiere CDL"],"explanation":"Un vehículo sencillo de 26,001 lbs o más de GVWR (que no remolca una unidad de más de 10,000 lbs) es un vehículo de Clase B en Misisipi. Fuente: Mississippi DPS Driver Service Bureau, Clases A-D del CDL; Manual CDL de Misisipi."},"22":{"q":"Bajo las reglas de Misisipi, un vehículo que no cumple con los umbrales de peso de Clase A o B aún requiere un CDL de Clase C si está diseñado para transportar cuántas personas (incluyendo al conductor)?","options":["8 o más","11 o más","24 o más","16 o más"],"explanation":"La Clase C de Misisipi aplica a un vehículo por debajo de los umbrales de peso de Clase A/B que está diseñado para transportar 16 o más pasajeros incluyendo al conductor, o que lleva materiales peligrosos con rótulo. Fuente: Mississippi DPS Driver Service Bureau, Clases A-D del CDL; Manual CDL de Misisipi."},"23":{"q":"Además de la regla de 16 pasajeros, ¿qué otra condición hace que un vehículo más pequeño requiera un CDL de Clase C en Misisipi?","options":["Está registrado para uso comercial","Transporta materiales peligrosos en cantidades que requieren rótulo","Cruza una línea estatal","Es propiedad de un transportista de carga"],"explanation":"Un vehículo por debajo de los límites de peso de Clase A/B requiere un CDL de Clase C si se usa para transportar materiales peligrosos en una cantidad que requiere rótulos. Fuente: Mississippi DPS Driver Service Bureau, Clases A-D del CDL; Manual CDL de Misisipi."},"24":{"q":"¿Cuál endoso de CDL se requiere en Misisipi para transportar materiales peligrosos en cantidades con rótulo?","options":["Endoso N","Endoso T","Endoso H","Solo el endoso X"],"explanation":"El endoso H (HazMat) se requiere para transportar materiales peligrosos con rótulo. El endoso X es un endoso combinado de HazMat más Tanque y no es requerido por los conductores que solo necesitan HazMat. Fuente: Mississippi DPS Driver Service Bureau, lista de endosos del CDL; FMCSA 49 CFR 383.93."},"25":{"q":"En Misisipi, ¿cuál endoso autoriza a un titular de CDL a conducir un vehículo cisterna (tanque)?","options":["Endoso T","Endoso P","Endoso S","Endoso N"],"explanation":"El endoso N es el endoso de vehículo cisterna (tanque). El T es dobles/triples, el P es de pasajeros y el S es de autobús escolar. Fuente: Mississippi DPS Driver Service Bureau, lista de endosos del CDL; FMCSA 49 CFR 383.93."},"26":{"q":"¿Cuál endoso de CDL de Misisipi se necesita para arrastrar remolques dobles o triples?","options":["Endoso T","Endoso N","Endoso H","Endoso P"],"explanation":"El endoso T (dobles/triples) se requiere para remolcar remolques dobles o triples y se obtiene únicamente mediante un examen de conocimientos. Fuente: Mississippi DPS Driver Service Bureau, lista de endosos del CDL; FMCSA 49 CFR 383.93."},"27":{"q":"¿Qué representa el endoso X en un CDL de Misisipi?","options":["Un endoso vencido pendiente de renovación","Una exención del certificado médico","Una combinación de los endosos de HazMat (H) y Tanque (N)","Un endoso de reciprocidad de otro estado"],"explanation":"Misisipi lista el X como el endoso combinado de HazMat y Tanque, emitido cuando un conductor califica para ambos H y N. Fuente: Mississippi DPS Driver Service Bureau, lista de endosos del CDL; FMCSA 49 CFR 383.93."},"28":{"q":"Para conducir un autobús escolar en Misisipi, ¿qué combinación de endosos debe obtener un titular de CDL?","options":["Solo el endoso S (autobús escolar)","Solo el endoso P (pasajeros)","El endoso T (dobles/triples)","Tanto el endoso P (pasajeros) como el S (autobús escolar)"],"explanation":"Los conductores de autobús escolar de Misisipi deben tener tanto el endoso de Pasajeros (P) como el de Autobús Escolar (S); el endoso S se basa en el endoso P. Fuente: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.93."},"29":{"q":"¿Cuál es la edad mínima para obtener un CDL de Misisipi válido solo para conducción intraestatal (dentro del estado)?","options":["18 años","21 años","19 años","16 años"],"explanation":"Misisipi permite un CDL a los 18 años solo para comercio intraestatal; la conducción interestatal requiere tener 21 años. Fuente: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"30":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo motorizado comercial a través de líneas estatales (interestatal) con un CDL de Misisipi?","options":["18 años","21 años","19 años","25 años"],"explanation":"Los conductores deben tener al menos 21 años para operar en comercio interestatal y para tener endosos de HazMat o pasajeros para trabajo interestatal. Fuente: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 391.11."},"31":{"q":"En Misisipi, ¿qué edad mínima se requiere antes de que un conductor pueda recibir un endoso de HazMat (H) o de pasajeros (P) para operación interestatal?","options":["18 años","19 años","23 años","21 años"],"explanation":"Misisipi exige que un conductor tenga al menos 21 años para que se le emitan endosos de HazMat o de pasajeros para comercio interestatal, en consonancia con las reglas federales. Fuente: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"32":{"q":"Después de obtener un Permiso de Aprendiz Comercial (CLP) en Misisipi, ¿cuánto tiempo debe tenerlo un conductor antes de que se le permita tomar el examen de habilidades (de manejo) del CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"La regla federal adoptada por Misisipi exige que el CLP se tenga por un mínimo de 14 días antes de que el solicitante pueda tomar el examen de habilidades del CDL. Fuente: Manual CDL de Misisipi; FMCSA 49 CFR 383.25."},"33":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Misisipi antes de que deba renovarse u obtenerse el CDL?","options":["30 días","180 días (6 meses)","1 año","90 días"],"explanation":"Un CLP de Misisipi es válido por 180 días (seis meses); los estados pueden permitir una renovación por 180 días adicionales. Fuente: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.25."},"34":{"q":"¿Cuál endoso NO está permitido colocarse en un Permiso de Aprendiz Comercial (CLP) de Misisipi?","options":["El endoso N (tanque), cuando el tanque está vacío","El endoso P (pasajeros)","El endoso H (HazMat)","El endoso S (autobús escolar)"],"explanation":"Las reglas federales adoptadas por Misisipi prohíben el endoso de HazMat (H) en un CLP; solo los endosos P, S y N pueden aparecer en un CLP, con restricciones. Fuente: Manual CDL de Misisipi; FMCSA 49 CFR 383.25."},"35":{"q":"¿Dónde completa ahora un solicitante de Misisipi la toma de huellas dactilares y la verificación de antecedentes de la TSA requeridas para un endoso de HazMat (H)?","options":["A través del proveedor de Servicios de Inscripción Universal de la TSA (IdentoGO), no en la estación local de CDL del DPS","En cualquier estación local de CDL del DPS de Misisipi","En la oficina del Registro Nacional de la FMCSA","En la oficina del secretario del tribunal de circuito del condado"],"explanation":"Misisipi trasladó la toma de huellas e inscripción de HazMat al programa de Servicios de Inscripción Universal de la TSA (IdentoGO / universalenroll.dhs.gov); ya no se realiza en las estaciones locales de CDL del DPS. Fuente: Mississippi DPS Driver Service Bureau, Programa de Inscripción de HazMat del CDL."},"36":{"q":"Desde el 7 de febrero de 2022, los solicitantes de CDL por primera vez en Misisipi deben completar la Capacitación para Conductores Principiantes (ELDT) proporcionada por quién?","options":["Cualquier colegio comunitario de Misisipi","El propio DPS de Misisipi","Un instructor interno de un empleador de cualquier tipo","Un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA"],"explanation":"A partir del 7 de febrero de 2022, los solicitantes de CDL por primera vez (y ciertos ascensos/endosos) deben completar el ELDT con un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes del examen del CDL. Fuente: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR Part 380."},"37":{"q":"Cuando un solicitante de CDL de Misisipi autocertifica su tipo de conducción, ¿cuál categoría indica que opera en comercio interestatal y debe cumplir con los requisitos federales del certificado médico del DOT?","options":["Interestatal Exento (EI)","Interestatal No Exento (NI)","Intraestatal No Exento (NA)","Intraestatal Exento (EA)"],"explanation":"Misisipi usa las cuatro categorías federales de autocertificación. Los conductores Interestatales No Exentos (NI) operan a través de líneas estatales y deben tener un certificado médico válido de examinador del DOT. Fuente: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.71."},"38":{"q":"¿Cuál conjunto de documentos debe presentar un solicitante de CDL de Misisipi para satisfacer los requisitos de identidad/presencia legal, Seguro Social y residencia?","options":["Un diploma de bachillerato, una credencial de votante y una factura de servicios","Solo un pasaporte, sin necesidad de comprobante de residencia","Un acta de nacimiento original (o comprobante de presencia legal), documentación del número de Seguro Social y dos comprobantes de residencia en Misisipi","Un título de vehículo, una tarjeta de seguro y una licencia de pesca"],"explanation":"Misisipi exige comprobante de identidad/presencia legal (por ejemplo, acta de nacimiento original), documentación del número de Seguro Social y dos comprobantes de residencia, además de una tarjeta médica válida, para solicitar un CDL. Fuente: Mississippi DPS Driver Service Bureau, requisitos para solicitantes de CDL."},"39":{"q":"En Misisipi, ¿cuál es la concentración máxima de alcohol en sangre/aliento (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial?","options":["0.02","0.04","0.08","0.10"],"explanation":"Misisipi sigue el estándar federal para CMV: es ilegal operar un vehículo motorizado comercial con una concentración de alcohol de 0.04% o más. Una lectura de 0.04% o más es motivo de una primera descalificación por delito mayor. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51; Manual CDL de Misisipi (DPS)."},"40":{"q":"Un titular de CDL de Misisipi es condenado por una primera infracción de operar un CMV con un BAC de 0.04% mientras NO transporta materiales peligrosos con rótulo. ¿Por cuánto tiempo queda descalificado el conductor para operar un CMV?","options":["6 meses","1 año","3 años","De por vida"],"explanation":"Un primer delito mayor (incluyendo conducir un CMV con un BAC de 0.04% o más) resulta en una descalificación mínima del CDL de 1 año en Misisipi. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Manual CDL de Misisipi."},"41":{"q":"Si un titular de CDL de Misisipi comete un primer delito mayor (como conducir en estado de ebriedad en un CMV) MIENTRAS transporta materiales peligrosos con rótulo, el período de descalificación aumenta a:","options":["1 año","2 años","3 años","5 años"],"explanation":"Bajo las reglas de Misisipi y federales, un primer delito mayor cometido mientras se transportan materiales peligrosos con rótulo conlleva una descalificación de 3 años en lugar del estándar de 1 año. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Manual CDL de Misisipi."},"42":{"q":"¿Cuál es el período de descalificación para un titular de CDL de Misisipi condenado por un SEGUNDO delito mayor (por ejemplo, una segunda conducción en estado de ebriedad en un CMV)?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Una segunda condena por cualquier delito mayor resulta en una descalificación del CDL de por vida en Misisipi. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(3); Manual CDL de Misisipi."},"43":{"q":"En Misisipi, ¿qué sucede con el privilegio de conducción comercial de un titular de CDL si se niega a someterse a una prueba química de aliento o sangre cuando se le solicita legalmente?","options":["Se emite una advertencia sin descalificación","Descalificación por 30 días","Descalificación por 1 año","Descalificación por 90 días"],"explanation":"La negativa a la prueba química se trata como un delito mayor; bajo la ley de consentimiento implícito de Misisipi, un CDL se descalifica por al menos 1 año por una primera negativa. Fuente: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51(b); Manual CDL de Misisipi."},"44":{"q":"Bajo la ley de consentimiento implícito de Misisipi, al operar cualquier vehículo motorizado en una carretera de Misisipi se considera que un conductor ha:","options":["Renunciado al derecho a un abogado","Otorgado su consentimiento a una prueba química de aliento, sangre u orina","Aceptado inspecciones aleatorias en la carretera","Aceptado puntos automáticos en la licencia"],"explanation":"El estatuto de consentimiento implícito de Misisipi establece que cualquier persona que conduce en las vías del estado se considera que ha otorgado su consentimiento a una prueba química para determinar la concentración de alcohol o drogas. Fuente: Miss. Code Ann. 63-11-5, 63-11-30; Manual CDL de Misisipi (DPS)."},"45":{"q":"¿Cuántas infracciones de tránsito graves (en incidentes separados) dentro de un período de 3 años activan una descalificación del CDL de 60 días en Misisipi?","options":["1","2","3","4"],"explanation":"Dos infracciones de tránsito graves dentro de un período de 3 años (que surgen de incidentes separados) resultan en una descalificación de 60 días. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Manual CDL de Misisipi."},"46":{"q":"En Misisipi, la condena por TRES infracciones de tránsito graves dentro de un período de 3 años resulta en una descalificación del CDL de:","options":["60 días","90 días","120 días","1 año"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años (incidentes separados) resultan en una descalificación de 120 días, que se cumple de manera consecutiva después de cualquier descalificación previa de 60 días. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Manual CDL de Misisipi."},"47":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE para un titular de CDL de Misisipi?","options":["Operar un CMV con un BAC de 0.04% o más","Exceder el límite de velocidad publicado por 15 mph o más","Negarse a una prueba química","Abandonar la escena de un accidente"],"explanation":"Exceder el límite de velocidad por 15 mph o más es una infracción de tránsito grave. Las otras tres opciones listadas son delitos mayores que conllevan una descalificación de 1 año (o más), no infracciones graves. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Manual CDL de Misisipi."},"48":{"q":"¿Cuál de las siguientes NO se cuenta como una infracción de tránsito grave para un titular de CDL de Misisipi?","options":["Seguir al vehículo de adelante demasiado cerca","Conducción imprudente","Realizar cambios de carril erráticos o indebidos","Estacionar indebidamente un CMV desatendido durante la noche"],"explanation":"Seguir demasiado cerca, la conducción imprudente y los cambios de carril erráticos/indebidos son todas infracciones de tránsito graves. El estacionamiento rutinario de un vehículo desatendido no está en la lista de infracciones graves. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Manual CDL de Misisipi."},"49":{"q":"Un conductor de CDL de Misisipi que envía mensajes de texto o usa un teléfono móvil de mano mientras conduce un CMV comete qué tipo de infracción?","options":["Una infracción no reportable","Una infracción de tránsito grave","Un delito mayor","Una infracción de fuera de servicio"],"explanation":"Enviar mensajes de texto o usar un teléfono de mano mientras se conduce un CMV es una infracción de tránsito grave; dos o tres de estas infracciones graves dentro de 3 años pueden conllevar una descalificación de 60 o 120 días. Fuente: 49 CFR 383.51(c), 392.80/392.82; Miss. Code Ann. 63-1-216; Manual CDL de Misisipi."},"50":{"q":"Una PRIMERA violación de una orden de fuera de servicio por parte de un conductor de CDL de Misisipi que transporta materiales peligrosos con rótulo o 16 o más pasajeros conlleva una descalificación de:","options":["No menos de 180 días, no más de 2 años","Exactamente 180 días","No menos de 60 días, no más de 1 año","De por vida"],"explanation":"Cuando una primera violación de fuera de servicio ocurre mientras se transportan materiales peligrosos con rótulo o se llevan 16 o más pasajeros, la descalificación es de no menos de 180 días y no más de 2 años. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(e); Manual CDL de Misisipi."},"51":{"q":"Un conductor de CDL de Misisipi condenado por una PRIMERA violación de un cruce a nivel entre ferrocarril y carretera mientras opera un CMV es descalificado por:","options":["No menos de 30 días","No menos de 60 días","No menos de 120 días","1 año"],"explanation":"Una primera violación de un cruce a nivel entre ferrocarril y carretera resulta en una descalificación de no menos de 60 días. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Manual CDL de Misisipi."},"52":{"q":"¿Cuál es el período de descalificación para la TERCERA violación de un cruce a nivel entre ferrocarril y carretera de un conductor de CDL de Misisipi dentro de un período de 3 años?","options":["120 días","6 meses","1 año","De por vida"],"explanation":"Una tercera (o subsiguiente) violación de un cruce a nivel de ferrocarril dentro de 3 años resulta en una descalificación de no menos de 1 año. La progresión es 60 días (primera), 120 días (segunda), 1 año (tercera). Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Manual CDL de Misisipi."},"53":{"q":"En Misisipi, un titular de CDL que usa un vehículo motorizado comercial para cometer un delito grave que involucra la fabricación, distribución o dispensación de una sustancia controlada es descalificado por:","options":["1 año","3 años","10 años","De por vida, sin reinstalación"],"explanation":"Usar un CMV en la comisión de un delito grave que involucra sustancias controladas resulta en una descalificación de por vida que, a diferencia de algunas descalificaciones de por vida, no puede reducirse. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Manual CDL de Misisipi."},"54":{"q":"¿Cuál de las siguientes es un delito MAYOR (descalificación mínima de 1 año) en lugar de una infracción de tránsito grave en Misisipi?","options":["Seguir demasiado cerca","Abandonar la escena de un accidente que involucra un CMV","Exceder el límite de velocidad por 15 mph","Cambio de carril indebido"],"explanation":"Abandonar la escena de un accidente que involucra un CMV es un delito mayor que conlleva una descalificación mínima de 1 año. Las otras opciones son infracciones de tránsito graves. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Manual CDL de Misisipi."},"55":{"q":"En Misisipi, si una persona se niega a una prueba química mientras tiene un CDL, la descalificación del privilegio comercial aplica:","options":["Solo si el conductor estaba operando un CMV en ese momento","Solo si el BAC luego resulta ser mayor a 0.04%","Incluso si la negativa ocurrió mientras conducía un vehículo personal (no comercial)","Solo después de una segunda negativa"],"explanation":"Un titular de CDL es descalificado por negarse a una prueba química incluso cuando la negativa ocurre mientras opera un vehículo no comercial; las condenas y negativas en un vehículo personal aún afectan el CDL. Fuente: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51; Manual CDL de Misisipi."},"56":{"q":"Un conductor de CDL de Misisipi recibe una infracción de tránsito grave en su vehículo PERSONAL que resulta en la suspensión de la licencia. ¿Cómo afecta esto al CDL?","options":["No tiene efecto porque no fue un CMV","Aún cuenta para la descalificación del CDL","Solo cuenta si el conductor estaba de servicio","Solo afecta el endoso de HazMat"],"explanation":"Las condenas y acciones sobre la licencia en un vehículo personal cuentan en contra del CDL; una suspensión/revocación/cancelación del privilegio de conducción por ciertas infracciones graves conlleva la descalificación del CDL. Fuente: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Manual CDL de Misisipi."},"57":{"q":"Según la ley \"Move Over\" (cédele el paso) de Mississippi, cuando te acercas a un vehículo de emergencia o de remolque detenido con luces intermitentes encendidas en una autopista de cuatro carriles con dos carriles en tu dirección, ¿qué debes hacer?","options":["Despejar el carril contiguo al vehículo detenido si es seguro hacerlo","Detenerte por completo hasta que el vehículo detenido se retire","Tocar la bocina de forma continua mientras pasas junto al vehículo","Mantener tu velocidad y permanecer en tu carril actual"],"explanation":"El Miss. Code 63-3-809 exige que los conductores en una vía con al menos cuatro carriles (dos o más en la misma dirección) cambien a un carril no contiguo al vehículo de emergencia, recuperación o servicio público detenido cuando sea seguro. Fuente: Mississippi Code 63-3-809."},"58":{"q":"Según la ley \"Move Over\" (cédele el paso) de Mississippi, si no puedes cambiar de carril con seguridad para alejarte de un vehículo de emergencia detenido con luces intermitentes encendidas, ¿qué se te exige hacer en su lugar?","options":["Continuar al límite de velocidad indicado sin cambiar nada","Detenerte en tu carril y esperar a que un oficial te indique pasar","Reducir la velocidad, avanzar con precaución y estar preparado para detenerte","Activar las luces de emergencia y pasar a velocidad normal"],"explanation":"El Miss. Code 63-3-809 dispone que el conductor que no puede cambiar de carril con seguridad debe reducir la velocidad, avanzar con la debida precaución y estar preparado para detenerse. Fuente: Mississippi Code 63-3-809."},"59":{"q":"En Mississippi, una infracción de la ley \"Move Over\" (63-3-809) que NO causa daños ni lesiones es sancionable con una multa de hasta cuánto?","options":["Hasta $100","Hasta $250","Hasta $500","Hasta $1,000"],"explanation":"El Miss. Code 63-3-809 establece una multa de hasta $250 por una infracción, que aumenta hasta $1,000 si la infracción causa daños materiales al vehículo detenido o lesiones corporales a sus ocupantes. Fuente: Mississippi Code 63-3-809."},"60":{"q":"Además de los vehículos de emergencia autorizados, ¿cuál de los siguientes vehículos detenidos con luces de advertencia intermitentes también protege la ley \"Move Over\" de Mississippi (63-3-809)?","options":["Solo los vehículos identificados de las fuerzas del orden","Solo las ambulancias y los vehículos de bomberos","Vehículos de recuperación (remolque) y vehículos de servicios públicos","Solo los vehículos propiedad del gobierno estatal"],"explanation":"El Miss. Code 63-3-809 extiende el deber de cambiar de carril o reducir la velocidad a los vehículos de emergencia autorizados detenidos, así como a los vehículos de recuperación (remolque) y de servicios públicos que usan luces intermitentes autorizadas. Fuente: Mississippi Code 63-3-809."},"61":{"q":"En la mayoría de las autopistas interestatales de Mississippi, la Comisión de Transporte de Mississippi puede fijar el límite máximo de velocidad en no más de qué valor?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"El Miss. Code 63-3-501 limita la velocidad máxima que la Comisión de Transporte puede fijar en el Sistema de Autopistas Interestatales y en las autopistas de acceso controlado de cuatro o más carriles a 70 mph. Fuente: Mississippi Code 63-3-501."},"62":{"q":"Según el Mississippi Code 63-3-501, donde se establece un límite de 70 mph en una autopista interestatal o U.S. de cuatro carriles, ¿qué velocidad MÍNIMA se aplica a un vehículo que tiene una restricción de velocidad máxima de 70 mph?","options":["30 mph","40 mph","45 mph","50 mph"],"explanation":"El Miss. Code 63-3-501 establece una velocidad mínima de 40 mph para los vehículos que tienen una restricción de velocidad máxima de 70 mph en dichas autopistas. Fuente: Mississippi Code 63-3-501."},"63":{"q":"Según la ley de Mississippi, cuando detienes un autobús que transporta pasajeros antes de cruzar un paso a nivel ferroviario, debes detenerte a qué distancia del riel más cercano?","options":["A no más de 50 pies pero no menos de 15 pies","A no más de 25 pies pero no menos de 5 pies","A no más de 75 pies pero no menos de 25 pies","A no más de 100 pies pero no menos de 50 pies"],"explanation":"El Miss. Code 63-3-1011 exige que los autobuses, los vehículos que transportan pasajeros por contrato, los autobuses escolares y los vehículos que transportan explosivos o líquidos inflamables se detengan a no más de 50 pies pero no menos de 15 pies del riel más cercano. Fuente: Mississippi Code 63-3-1011."},"64":{"q":"Según el Manual de CDL de Mississippi, ¿qué vehículos comerciales están siempre obligados a detenerse en los pasos a nivel ferroviarios?","options":["Todos los vehículos comerciales que pesan más de 10,000 libras","Los autobuses que transportan pasajeros y los vehículos que transportan materiales peligrosos con placa","Solo las combinaciones de triple remolque","Cualquier vehículo que remolque un remolque de cualquier tipo"],"explanation":"El Manual de CDL de Mississippi (que refleja el 49 CFR 392.10 y el Miss. Code 63-3-1011) exige que los autobuses que transportan pasajeros y los vehículos de materiales peligrosos con placa se detengan antes de cruzar las vías, y luego miren y escuchen. Fuente: Manual de CDL de Mississippi / Miss. Code 63-3-1011."},"65":{"q":"Cuando se requiere detenerse en un cruce ferroviario en Mississippi, después de detenerse en la zona de 15 a 50 pies, ¿cómo debe cruzar las vías el conductor de un autobús o de un vehículo con placa?","options":["Rápidamente, subiendo de marcha para despejar el cruce con rapidez","En una marcha que permita completar el cruce sin cambiar de marcha","En punto muerto, deslizándose a través con el embrague pisado","Solo después de tocar la bocina tres veces"],"explanation":"El Manual de CDL de Mississippi instruye a los conductores a cruzar en una marcha que permita completar el cruce sin cambiar de marcha, y a no cambiar de marcha mientras estén sobre las vías. Fuente: Manual de CDL de Mississippi (cruces ferroviarios)."},"66":{"q":"Según la ley de autobuses escolares de Mississippi (Ley de Nathan, 63-3-615), ¿a qué distancia puede detenerse un vehículo que viene en sentido contrario o que adelanta a un autobús escolar que está cargando o descargando niños con sus luces rojas intermitentes encendidas y el brazo de pare extendido?","options":["A no menos de 10 pies del autobús","A no menos de 25 pies del autobús","A no menos de 50 pies del autobús","A no menos de 5 pies del autobús"],"explanation":"El Miss. Code 63-3-615 exige que los conductores que vienen en sentido contrario o que adelantan se detengan a no menos de 10 pies de un autobús escolar que está detenido para recoger o dejar niños. Fuente: Mississippi Code 63-3-615."},"67":{"q":"En una autopista de Mississippi, ¿bajo qué condición un conductor NO tiene que detenerse ante un autobús escolar que está detenido para cargar o descargar niños?","options":["Siempre que el conductor viaje en la dirección opuesta en cualquier camino de dos carriles","Cuando el autobús está detenido en la calzada opuesta de una autopista dividida de cuatro o más carriles con al menos dos carriles en direcciones opuestas","Siempre que el tráfico sea denso y detenerse resulte inconveniente","Cuando el conductor está a más de 100 pies del autobús"],"explanation":"El Miss. Code 63-3-615 exime a un conductor en una autopista dividida de cuatro o más carriles (que permite al menos dos carriles de tráfico en direcciones opuestas) de detenerse ante un autobús detenido en la calzada opuesta. Fuente: Mississippi Code 63-3-615."},"68":{"q":"Según el Mississippi Code 63-3-615, la multa por primera infracción por adelantar ilegalmente a un autobús escolar detenido es de no menos de qué monto?","options":["No menos de $100","No menos de $200","No menos de $350","No menos de $1,000"],"explanation":"El Miss. Code 63-3-615 establece una multa por primera infracción de no menos de $350 ni más de $750 (y posible cárcel) por adelantar ilegalmente a un autobús escolar detenido. Fuente: Mississippi Code 63-3-615."},"69":{"q":"Según las reglas de uso de carriles de Mississippi, ¿por dónde debe conducirse un vehículo comercial que avanza más lento que la velocidad normal del tráfico en una autopista de varios carriles?","options":["Por el carril derecho o lo más cerca posible del borde derecho de la calzada","Por el carril central en todo momento","Por el carril izquierdo para mantenerse alejado del tráfico que se incorpora","Por el carril que tenga menos tráfico"],"explanation":"El Miss. Code 63-3-603 exige que un vehículo que avanza más lento que la velocidad normal del tráfico use el carril derecho o se mantenga lo más cerca posible del borde derecho, excepto al adelantar o al prepararse para girar a la izquierda. Fuente: Mississippi Code 63-3-603."},"70":{"q":"¿Qué dice el Mississippi Code 63-3-603 sobre conducir de forma continua por el carril más a la izquierda de una calzada de varios carriles?","options":["Está permitido para camiones pero prohibido para automóviles","Está prohibido siempre que obstaculice el flujo del resto del tráfico","Es obligatorio para todos los vehículos de más de 26,000 libras","Está permitido en cualquier momento siempre que señalices primero"],"explanation":"El Miss. Code 63-3-603 prohíbe conducir de forma continua por el carril más a la izquierda de una calzada de varios carriles siempre que al hacerlo se obstaculice el flujo del resto del tráfico. Fuente: Mississippi Code 63-3-603."},"71":{"q":"Según el Manual de CDL de Mississippi, cuando tu vehículo comercial está detenido en el acotamiento de una autopista de un solo sentido o dividida, ¿dónde colocas tus tres triángulos de advertencia?","options":["A 10, 100 y 200 pies en dirección al tráfico que se aproxima (todos hacia atrás)","A 25 pies adelante, junto al vehículo y 25 pies atrás","Uno junto al vehículo y dos lado a lado a 50 pies atrás","A 10, 100 y 200 pies tanto adelante como atrás del vehículo"],"explanation":"El Manual de CDL de Mississippi (según el 49 CFR 392.22) indica colocar los triángulos a 10, 100 y 200 pies en dirección al tráfico que se aproxima en una autopista de un solo sentido o dividida. Fuente: Manual de CDL de Mississippi / 49 CFR 392.22."},"72":{"q":"Según el Manual de CDL de Mississippi, en un camino no dividido de dos carriles que lleva tráfico en ambas direcciones, ¿dónde deben colocarse los dispositivos de advertencia para un vehículo comercial detenido?","options":["Los tres dentro de los 10 pies detrás del vehículo","Dentro de los 10 pies del vehículo, más 100 pies atrás y 100 pies adelante","Solo un dispositivo, 200 pies detrás del vehículo","A 50 pies y 500 pies detrás del vehículo"],"explanation":"El Manual de CDL de Mississippi (según el 49 CFR 392.22) exige un dispositivo dentro de los 10 pies del vehículo y dispositivos a unos 100 pies atrás y 100 pies adelante en un camino de dos carriles y doble sentido. Fuente: Manual de CDL de Mississippi / 49 CFR 392.22."},"73":{"q":"Según el Manual de CDL de Mississippi, después de que un vehículo comercial se detiene en una calzada o acotamiento, ¿dentro de cuánto tiempo debe el conductor colocar los dispositivos de advertencia de emergencia?","options":["Dentro de 5 segundos","Dentro de 10 minutos","Dentro de 30 minutos","Dentro de 1 hora"],"explanation":"El Manual de CDL de Mississippi (según el 49 CFR 392.22) exige que los dispositivos de advertencia se coloquen dentro de los 10 minutos de detenerse; las luces de emergencia se usan de inmediato y hasta que se coloquen los triángulos. Fuente: Manual de CDL de Mississippi / 49 CFR 392.22."},"74":{"q":"¿Qué ruta de Mississippi, que cruza el estado en diagonal, prohíbe que los camiones comerciales (los de más de una tonelada de capacidad nominal) la usen?","options":["La Interestatal 55","La U.S. Highway 49","El Natchez Trace Parkway","La Interestatal 20"],"explanation":"El Natchez Trace Parkway, una ruta escénica administrada por el gobierno federal, prohíbe los vehículos comerciales y los camiones de más de una tonelada de capacidad nominal. Fuente: 36 CFR 7.43 / National Park Service."},"75":{"q":"En Mississippi, ¿cuál es el ancho máximo legal de un vehículo permitido en las autopistas designadas antes de que se requiera un permiso de sobredimensión?","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","9 pies 0 pulgadas","10 pies 0 pulgadas"],"explanation":"El ancho máximo legal de Mississippi en las autopistas designadas es de 8 pies 6 pulgadas; las cargas más anchas que esto requieren un permiso de sobredimensión. Fuente: reglas de permisos de sobredimensión/sobrepeso del Mississippi DOT."},"76":{"q":"En Mississippi, ¿cuál es el peso bruto vehicular máximo legal en el sistema interestatal antes de que se requiera un permiso de sobrepeso?","options":["73,280 libras","80,000 libras","88,000 libras","100,000 libras"],"explanation":"Mississippi sigue el límite federal de 80,000 libras de peso bruto máximo legal en el sistema interestatal; excederlo requiere un permiso de sobrepeso del MDOT. Fuente: reglas de permisos de sobrepeso del Mississippi DOT."},"77":{"q":"¿Qué agencia de Mississippi emite las licencias de conducir comerciales y administra las pruebas de CDL en el estado?","options":["El Departamento de Seguridad Pública de Mississippi (DPS), a través de su Driver Service Bureau","El Departamento de Transporte de Mississippi (MDOT)","La oficina del Secretario del Tribunal de Circuito del condado donde reside el conductor","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"Las CDL de Mississippi son emitidas y las pruebas de CDL administradas por el Departamento de Seguridad Pública de Mississippi (DPS) a través de su Driver Service Bureau. El MDOT se encarga de las carreteras y los permisos, no de las licencias, y la FMCSA fija las normas federales pero no emite licencias estatales. Fuente: MS DPS Driver Service Bureau; Miss. Code Título 63, Capítulo 1."},"78":{"q":"¿Cuál es la calificación mínima para aprobar los exámenes de conocimientos (escritos) de la CDL de Mississippi?","options":["80%","70%","75%","90%"],"explanation":"Mississippi exige una calificación mínima del 80% en cada examen de conocimientos de CDL requerido, de acuerdo con la norma federal de pruebas de AAMVA. Fuente: MS DPS / Manual de CDL de Mississippi."},"79":{"q":"Antes de que un solicitante de CDL por primera vez en Mississippi pueda presentar las pruebas de conocimientos o de habilidades requeridas, ¿qué capacitación debe completar?","options":["Capacitación de conductor de nivel inicial (ELDT) de un proveedor de capacitación registrado ante la FMCSA","Un curso de manejo defensivo aprobado por el MDOT","Un curso de aula de 40 horas en un colegio comunitario","Un aprendizaje registrado con la Mississippi Trucking Association"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de CDL por primera vez deben completar la Capacitación de Conductor de Nivel Inicial (ELDT) de un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes de presentar las pruebas de habilidades o de conocimientos requeridas. Fuente: MS DPS Driver Service Bureau; regla ELDT de la FMCSA (49 CFR Parte 380)."},"80":{"q":"¿Por cuánto tiempo debe poseerse un Permiso de Aprendiz Comercial (CLP) de Mississippi antes de que el titular pueda presentar la prueba de habilidades de la CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 10 días","Al menos 60 días"],"explanation":"Mississippi sigue la regla federal que exige poseer un CLP durante un mínimo de 14 días antes de que el titular sea elegible para presentar la prueba de habilidades de la CDL. Fuente: MS DPS Driver Service Bureau; 49 CFR 383.25."},"81":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Mississippi?","options":["6 meses","1 año","30 días","90 días"],"explanation":"Un CLP de Mississippi es válido por 6 meses (180 días), de acuerdo con el período máximo federal de validez del CLP. Fuente: MS DPS Driver Service Bureau; 49 CFR 383.25."},"82":{"q":"La prueba de habilidades de la CDL de Mississippi consta de qué tres partes, realizadas en orden?","options":["Inspección previa al viaje del vehículo, control básico del vehículo y conducción en carretera","Prueba escrita de conocimientos, prueba de frenos de aire y conducción en carretera","Inspección previa al viaje, manejo de materiales peligrosos y conducción nocturna","Control básico del vehículo, acoplamiento/desacoplamiento y un examen escrito de endoso"],"explanation":"La prueba de habilidades de la CDL de Mississippi tiene tres partes: la inspección previa al viaje del vehículo, la prueba de habilidades de control básico del vehículo y la prueba de conducción en carretera. Las tres deben aprobarse. Fuente: MS DPS / Manual de CDL de Mississippi."},"83":{"q":"¿Cuál es la vigencia (período de validez) de una licencia de conducir comercial de Mississippi antes de que deba renovarse?","options":["5 años, con vencimiento el día del cumpleaños del titular","4 años, con vencimiento el día del cumpleaños del titular","8 años, con vencimiento el día del cumpleaños del titular","2 años, vinculada al certificado médico"],"explanation":"Una CDL de Mississippi se emite por un período de cinco años y vence a la medianoche del día del cumpleaños del titular. Fuente: Miss. Code Ann. Sec. 63-1-47 (y Sec. 63-1-211)."},"84":{"q":"¿Con cuánta anticipación a su fecha de vencimiento puede un titular de una CDL de Mississippi renovar la licencia?","options":["En cualquier momento dentro de los 6 meses anteriores al vencimiento","Solo dentro de los 30 días anteriores al vencimiento","En cualquier momento dentro de los 90 días anteriores al vencimiento","Solo en la fecha de vencimiento o después de ella"],"explanation":"Mississippi permite la renovación en cualquier momento dentro de los seis (6) meses anteriores al vencimiento de la licencia, previa solicitud y pago de la tarifa requerida, salvo que se requiera un nuevo examen. Fuente: Miss. Code Ann. Sec. 63-1-47."},"85":{"q":"Cuando un solicitante de CDL autocertifica su tipo de conducción ante el Mississippi DPS, ¿cuántas categorías de autocertificación hay disponibles para elegir?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Hay cuatro categorías de autocertificación: Interestatal No Exenta, Interestatal Exenta, Intraestatal No Exenta e Intraestatal Exenta. El solicitante debe elegir exactamente una. Fuente: Autocertificación del MS DPS Driver Service Bureau; 49 CFR 383.71(b)."},"86":{"q":"¿Qué categoría de autocertificación en Mississippi se aplica a un conductor que opera cruzando las fronteras estatales y está obligado a cumplir con todas las normas federales de calificación médica?","options":["Interestatal No Exenta (NI)","Interestatal Exenta (EI)","Intraestatal No Exenta (NA)","Intraestatal Exenta (EA)"],"explanation":"Los conductores Interestatales No Exentos (NI) operan en el comercio interestatal, deben cumplir con todos los requisitos médicos federales del DOT y deben mantener archivado un certificado vigente del examinador médico. Fuente: categorías de autocertificación del MS DPS; 49 CFR 383.71(b)."},"87":{"q":"Un conductor de Mississippi que se autocertifica como Interestatal No Exento debe mantener qué archivado ante el DPS para conservar una CDL válida?","options":["Un certificado vigente del examinador médico del DOT","Un certificado vigente de seguro de responsabilidad civil comercial general","Un CLP renovado cada seis meses","Un permiso de sobredimensión/sobrepeso del MDOT"],"explanation":"Los conductores Interestatales No Exentos (e Intraestatales No Exentos) deben mantener un certificado vigente del examinador médico del DOT registrado ante el DPS; no hacerlo provoca una rebaja de categoría. Fuente: Requisitos de Certificación Médica del MS DPS; 49 CFR 383.71/383.73."},"88":{"q":"A partir del 23 de junio de 2025, ¿cómo se transmite al Mississippi DPS el resultado del examen médico del DOT de un conductor de CDL?","options":["El examinador médico certificado lo envía electrónicamente al National Registry de la FMCSA, que lo transmite al DPS","El conductor envía por correo una copia en papel del Formulario MCSA-5876 a la sede del DPS","El conductor sube una copia escaneada a través del portal en línea del DPS","El empleador envía por fax una copia a la estación local de licencias de conducir del DPS"],"explanation":"Conforme a la regla final de la FMCSA vigente desde el 23 de junio de 2025, los examinadores médicos certificados envían los resultados del examen electrónicamente al National Registry, que los transmite al estado; Mississippi registra el resultado directamente en el expediente del conductor. Fuente: Requisitos de Certificación Médica del MS DPS; regla final de Integración de la Certificación del Examinador Médico de la FMCSA."},"89":{"q":"Después del cambio federal del 23 de junio de 2025, ¿puede una estación de licencias de conducir de Mississippi aceptar una copia en papel o escaneada del Certificado del Examinador Médico (Formulario MCSA-5876)?","options":["No; las copias en papel y escaneadas ya no se aceptan, ya que los resultados llegan electrónicamente desde el National Registry","Sí; las copias en papel siguen siendo el método principal de presentación","Sí, pero solo si se notariza dentro de los 15 días del examen","Sí, pero solo para conductores intraestatales (NA)"],"explanation":"A partir del 23 de junio de 2025, las estaciones del DPS ya no aceptan copias físicas ni escaneadas del MCSA-5876; el resultado del examen médico debe recibirse electrónicamente desde el National Registry de la FMCSA. Fuente: Requisitos de Certificación Médica del MS DPS; regla final de Integración de la Certificación del Examinador Médico de la FMCSA."},"90":{"q":"Según la regla de la FMCSA que sigue Mississippi, ¿para cuándo debe un examinador médico certificado subir al National Registry el resultado del examen de un conductor de CDL?","options":["Para el final del siguiente día calendario después del examen","Dentro de los 30 días del examen","Dentro de los 14 días del examen","Para el final de la misma semana laboral"],"explanation":"Conforme a la regla vigente desde el 23 de junio de 2025, el examinador médico certificado debe subir electrónicamente los resultados del examen al National Registry antes de la medianoche del siguiente día calendario posterior al examen. Fuente: regla final de Integración de la Certificación del Examinador Médico de la FMCSA, aplicada por el MS DPS."},"91":{"q":"¿Qué le sucede a una CDL de Mississippi si un conductor no exento deja vencer su certificación médica del DOT y no la actualiza?","options":["El DPS rebaja la categoría de la CDL, eliminando los privilegios de conducción comercial hasta que se restablezca la certificación","La CDL se revoca permanentemente y no puede reinstaurarse","Nada cambia hasta la siguiente renovación de 5 años","El conductor se reclasifica automáticamente como Interestatal Exento"],"explanation":"A un conductor no exento que no mantiene vigente su certificación médica se le cambia a \"no certificado\", y el estado rebaja la categoría de la CDL, eliminando los privilegios comerciales hasta que haya nuevamente una certificación válida archivada. Fuente: Requisitos de Certificación Médica del MS DPS; 49 CFR 383.73."},"92":{"q":"¿Qué documentos suelen requerirse al solicitar una nueva CDL de Mississippi en una oficina del DPS?","options":["Prueba de identidad/nacimiento, número de Seguro Social y dos pruebas de residencia en Mississippi","Solo un pasaporte, sin ninguna otra documentación necesaria","Un diploma de escuela secundaria y tres referencias personales","Solo un título del vehículo y prueba de seguro comercial de automóvil"],"explanation":"Un nuevo solicitante de CDL debe presentar prueba de identidad (como un certificado de nacimiento), prueba del número de Seguro Social y dos pruebas de residencia en Mississippi, además de aprobar los exámenes requeridos. Fuente: requisitos para nueva CDL del MS DPS Driver Service Bureau."},"93":{"q":"¿Cuál es la edad mínima para obtener una CDL de Mississippi limitada a la conducción comercial intraestatal (dentro del estado)?","options":["18 años","21 años","19 años","16 años"],"explanation":"Un conductor puede obtener una CDL para operación intraestatal a los 18 años, pero debe tener 21 para la operación interestatal y para transportar materiales peligrosos. Fuente: MS DPS / Manual de CDL de Mississippi; 49 CFR 383.3 / 391.11."},"94":{"q":"¿Cuál es la edad mínima para obtener una CDL de Mississippi para conducción interestatal o para transportar materiales peligrosos con placa?","options":["21 años","18 años","23 años","19 años"],"explanation":"Las reglas federales adoptadas por Mississippi exigen que un conductor tenga al menos 21 años para operar en el comercio interestatal y para transportar materiales peligrosos con placa. Fuente: MS DPS / Manual de CDL de Mississippi; 49 CFR 391.11."},"95":{"q":"¿Quién puede administrar legalmente la prueba de habilidades (de carretera) de la CDL de Mississippi además de los examinadores del DPS?","options":["Examinadores/Evaluadores Externos aprobados por el estado","Cualquier titular de CDL con licencia y dos años de experiencia","El gerente de seguridad del posible empleador del solicitante","Cualquier instructor de aula de ELDT registrado ante la FMCSA"],"explanation":"Mississippi permite que la prueba de habilidades de la CDL la administren ya sea los examinadores del DPS o los Evaluadores Externos aprobados por el estado de la lista que mantiene el DPS. Fuente: MS DPS Driver Service Bureau (programa de Evaluadores Externos); 49 CFR 383.75."},"96":{"q":"Un solicitante de Mississippi reprueba únicamente la parte de conducción en carretera de la prueba de habilidades de la CDL pero aprueba las partes de inspección previa al viaje y de control básico. ¿Cuál es el resultado general?","options":["El solicitante debe volver a presentar la parte de conducción en carretera y todavía no recibe la CDL","El solicitante recibe automáticamente una CDL intraestatal restringida","Las tres partes de habilidades deben repetirse desde el principio","Se le emite la CDL al solicitante porque aprobó dos de las tres partes"],"explanation":"Las tres partes de habilidades (inspección previa al viaje, control básico del vehículo y conducción en carretera) deben aprobarse para que se emita una CDL; reprobar cualquiera de las partes significa que debe repetirse y la CDL no se emite hasta que todas estén aprobadas. Fuente: MS DPS / Manual de CDL de Mississippi; 49 CFR 383.113."}},"hi":{"0":{"q":"मिसिसिपी के राजमार्गों पर किसी वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई कितनी है (आवश्यक सुरक्षा उपकरणों और शीशों को छोड़कर)?","options":["8 feet 0 inches (96 inches)","8 feet 6 inches (102 inches)","9 feet 0 inches (108 inches)","10 feet 0 inches (120 inches)"],"explanation":"मिसिसिपी वाहन की चौड़ाई को 8 feet 6 inches (102 inches) तक सीमित करता है; इससे अधिक चौड़े लोड के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Miss. Code Ann. Sec. 63-5-13 (Outside width of vehicles); MDOT Office of Enforcement Permit rules."},"1":{"q":"मिसिसिपी के राजमार्गों पर किसी वाहन की, किसी भी लोड सहित, अधिकतम कानूनी ऊँचाई कितनी है?","options":["14 feet 6 inches","14 feet 0 inches","12 feet 6 inches","13 feet 6 inches"],"explanation":"मिसिसिपी में कोई भी वाहन, चाहे बिना लोड के हो या लोड के साथ, 13 feet 6 inches की ऊँचाई से अधिक नहीं हो सकता। स्रोत: Miss. Code Ann. Sec. 63-5-17 (Height of vehicles)."},"2":{"q":"मिसिसिपी में, बिना किसी विशेष परमिट के संचालित होने वाले किसी वाहन या संयोजन के लिए अधिकतम सकल वज़न (किसी भी छूट के बिना) कितना है?","options":["73,280 pounds","76,000 pounds","80,000 pounds","88,000 pounds"],"explanation":"परमिट के बिना अधिकतम सकल वाहन वज़न 80,000 pounds है (इसके ऊपर 2% की छूट लागू हो सकती है)। स्रोत: Miss. Code Ann. Sec. 63-5-33; MDOT Mississippi Maximum Weight Laws."},"3":{"q":"मिसिसिपी किसी एकल धुरी (single axle) पर अधिकतम कितना सकल वज़न अनुमति देता है?","options":["24,000 pounds","22,400 pounds","18,000 pounds","20,000 pounds"],"explanation":"किसी भी एकल धुरी पर सकल वज़न 20,000 pounds से अधिक नहीं हो सकता (वैधानिक छूट को छोड़कर)। स्रोत: Miss. Code Ann. Sec. 63-5-27 (Wheel and axle loads); MDOT Maximum Weight Laws."},"4":{"q":"मिसिसिपी किसी जुड़वाँ धुरी (tandem axle) पर अधिकतम कितना सकल वज़न अनुमति देता है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"किसी भी जुड़वाँ धुरी पर सकल वज़न 34,000 pounds से अधिक नहीं हो सकता (वैधानिक छूट को छोड़कर)। स्रोत: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"5":{"q":"मिसिसिपी कानून के तहत, वज़न के प्रयोजनों के लिए 'एकल धुरी' (single axle) को कैसे परिभाषित किया गया है?","options":["कोई भी दो लगातार धुरियाँ जो 40 inches से अधिक दूरी पर हों","दो या अधिक धुरियाँ जो ठीक 96 inches की दूरी पर हों","वाहन के प्रत्येक ओर एक एकल पहिया और टायर असेंबली","एक ही अनुप्रस्थ तल में दो या अधिक पहिये, या 40 inches की दूरी पर स्थित समानांतर तलों के भीतर"],"explanation":"एकल धुरी दो या अधिक पहियों की एक असेंबली है जिनके केंद्र एक ही अनुप्रस्थ ऊर्ध्वाधर तल में होते हैं, या जो वाहन की पूरी चौड़ाई पर 40 inches की दूरी पर स्थित दो समानांतर अनुप्रस्थ तलों के बीच आते हैं। स्रोत: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"6":{"q":"मिसिसिपी कानून वज़न के प्रयोजनों के लिए 'जुड़वाँ धुरी' (tandem axle) को कैसे परिभाषित करता है?","options":["दो या अधिक लगातार धुरियाँ जिनके केंद्र 40 inches से अधिक परंतु 96 inches से अधिक नहीं की दूरी पर हों","दो धुरियाँ जिनके केंद्र ठीक 40 inches की दूरी पर हों","कोई भी धुरियों का समूह जो 96 inches से अधिक फैला हो","दो धुरियाँ जहाँ एक ड्राइविंग धुरी और एक स्टीयरिंग धुरी हो"],"explanation":"जुड़वाँ धुरी कोई भी दो या अधिक लगातार धुरियाँ हैं जिनके केंद्र 40 inches से अधिक परंतु 96 inches से अधिक नहीं की दूरी पर हों, और समूह की किसी एक भी धुरी पर एकल-धुरी सीमा से अधिक वज़न नहीं हो सकता। स्रोत: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"7":{"q":"मिसिसिपी के राजमार्गों पर एकल (सीधे) ट्रक की अधिकतम लंबाई कितनी है?","options":["40 feet","45 feet","48 feet","53 feet"],"explanation":"मिसिसिपी में कोई भी एकल वाहन (सीधा ट्रक) कुल लंबाई में 40 feet से अधिक नहीं हो सकता। स्रोत: Miss. Code Ann. Sec. 63-5-19 (Vehicle length limitations)."},"8":{"q":"मिसिसिपी में ट्रक-ट्रैक्टर/सेमीट्रेलर संयोजन में संचालित सेमीट्रेलर की अधिकतम लंबाई कितनी है?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"मिसिसिपी में ट्रक-ट्रैक्टर/सेमीट्रेलर संयोजन में संचालित सेमीट्रेलर 53 feet से अधिक नहीं हो सकता। स्रोत: Miss. Code Ann. Sec. 63-5-19 (Vehicle length limitations)."},"9":{"q":"दो या अधिक लगातार धुरियों के किसी भी समूह पर अधिकतम वज़न निर्धारित करने के लिए, मिसिसिपी कौन सा मानक लागू करता है?","options":["दूरी की परवाह किए बिना एक समान 80,000-pound की सीमा","Federal Bridge Formula (वज़न धुरी की दूरी से जुड़ा)","केवल 550-pounds-per-inch टायर-चौड़ाई नियम","हार्वेस्ट-परमिट छूट अनुसूची"],"explanation":"मिसिसिपी Federal Bridge Formula का उपयोग करता है, इसलिए धुरियों के किसी समूह पर अनुमेय वज़न समूह की चरम धुरियों के बीच की दूरी पर निर्भर करता है। स्रोत: Miss. Code Ann. Sec. 63-5-29/63-5-33 weight tables; MDOT Maximum Weight Laws."},"10":{"q":"हार्वेस्ट परमिट के बिना संचालित वाहन के लिए मिसिसिपी का अधिकतम सकल वज़न 80,000 pounds किस वैधानिक छूट तक पार किया जा सकता है?","options":["10%","5%","1%","2%"],"explanation":"अधिकतम सकल वाहन वज़न 80,000 pounds से अधिक नहीं हो सकता, साथ ही 2% से अधिक नहीं की छूट। स्रोत: Miss. Code Ann. Sec. 63-5-33."},"11":{"q":"हार्वेस्ट परमिट के साथ संचालित वाहन को मिसिसिपी अपने अधिकृत सकल, जुड़वाँ, या धुरी वज़न से ऊपर कितनी वज़न छूट की अनुमति देता है?","options":["2%","5%","10%","15%"],"explanation":"हार्वेस्ट-परमिट वाहन को अपने अधिकृत सकल, जुड़वाँ, या धुरी वज़न से ऊपर 10% से अधिक नहीं की छूट की अनुमति है (88,000-pound की सीमा के अधीन)। स्रोत: Miss. Code Ann. Sec. 63-5-33."},"12":{"q":"मिसिसिपी में ओवरसाइज़/ओवरवेट (ओवर-डाइमेंशनल) परमिट कौन सी एजेंसी जारी करती है?","options":["Mississippi Department of Transportation, Office of Enforcement Permit Division","Mississippi Department of Public Safety, Driver Services","Mississippi State Tax Commission","मूल काउंटी का काउंटी शेरिफ"],"explanation":"ओवर-डाइमेंशनल परमिट MDOT Office of Enforcement, Permit Division द्वारा Mississippi Transportation Commission के प्राधिकार के तहत जारी किए जाते हैं। स्रोत: MDOT Over-Dimensional Permit Rules (Sub-Part 6601, Chapter 03001); Miss. Code Ann. Sec. 65-1-8."},"13":{"q":"मिसिसिपी में, एक Single Trip ओवर-डाइमेंशनल परमिट कितनी अधिकतम अवधि के लिए आवाजाही को अधिकृत करता है?","options":["24 hours","लगातार तीन दिन","लगातार सात दिन","तीस दिन"],"explanation":"एक Single Trip Permit किसी विशिष्ट वाहन/लोड की आवाजाही को लगातार तीन (3) दिनों से अधिक नहीं की अवधि के लिए अधिकृत करता है। स्रोत: MDOT Over-Dimensional Permit Rules, Sec. 213 (Definitions)."},"14":{"q":"किसी अविभाज्य (non-divisible) लोड के लिए आम तौर पर मिसिसिपी ओवरसाइज़ परमिट प्राप्त करना तब आवश्यक होता है जब उसकी चौड़ाई किस आयाम से अधिक हो जाए?","options":["8 feet 0 inches","8 feet 6 inches","10 feet 0 inches","12 feet 0 inches"],"explanation":"कानूनी 8-foot-6-inch (102-inch) चौड़ाई सीमा से अधिक लोड को ले जाने के लिए परमिट की आवश्यकता होती है। स्रोत: Miss. Code Ann. Sec. 63-5-13; MDOT Office of Enforcement Permit rules."},"15":{"q":"मिसिसिपी ओवर-डाइमेंशनल परमिट नियमों के तहत, किस लोड चौड़ाई पर सख्त 'दिन के उजाले के घंटे' (daylight hours) और एस्कॉर्ट आवश्यकताएँ लागू हो जाती हैं?","options":["12 feet से अधिक चौड़ाई","10 feet से अधिक चौड़ाई","14 feet से अधिक चौड़ाई","16 feet से अधिक चौड़ाई"],"explanation":"12 feet से अधिक चौड़ाई वाले लोड के लिए, 'दिन के उजाले के घंटे' सूर्योदय के 30 मिनट बाद से सूर्यास्त के 30 मिनट पहले तक सीमित हो जाते हैं और अतिरिक्त एस्कॉर्ट आवश्यकताएँ लागू होती हैं। स्रोत: MDOT Over-Dimensional Permit Rules, Sec. 200."},"16":{"q":"मिसिसिपी एकल- और जुड़वाँ-धुरी वज़न को इस प्रकार सीमित करता है कि सकल वज़न टायर की चौड़ाई के प्रति इंच कितने pounds से अधिक न हो (धुरी अधिकतम सीमाओं के अधीन)?","options":["650 pounds per inch","600 pounds per inch","500 pounds per inch","550 pounds per inch"],"explanation":"एकल या जुड़वाँ धुरी का सकल वज़न टायर की चौड़ाई के प्रति इंच 550 pounds से अधिक नहीं हो सकता (500 pounds तक की छूट के साथ), जो कभी भी 20,000/34,000-pound धुरी अधिकतम सीमाओं से अधिक नहीं हो। स्रोत: Miss. Code Ann. Sec. 63-5-27; MDOT Maximum Weight Laws."},"17":{"q":"मिसिसिपी राज्य राजमार्गों पर (Interstate प्रणाली को छोड़कर), अपनी चरम धुरियों के बीच 29 feet से अधिक मापने वाला एक पंजीकृत वाहन, ब्रिज-फॉर्मूला वज़न के प्रयोजनों के लिए, ऐसा माना जाता है जैसे उस धुरी समूह की लंबाई कितनी अधिक हो?","options":["6 feet अधिक","12 feet अधिक","20 feet अधिक","29 feet अधिक"],"explanation":"Sec. 63-5-34 के केवल-राज्य-राजमार्ग प्रावधान के तहत, ऐसे वाहन को उसके चरम धुरी समूह को उसके वास्तविक माप से 12 feet अधिक दूरी पर माना जाता है (यह federal Interstate प्रणाली पर लागू नहीं होता)। स्रोत: Miss. Code Ann. Sec. 63-5-34; MDOT Maximum Weight Laws."},"18":{"q":"मिसिसिपी में जुड़वाँ धुरियों के दो लगातार सेटों में से प्रत्येक को 34,000 pounds ले जाने के लिए (80,000 pounds सकल से अधिक हुए बिना), सेटों की पहली और अंतिम धुरियों के बीच की दूरी कम से कम कितनी होनी चाहिए?","options":["30 feet","34 feet","36 feet","40 feet"],"explanation":"जुड़वाँ धुरियों के दो लगातार सेट प्रत्येक 34,000 pounds ले जा सकते हैं बशर्ते पहली और अंतिम धुरियों के बीच की कुल दूरी 36 feet या अधिक हो, कुल सकल वज़न Sec. 63-5-33 द्वारा अनुमत के अलावा 80,000 pounds से अधिक न हो। स्रोत: MDOT Maximum Weight Laws (Table III note); Miss. Code Ann. Sec. 63-5-33."},"19":{"q":"मिसिसिपी में, न्यूनतम सकल वाहन वज़न रेटिंग (GVWR) सीमा क्या है जो किसी एकल वाणिज्यिक वाहन को Class A या Class B श्रेणी में रखती है?","options":["26,001 pounds या अधिक","10,001 pounds या अधिक","18,001 pounds या अधिक","33,001 pounds या अधिक"],"explanation":"मिसिसिपी Class B को 26,001 pounds या अधिक GVWR वाले किसी भी एकल वाहन के रूप में, और Class A को 26,001 pounds या अधिक GVWR वाले वाहनों के संयोजन (10,000 lbs से अधिक की इकाई को खींचना) के रूप में परिभाषित करता है। स्रोत: Mississippi DPS Driver Service Bureau, CDL Classes A-D page; Mississippi CDL Manual."},"20":{"q":"26,001 pounds या अधिक GVWR वाले वाहनों के किसी भी संयोजन को संचालित करने के लिए, जहाँ खींचे जा रहे वाहन का GVWR 10,000 pounds से अधिक हो, कौन सा मिसिसिपी CDL वर्ग आवश्यक है?","options":["Class B","Class A","Class C","Class D"],"explanation":"मिसिसिपी Class A में 26,001 lbs या अधिक GVWR वाले संयोजन वाहन शामिल हैं जो 10,000 lbs से अधिक GVWR वाली इकाई को खींचते हैं। स्रोत: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"21":{"q":"एक मिसिसिपी चालक 30,000 pounds GVWR वाला एक एकल सीधा ट्रक चलाता है जो कुछ भी नहीं खींचता। इसके लिए कौन सा CDL वर्ग आवश्यक है?","options":["Class A","Class C","Class B","कोई CDL आवश्यक नहीं है"],"explanation":"26,001 lbs या अधिक GVWR वाला एक एकल वाहन (जो 10,000 lbs से अधिक की इकाई को नहीं खींचता) मिसिसिपी में एक Class B वाहन है। स्रोत: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"22":{"q":"मिसिसिपी नियमों के तहत, ऐसा वाहन जो Class A या B वज़न सीमाओं को पूरा नहीं करता, फिर भी Class C CDL की आवश्यकता होती है यदि उसे कितने लोगों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया हो?","options":["8 या अधिक","11 या अधिक","24 या अधिक","16 या अधिक"],"explanation":"मिसिसिपी Class C ऐसे वाहन पर लागू होता है जो Class A/B वज़न सीमाओं से कम है और जिसे चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो, या जो प्लेकार्ड किए गए खतरनाक पदार्थों को ले जाता हो। स्रोत: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"23":{"q":"16-यात्री नियम के अलावा, मिसिसिपी में कौन सी अन्य स्थिति किसी छोटे वाहन के लिए Class C CDL की आवश्यकता का कारण बनती है?","options":["यह वाणिज्यिक उपयोग के लिए पंजीकृत है","यह प्लेकार्डिंग की आवश्यकता वाली मात्रा में खतरनाक पदार्थों का परिवहन करता है","यह राज्य की सीमा पार करता है","इसका स्वामित्व किसी मोटर वाहक के पास है"],"explanation":"Class A/B वज़न सीमाओं से कम वाहन के लिए Class C CDL की आवश्यकता होती है यदि उसका उपयोग प्लेकार्ड की आवश्यकता वाली मात्रा में खतरनाक पदार्थों के परिवहन के लिए किया जाता है। स्रोत: Mississippi DPS Driver Service Bureau, CDL Classes A-D; Mississippi CDL Manual."},"24":{"q":"मिसिसिपी में प्लेकार्ड की गई मात्रा में खतरनाक पदार्थों का परिवहन करने के लिए कौन सा CDL एंडोर्समेंट आवश्यक है?","options":["N endorsement","T endorsement","H endorsement","केवल X endorsement"],"explanation":"प्लेकार्ड किए गए खतरनाक पदार्थों को ढोने के लिए H (HazMat) एंडोर्समेंट आवश्यक है। X एंडोर्समेंट एक संयुक्त HazMat-प्लस-Tank एंडोर्समेंट है और जिन चालकों को केवल HazMat की आवश्यकता है उनके लिए यह आवश्यक नहीं है। स्रोत: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93."},"25":{"q":"मिसिसिपी में, कौन सा एंडोर्समेंट किसी CDL धारक को टैंक वाहन (टैंकर) चलाने के लिए अधिकृत करता है?","options":["T endorsement","P endorsement","S endorsement","N endorsement"],"explanation":"N एंडोर्समेंट टैंक वाहन (टैंकर) एंडोर्समेंट है। T डबल्स/ट्रिपल्स है, P यात्री है, और S स्कूल बस है। स्रोत: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93."},"26":{"q":"डबल या ट्रिपल ट्रेलर खींचने के लिए कौन सा मिसिसिपी CDL एंडोर्समेंट आवश्यक है?","options":["T endorsement","N endorsement","H endorsement","P endorsement"],"explanation":"डबल या ट्रिपल ट्रेलर खींचने के लिए T एंडोर्समेंट (डबल्स/ट्रिपल्स) आवश्यक है और यह केवल एक ज्ञान परीक्षण द्वारा प्राप्त किया जाता है। स्रोत: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93."},"27":{"q":"मिसिसिपी CDL पर X एंडोर्समेंट क्या दर्शाता है?","options":["नवीनीकरण के लंबित एक समाप्त एंडोर्समेंट","मेडिकल प्रमाणपत्र से छूट","HazMat (H) और Tank (N) एंडोर्समेंट का संयोजन","एक राज्य-बाहरी पारस्परिकता एंडोर्समेंट"],"explanation":"मिसिसिपी X को संयुक्त HazMat-और-Tank एंडोर्समेंट के रूप में सूचीबद्ध करता है, जो तब जारी किया जाता है जब कोई चालक H और N दोनों के लिए योग्य होता है। स्रोत: Mississippi DPS Driver Service Bureau, CDL endorsement list; FMCSA 49 CFR 383.93."},"28":{"q":"मिसिसिपी में स्कूल बस चलाने के लिए, किसी CDL धारक को एंडोर्समेंट का कौन सा संयोजन प्राप्त करना चाहिए?","options":["केवल S (स्कूल बस) एंडोर्समेंट","केवल P (यात्री) एंडोर्समेंट","T (डबल्स/ट्रिपल्स) एंडोर्समेंट","P (यात्री) और S (स्कूल बस) दोनों एंडोर्समेंट"],"explanation":"मिसिसिपी स्कूल बस चालकों के पास Passenger (P) और School Bus (S) दोनों एंडोर्समेंट होने चाहिए; S एंडोर्समेंट P एंडोर्समेंट पर आधारित होता है। स्रोत: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.93."},"29":{"q":"केवल राज्य के भीतर (intrastate) ड्राइविंग के लिए मान्य मिसिसिपी CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"मिसिसिपी केवल राज्य के भीतर वाणिज्य के लिए 18 वर्ष की आयु में CDL की अनुमति देता है; अंतरराज्यीय (interstate) ड्राइविंग के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"30":{"q":"मिसिसिपी CDL के साथ राज्य की सीमाओं के पार (interstate) किसी वाणिज्यिक मोटर वाहन को संचालित करने के लिए न्यूनतम कितनी आयु आवश्यक है?","options":["18 years old","21 years old","19 years old","25 years old"],"explanation":"चालकों को अंतरराज्यीय वाणिज्य में संचालन के लिए और अंतरराज्यीय कार्य हेतु HazMat या यात्री एंडोर्समेंट रखने के लिए कम से कम 21 वर्ष का होना चाहिए। स्रोत: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 391.11."},"31":{"q":"मिसिसिपी में, अंतरराज्यीय संचालन के लिए चालक को HazMat (H) या यात्री (P) एंडोर्समेंट प्राप्त करने से पहले न्यूनतम कितनी आयु आवश्यक है?","options":["18 years old","19 years old","23 years old","21 years old"],"explanation":"मिसिसिपी के अनुसार चालक को अंतरराज्यीय वाणिज्य के लिए HazMat या यात्री एंडोर्समेंट जारी किए जाने हेतु कम से कम 21 वर्ष का होना चाहिए, जो संघीय नियमों के अनुरूप है। स्रोत: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.3 / 391.11."},"32":{"q":"मिसिसिपी में Commercial Learner Permit (CLP) प्राप्त करने के बाद, CDL कौशल (सड़क) परीक्षण देने की अनुमति मिलने से पहले किसी चालक को इसे कितने समय तक रखना आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 7 दिन","कम से कम 60 दिन"],"explanation":"मिसिसिपी द्वारा अपनाए गए संघीय नियम के अनुसार आवेदक द्वारा CDL कौशल परीक्षण देने से पहले CLP को न्यूनतम 14 दिनों तक रखा जाना आवश्यक है। स्रोत: Mississippi CDL Manual; FMCSA 49 CFR 383.25."},"33":{"q":"मिसिसिपी Commercial Learner Permit (CLP) नवीनीकृत किए जाने या CDL प्राप्त किए जाने से पहले कितने समय के लिए मान्य होता है?","options":["30 दिन","180 दिन (6 महीने)","1 वर्ष","90 दिन"],"explanation":"एक मिसिसिपी CLP 180 दिनों (छह महीने) के लिए मान्य होता है; राज्य अतिरिक्त 180 दिनों के लिए एक नवीनीकरण की अनुमति दे सकते हैं। स्रोत: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.25."},"34":{"q":"किस एंडोर्समेंट को मिसिसिपी Commercial Learner Permit (CLP) पर रखने की अनुमति नहीं है?","options":["N (टैंक) एंडोर्समेंट, जब टैंक खाली हो","P (यात्री) एंडोर्समेंट","H (HazMat) एंडोर्समेंट","S (स्कूल बस) एंडोर्समेंट"],"explanation":"मिसिसिपी द्वारा अपनाए गए संघीय नियम CLP पर HazMat (H) एंडोर्समेंट को प्रतिबंधित करते हैं; केवल P, S, और N एंडोर्समेंट प्रतिबंधों के साथ CLP पर दिखाई दे सकते हैं। स्रोत: Mississippi CDL Manual; FMCSA 49 CFR 383.25."},"35":{"q":"मिसिसिपी आवेदक अब HazMat (H) एंडोर्समेंट के लिए आवश्यक फिंगरप्रिंटिंग और TSA पृष्ठभूमि जाँच कहाँ पूरी करता है?","options":["TSA Universal Enrollment Services प्रदाता (IdentoGO) के माध्यम से, न कि स्थानीय DPS CDL स्टेशन पर","किसी भी स्थानीय Mississippi DPS CDL स्टेशन पर","FMCSA National Registry कार्यालय पर","काउंटी सर्किट क्लर्क के कार्यालय में"],"explanation":"मिसिसिपी ने HazMat फिंगरप्रिंटिंग और नामांकन को TSA Universal Enrollment Services कार्यक्रम (IdentoGO / universalenroll.dhs.gov) में स्थानांतरित कर दिया है; यह अब स्थानीय DPS CDL स्टेशनों पर नहीं किया जाता। स्रोत: Mississippi DPS Driver Service Bureau, CDL HazMat Enrollment Program."},"36":{"q":"7 फरवरी 2022 से, पहली बार के मिसिसिपी CDL आवेदकों को किसके द्वारा प्रदान किया गया Entry-Level Driver Training (ELDT) पूरा करना होगा?","options":["कोई भी मिसिसिपी सामुदायिक कॉलेज","Mississippi DPS स्वयं","किसी भी प्रकार के नियोक्ता का इन-हाउस प्रशिक्षक","FMCSA Training Provider Registry पर सूचीबद्ध एक प्रदाता"],"explanation":"7 फरवरी 2022 से प्रभावी, पहली बार के CDL आवेदकों (और कुछ अपग्रेड/एंडोर्समेंट) को CDL परीक्षण से पहले FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता से ELDT पूरा करना होगा। स्रोत: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR Part 380."},"37":{"q":"जब कोई मिसिसिपी CDL आवेदक अपने ड्राइविंग के प्रकार को स्व-प्रमाणित करता है, तो कौन सी श्रेणी इंगित करती है कि वे अंतरराज्यीय वाणिज्य में संचालन करते हैं और उन्हें संघीय DOT मेडिकल प्रमाणपत्र आवश्यकताओं को पूरा करना होगा?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"मिसिसिपी चार संघीय स्व-प्रमाणन श्रेणियों का उपयोग करता है। Non-Excepted Interstate (NI) चालक राज्य की सीमाओं के पार संचालन करते हैं और उन्हें एक मान्य DOT मेडिकल परीक्षक का प्रमाणपत्र रखना होगा। स्रोत: Mississippi DPS Driver Service Bureau; FMCSA 49 CFR 383.71."},"38":{"q":"पहचान/वैध उपस्थिति, सामाजिक सुरक्षा, और निवास आवश्यकताओं को पूरा करने के लिए किसी मिसिसिपी CDL आवेदक को दस्तावेज़ों का कौन सा समूह प्रस्तुत करना चाहिए?","options":["एक हाई स्कूल डिप्लोमा, एक मतदाता कार्ड, और एक यूटिलिटी बिल","केवल एक पासपोर्ट, बिना किसी निवास प्रमाण की आवश्यकता के","एक मूल जन्म प्रमाणपत्र (या वैध-उपस्थिति प्रमाण), सामाजिक सुरक्षा संख्या दस्तावेज़, और मिसिसिपी निवास के दो प्रमाण","एक वाहन शीर्षक, एक बीमा कार्ड, और एक मछली पकड़ने का लाइसेंस"],"explanation":"मिसिसिपी को CDL के लिए आवेदन करने हेतु पहचान/वैध उपस्थिति का प्रमाण (जैसे, मूल जन्म प्रमाणपत्र), सामाजिक सुरक्षा संख्या दस्तावेज़, और निवास के दो प्रमाण, साथ ही एक मान्य मेडिकल कार्ड की आवश्यकता होती है। स्रोत: Mississippi DPS Driver Service Bureau, CDL applicant requirements."},"39":{"q":"मिसिसिपी में, अधिकतम रक्त/श्वास अल्कोहल सांद्रता (BAC) कितनी है जिस पर कोई व्यक्ति कानूनी रूप से किसी वाणिज्यिक मोटर वाहन को संचालित कर सकता है?","options":["0.02","0.04","0.08","0.10"],"explanation":"मिसिसिपी संघीय CMV मानक का पालन करता है: 0.04% या अधिक की अल्कोहल सांद्रता के साथ किसी वाणिज्यिक मोटर वाहन को संचालित करना गैरकानूनी है। 0.04% या अधिक की रीडिंग पहली प्रमुख-अपराध अयोग्यता का आधार है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51; Mississippi CDL Manual (DPS)."},"40":{"q":"एक मिसिसिपी CDL धारक प्लेकार्ड किए गए खतरनाक पदार्थों को न ले जाते हुए 0.04% BAC के साथ CMV संचालित करने के पहले अपराध के लिए दोषी पाया जाता है। चालक को CMV संचालित करने से कितने समय के लिए अयोग्य ठहराया जाता है?","options":["6 महीने","1 वर्ष","3 वर्ष","आजीवन"],"explanation":"एक पहला प्रमुख अपराध (जिसमें 0.04% या अधिक BAC के साथ CMV चलाना शामिल है) के परिणामस्वरूप मिसिसिपी में न्यूनतम 1-वर्ष की CDL अयोग्यता होती है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"41":{"q":"यदि कोई मिसिसिपी CDL धारक प्लेकार्ड किए गए खतरनाक पदार्थों का परिवहन करते समय पहला प्रमुख अपराध (जैसे CMV में DUI) करता है, तो अयोग्यता अवधि बढ़कर हो जाती है:","options":["1 वर्ष","2 वर्ष","3 वर्ष","5 वर्ष"],"explanation":"मिसिसिपी और संघीय नियमों के तहत, प्लेकार्ड किए गए खतरनाक पदार्थों का परिवहन करते समय किया गया पहला प्रमुख अपराध मानक 1 वर्ष के बजाय 3-वर्ष की अयोग्यता वहन करता है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual."},"42":{"q":"दूसरे प्रमुख अपराध (उदाहरण के लिए, CMV में दूसरा DUI) के लिए दोषी पाए गए मिसिसिपी CDL धारक के लिए अयोग्यता अवधि क्या है?","options":["3 वर्ष","5 वर्ष","10 वर्ष","आजीवन"],"explanation":"किसी भी प्रमुख अपराध के लिए दूसरी सजा के परिणामस्वरूप मिसिसिपी में आजीवन CDL अयोग्यता होती है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(3); Mississippi CDL Manual."},"43":{"q":"मिसिसिपी में, किसी CDL धारक के वाणिज्यिक ड्राइविंग विशेषाधिकार का क्या होता है यदि वे कानूनी रूप से अनुरोध किए जाने पर श्वास या रक्त के रासायनिक परीक्षण के लिए सहमत होने से इनकार करते हैं?","options":["बिना किसी अयोग्यता के एक चेतावनी जारी की जाती है","30 दिनों के लिए अयोग्यता","1 वर्ष के लिए अयोग्यता","90 दिनों के लिए अयोग्यता"],"explanation":"रासायनिक परीक्षण से इनकार को एक प्रमुख अपराध माना जाता है; मिसिसिपी के निहित-सहमति कानून के तहत पहली बार इनकार के लिए CDL को कम से कम 1 वर्ष के लिए अयोग्य ठहराया जाता है। स्रोत: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"44":{"q":"मिसिसिपी के निहित-सहमति (implied-consent) कानून के तहत, किसी मिसिसिपी राजमार्ग पर कोई भी मोटर वाहन संचालित करके एक चालक के बारे में यह माना जाता है कि उसने:","options":["वकील के अधिकार का त्याग कर दिया है","श्वास, रक्त, या मूत्र के रासायनिक परीक्षण के लिए सहमति दे दी है","यादृच्छिक सड़क किनारे निरीक्षणों के लिए सहमति दी है","स्वचालित लाइसेंस अंक स्वीकार कर लिए हैं"],"explanation":"मिसिसिपी का निहित-सहमति कानून प्रावधान करता है कि कोई भी व्यक्ति जो राज्य की सड़कों पर वाहन चलाता है, उसके बारे में यह माना जाता है कि उसने अल्कोहल या ड्रग सांद्रता निर्धारित करने के लिए रासायनिक परीक्षण के लिए सहमति दे दी है। स्रोत: Miss. Code Ann. 63-11-5, 63-11-30; Mississippi CDL Manual (DPS)."},"45":{"q":"3-वर्ष की अवधि के भीतर कितने गंभीर यातायात उल्लंघन (अलग-अलग घटनाओं में) मिसिसिपी में 60-दिन की CDL अयोग्यता को सक्रिय करते हैं?","options":["1","2","3","4"],"explanation":"3-वर्ष की अवधि के भीतर दो गंभीर यातायात उल्लंघन (अलग-अलग घटनाओं से उत्पन्न) के परिणामस्वरूप 60-दिन की अयोग्यता होती है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"46":{"q":"मिसिसिपी में, 3-वर्ष की अवधि के भीतर तीन गंभीर यातायात उल्लंघनों की सजा के परिणामस्वरूप CDL अयोग्यता होती है:","options":["60 दिन","90 दिन","120 दिन","1 वर्ष"],"explanation":"3 वर्षों के भीतर तीन गंभीर यातायात उल्लंघन (अलग-अलग घटनाएँ) के परिणामस्वरूप 120-दिन की अयोग्यता होती है, जो किसी पूर्व 60-दिन की अयोग्यता के बाद क्रमिक रूप से पूरी की जाती है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"47":{"q":"निम्नलिखित में से किसे मिसिसिपी CDL धारक के लिए एक गंभीर (SERIOUS) यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["0.04% या अधिक BAC के साथ CMV संचालित करना","निर्धारित सीमा से 15 mph या अधिक गति से चलना","रासायनिक परीक्षण से इनकार करना","दुर्घटनास्थल से चले जाना"],"explanation":"सीमा से 15 mph या अधिक की गति एक गंभीर यातायात उल्लंघन है। सूचीबद्ध अन्य तीन प्रमुख अपराध हैं जो 1-वर्ष (या उससे अधिक) की अयोग्यता वहन करते हैं, न कि गंभीर उल्लंघन। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"48":{"q":"निम्नलिखित में से किसे मिसिसिपी CDL धारक के लिए गंभीर यातायात उल्लंघन के रूप में नहीं गिना जाता है?","options":["आगे चल रहे वाहन के बहुत करीब चलना","लापरवाही से वाहन चलाना","अनियमित या अनुचित लेन परिवर्तन करना","रात भर एक लावारिस CMV को अनुचित तरीके से पार्क करना"],"explanation":"बहुत करीब चलना, लापरवाही से वाहन चलाना, और अनियमित/अनुचित लेन परिवर्तन सभी गंभीर यातायात उल्लंघन हैं। किसी लावारिस वाहन की सामान्य पार्किंग गंभीर-उल्लंघन सूची में नहीं है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(c); Mississippi CDL Manual."},"49":{"q":"एक मिसिसिपी CDL चालक जो CMV चलाते समय टेक्स्ट करता है या हाथ में पकड़े मोबाइल फोन का उपयोग करता है, वह किस प्रकार का उल्लंघन करता है?","options":["एक गैर-रिपोर्ट योग्य उल्लंघन","एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक आउट-ऑफ-सर्विस उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्ट करना या हाथ में पकड़े फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है; 3 वर्षों के भीतर ऐसे दो या तीन गंभीर उल्लंघन 60- या 120-दिन की अयोग्यता का कारण बन सकते हैं। स्रोत: 49 CFR 383.51(c), 392.80/392.82; Miss. Code Ann. 63-1-216; Mississippi CDL Manual."},"50":{"q":"एक मिसिसिपी CDL चालक द्वारा प्लेकार्ड किए गए खतरनाक पदार्थों या 16 या अधिक यात्रियों का परिवहन करते समय पहला आउट-ऑफ-सर्विस आदेश उल्लंघन किस अयोग्यता को वहन करता है:","options":["180 दिनों से कम नहीं, 2 वर्ष से अधिक नहीं","ठीक 180 दिन","60 दिनों से कम नहीं, 1 वर्ष से अधिक नहीं","आजीवन"],"explanation":"जब प्लेकार्ड किए गए हेज़मैट का परिवहन करते समय या 16 या अधिक यात्रियों को ले जाते समय पहला आउट-ऑफ-सर्विस उल्लंघन होता है, तो अयोग्यता 180 दिनों से कम नहीं और 2 वर्ष से अधिक नहीं होती है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(e); Mississippi CDL Manual."},"51":{"q":"CMV संचालित करते समय पहले रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए दोषी पाए गए मिसिसिपी CDL चालक को अयोग्य ठहराया जाता है:","options":["30 दिनों से कम नहीं","60 दिनों से कम नहीं","120 दिनों से कम नहीं","1 वर्ष"],"explanation":"पहले रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप 60 दिनों से कम नहीं की अयोग्यता होती है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual."},"52":{"q":"3-वर्ष की अवधि के भीतर किसी मिसिसिपी CDL चालक के तीसरे रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता अवधि क्या है?","options":["120 दिन","6 महीने","1 वर्ष","आजीवन"],"explanation":"3 वर्षों के भीतर तीसरे (या बाद के) रेलरोड-ग्रेड-क्रॉसिंग उल्लंघन के परिणामस्वरूप 1 वर्ष से कम नहीं की अयोग्यता होती है। प्रगति है 60 दिन (पहला), 120 दिन (दूसरा), 1 वर्ष (तीसरा)। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(d); Mississippi CDL Manual."},"53":{"q":"मिसिसिपी में, एक CDL धारक जो किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े अपराध (felony) को करने के लिए किसी वाणिज्यिक मोटर वाहन का उपयोग करता है, उसे अयोग्य ठहराया जाता है:","options":["1 वर्ष","3 वर्ष","10 वर्ष","आजीवन, बिना किसी पुनर्बहाली के"],"explanation":"नियंत्रित पदार्थों से जुड़े किसी अपराध (felony) के संचालन में CMV का उपयोग करने के परिणामस्वरूप आजीवन अयोग्यता होती है, जो कुछ आजीवन अयोग्यताओं के विपरीत, कम नहीं की जा सकती। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"54":{"q":"निम्नलिखित में से कौन मिसिसिपी में एक गंभीर यातायात उल्लंघन के बजाय एक प्रमुख अपराध (1-वर्ष न्यूनतम अयोग्यता) है?","options":["बहुत करीब चलना","CMV से जुड़ी किसी दुर्घटना के स्थल से चले जाना","सीमा से 15 mph अधिक गति से चलना","अनुचित लेन परिवर्तन"],"explanation":"CMV से जुड़ी किसी दुर्घटना के स्थल से चले जाना एक प्रमुख अपराध है जो 1-वर्ष न्यूनतम अयोग्यता वहन करता है। अन्य विकल्प गंभीर यातायात उल्लंघन हैं। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b); Mississippi CDL Manual."},"55":{"q":"मिसिसिपी में, यदि कोई व्यक्ति CDL रखते हुए रासायनिक परीक्षण से इनकार करता है, तो वाणिज्यिक विशेषाधिकार की अयोग्यता लागू होती है:","options":["केवल यदि चालक उस समय CMV संचालित कर रहा था","केवल यदि बाद में BAC 0.04% से अधिक साबित होता है","भले ही इनकार किसी व्यक्तिगत (गैर-वाणिज्यिक) वाहन को चलाते समय हुआ हो","केवल दूसरी बार इनकार के बाद"],"explanation":"एक CDL धारक रासायनिक परीक्षण से इनकार करने के लिए अयोग्य ठहराया जाता है भले ही इनकार किसी गैर-वाणिज्यिक वाहन को संचालित करते समय हो; किसी व्यक्तिगत वाहन में सजा और इनकार अभी भी CDL को प्रभावित करते हैं। स्रोत: Miss. Code Ann. 63-11-30, 63-1-216; 49 CFR 383.51; Mississippi CDL Manual."},"56":{"q":"एक मिसिसिपी CDL चालक को अपने व्यक्तिगत वाहन में एक गंभीर यातायात उल्लंघन प्राप्त होता है जिसके परिणामस्वरूप लाइसेंस निलंबन होता है। यह CDL को कैसे प्रभावित करता है?","options":["इसका कोई प्रभाव नहीं होता क्योंकि यह CMV नहीं था","यह फिर भी CDL अयोग्यता की ओर गिना जाता है","यह केवल तभी गिना जाता है जब चालक ड्यूटी पर था","यह केवल हेज़मैट एंडोर्समेंट को प्रभावित करता है"],"explanation":"किसी व्यक्तिगत वाहन में सजा और लाइसेंस कार्रवाइयाँ CDL के विरुद्ध गिनी जाती हैं; कुछ गंभीर उल्लंघनों के लिए ड्राइविंग विशेषाधिकार का निलंबन/निरस्तीकरण/रद्दीकरण CDL अयोग्यता की ओर ले जाता है। स्रोत: Miss. Code Ann. 63-1-216; 49 CFR 383.51(b)(2); Mississippi CDL Manual."},"57":{"q":"मिसिसिपी के मूव ओवर कानून के तहत, जब आप दो लेन आपकी दिशा में जाने वाली चार-लेन वाली राजमार्ग पर चमकती लाइटें दिखाने वाले रुके हुए आपातकालीन या टो वाहन के पास पहुँचते हैं, तो आपको क्या करना चाहिए?","options":["यदि ऐसा करना सुरक्षित हो तो रुके हुए वाहन के बगल वाली लेन खाली कर दें","जब तक रुका हुआ वाहन वहाँ से चला न जाए तब तक पूरी तरह रुक जाएँ","वाहन को पार करते समय लगातार हॉर्न बजाएँ","अपनी गति बनाए रखें और अपनी मौजूदा लेन में ही रहें"],"explanation":"Miss. Code 63-3-809 के अनुसार कम से कम चार लेन वाली सड़क (एक ही दिशा में दो या अधिक लेन) पर चालकों को, जब सुरक्षित हो, स्थिर आपातकालीन, रिकवरी या यूटिलिटी वाहन के बगल वाली नहीं बल्कि किसी अन्य लेन में बदलना आवश्यक है। स्रोत: Mississippi Code 63-3-809."},"58":{"q":"मिसिसिपी के मूव ओवर कानून के तहत, यदि आप चमकती लाइटें दिखाने वाले रुके हुए आपातकालीन वाहन से दूर सुरक्षित रूप से लेन नहीं बदल सकते, तो इसके बजाय आपसे क्या करने की अपेक्षा की जाती है?","options":["बिना कुछ बदले निर्धारित गति सीमा पर चलते रहें","अपनी लेन में रुक जाएँ और किसी अधिकारी के आपको आगे जाने का इशारा करने का इंतज़ार करें","गति धीमी करें, सावधानी से आगे बढ़ें, और रुकने के लिए तैयार रहें","अपनी हैज़र्ड लाइटें चालू करें और सामान्य गति से पार करें"],"explanation":"Miss. Code 63-3-809 उस चालक को, जो सुरक्षित रूप से लेन नहीं बदल सकता, गति कम करने, उचित सावधानी के साथ आगे बढ़ने, और रुकने के लिए तैयार रहने का निर्देश देता है। स्रोत: Mississippi Code 63-3-809."},"59":{"q":"मिसिसिपी में, मूव ओवर कानून (63-3-809) का ऐसा उल्लंघन जिससे कोई क्षति या चोट नहीं होती, उस पर अधिकतम कितने जुर्माने का दंड लगाया जा सकता है?","options":["$100 तक","$250 तक","$500 तक","$1,000 तक"],"explanation":"Miss. Code 63-3-809 उल्लंघन के लिए $250 तक का जुर्माना निर्धारित करता है, जो $1,000 तक बढ़ जाता है यदि उल्लंघन से स्थिर वाहन को संपत्ति क्षति या उसमें बैठे लोगों को शारीरिक चोट पहुँचती है। स्रोत: Mississippi Code 63-3-809."},"60":{"q":"अधिकृत आपातकालीन वाहनों के अलावा, चमकती चेतावनी लाइटें दिखाने वाले निम्नलिखित में से किन रुके हुए वाहनों की मिसिसिपी का मूव ओवर कानून (63-3-809) भी रक्षा करता है?","options":["केवल चिह्नित कानून प्रवर्तन वाहनों की","केवल एम्बुलेंस और फायर उपकरणों की","रिकवरी (टो) वाहनों और यूटिलिटी सेवा वाहनों की","केवल राज्य सरकार के स्वामित्व वाले वाहनों की"],"explanation":"Miss. Code 63-3-809 मूव-ओवर/धीमे-होने के कर्तव्य को स्थिर अधिकृत आपातकालीन वाहनों के साथ-साथ अधिकृत चमकती लाइटों का उपयोग करने वाले रिकवरी (टो) और यूटिलिटी सेवा वाहनों तक बढ़ाता है। स्रोत: Mississippi Code 63-3-809."},"61":{"q":"मिसिसिपी के अधिकांश अंतरराज्यीय राजमार्गों पर, मिसिसिपी परिवहन आयोग अधिकतम गति सीमा किस मान से अधिक निर्धारित नहीं कर सकता?","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"Miss. Code 63-3-501 परिवहन आयोग द्वारा अंतरराज्यीय राजमार्ग प्रणाली और चार-या-अधिक-लेन वाले नियंत्रित-पहुँच राजमार्गों पर निर्धारित की जा सकने वाली अधिकतम गति को 70 mph पर सीमित करता है। स्रोत: Mississippi Code 63-3-501."},"62":{"q":"Mississippi Code 63-3-501 के तहत, जहाँ किसी अंतरराज्यीय या चार-लेन वाले U.S. राजमार्ग पर 70 mph की सीमा स्थापित है, वहाँ ऐसे वाहन पर कौन-सी न्यूनतम गति लागू होती है जिस पर 70 mph की अधिकतम गति प्रतिबंध है?","options":["30 mph","40 mph","45 mph","50 mph"],"explanation":"Miss. Code 63-3-501 ऐसे राजमार्गों पर 70 mph की अधिकतम गति प्रतिबंध वाले वाहनों के लिए 40 mph की न्यूनतम गति स्थापित करता है। स्रोत: Mississippi Code 63-3-501."},"63":{"q":"मिसिसिपी कानून के तहत, जब आप किसी रेलमार्ग ग्रेड क्रॉसिंग को पार करने से पहले यात्रियों को ले जा रही बस को रोकते हैं, तो आपको निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["50 फीट के भीतर परंतु 15 फीट से कम नहीं","25 फीट के भीतर परंतु 5 फीट से कम नहीं","75 फीट के भीतर परंतु 25 फीट से कम नहीं","100 फीट के भीतर परंतु 50 फीट से कम नहीं"],"explanation":"Miss. Code 63-3-1011 के अनुसार बसों, किराये पर यात्रियों को ले जाने वाले वाहनों, स्कूल बसों, और विस्फोटक या ज्वलनशील तरल पदार्थ ढोने वाले वाहनों को निकटतम रेल से 50 फीट के भीतर परंतु 15 फीट से कम नहीं की दूरी पर रुकना आवश्यक है। स्रोत: Mississippi Code 63-3-1011."},"64":{"q":"मिसिसिपी CDL मैनुअल के अनुसार, किन वाणिज्यिक वाहनों को रेलमार्ग ग्रेड क्रॉसिंग पर हमेशा रुकना आवश्यक है?","options":["10,000 पाउंड से अधिक वजन वाले सभी वाणिज्यिक वाहन","यात्रियों को ले जाने वाली बसें और प्लेकार्ड किए गए खतरनाक माल ढोने वाले वाहन","केवल ट्रिपल-ट्रेलर संयोजन","किसी भी प्रकार के ट्रेलर को खींचने वाला कोई भी वाहन"],"explanation":"मिसिसिपी CDL मैनुअल (49 CFR 392.10 और Miss. Code 63-3-1011 के अनुरूप) के अनुसार यात्रियों को ले जाने वाली बसों और प्लेकार्ड किए गए हैज़मैट वाहनों को पटरियाँ पार करने से पहले रुकना, फिर देखना और सुनना आवश्यक है। स्रोत: Mississippi CDL Manual / Miss. Code 63-3-1011."},"65":{"q":"मिसिसिपी में रेलमार्ग क्रॉसिंग पर रुकना आवश्यक होने पर, 15-से-50-फीट क्षेत्र के भीतर रुकने के बाद बस या प्लेकार्ड वाहन के चालक को पटरियाँ कैसे पार करनी चाहिए?","options":["जल्दी से, क्रॉसिंग को तेज़ी से पार करने के लिए गियर ऊपर बढ़ाते हुए","ऐसे गियर में जो बिना गियर बदले क्रॉसिंग पूरी करने की अनुमति दे","न्यूट्रल में, क्लच दबाकर लुढ़कते हुए पार करते हुए","केवल तीन बार हॉर्न बजाने के बाद"],"explanation":"मिसिसिपी CDL मैनुअल चालकों को ऐसे गियर में पार करने का निर्देश देता है जो बिना शिफ्ट किए क्रॉसिंग पूरी करने की अनुमति दे, और पटरियों पर रहते हुए गियर न बदलने का। स्रोत: Mississippi CDL Manual (railroad crossings)."},"66":{"q":"मिसिसिपी के स्कूल बस कानून (Nathan's Law, 63-3-615) के तहत, अपनी लाल लाइटें चमकाती और स्टॉप आर्म बाहर निकाली हुई स्कूल बस जो बच्चों को चढ़ा या उतार रही हो, उसके पास सामने से आता या उससे आगे निकलता वाहन कितनी निकटता तक रुक सकता है?","options":["बस से 10 फीट से कम नहीं","बस से 25 फीट से कम नहीं","बस से 50 फीट से कम नहीं","बस से 5 फीट से कम नहीं"],"explanation":"Miss. Code 63-3-615 के अनुसार सामने से आते या आगे निकलते चालकों को बच्चों को चढ़ाने या उतारने के लिए रुकी हुई स्कूल बस से 10 फीट से कम दूरी पर नहीं रुकना चाहिए। स्रोत: Mississippi Code 63-3-615."},"67":{"q":"मिसिसिपी राजमार्ग पर, किस स्थिति में किसी चालक को बच्चों को चढ़ाने या उतारने के लिए रुकी हुई स्कूल बस के लिए रुकने की आवश्यकता नहीं होती?","options":["जब भी चालक किसी भी दो-लेन वाली सड़क पर विपरीत दिशा में यात्रा कर रहा हो","जब बस चार या अधिक लेन वाले विभाजित राजमार्ग की विपरीत सड़क पर रुकी हो, जिसमें विपरीत दिशाओं में कम से कम दो लेन हों","जब भी यातायात भारी हो और रुकना असुविधाजनक हो","जब चालक बस से 100 फीट से अधिक दूर हो"],"explanation":"Miss. Code 63-3-615 चार या अधिक लेन वाले विभाजित राजमार्ग (जो विपरीत दिशाओं में कम से कम दो लेन यातायात की अनुमति देता है) पर चालक को विपरीत सड़क पर रुकी हुई बस के लिए रुकने से छूट देता है। स्रोत: Mississippi Code 63-3-615."},"68":{"q":"Mississippi Code 63-3-615 के तहत, रुकी हुई स्कूल बस को अवैध रूप से पार करने पर पहली बार के अपराध का जुर्माना कितनी राशि से कम नहीं होता?","options":["$100 से कम नहीं","$200 से कम नहीं","$350 से कम नहीं","$1,000 से कम नहीं"],"explanation":"Miss. Code 63-3-615 रुकी हुई स्कूल बस को गैरकानूनी रूप से पार करने पर पहली बार के अपराध का जुर्माना $350 से कम और $750 से अधिक नहीं (और संभावित कारावास) निर्धारित करता है। स्रोत: Mississippi Code 63-3-615."},"69":{"q":"मिसिसिपी के लेन-उपयोग नियमों के तहत, यातायात की सामान्य गति से धीमे चलने वाले वाणिज्यिक वाहन को बहु-लेन वाले राजमार्ग पर कहाँ चलाया जाना चाहिए?","options":["दाहिनी ओर की लेन में या सड़क के दाहिने किनारे के यथासंभव निकट","हर समय बीच वाली लेन में","विलय करने वाले यातायात से दूर रहने के लिए बायीं ओर की लेन में","जिस भी लेन में सबसे कम यातायात हो"],"explanation":"Miss. Code 63-3-603 के अनुसार यातायात की सामान्य गति से कम चलने वाले वाहन को, पार करने या बायें मुड़ने की तैयारी के समय को छोड़कर, दाहिनी ओर की लेन का उपयोग करना चाहिए या दाहिने किनारे के यथासंभव निकट रहना चाहिए। स्रोत: Mississippi Code 63-3-603."},"70":{"q":"बहु-लेन वाली सड़क की सबसे बायीं ओर की लेन में लगातार गाड़ी चलाने के बारे में Mississippi Code 63-3-603 क्या कहता है?","options":["यह ट्रकों के लिए अनुमत है परंतु कारों के लिए निषिद्ध है","यह तब निषिद्ध है जब भी इससे अन्य यातायात के प्रवाह में बाधा आती हो","यह 26,000 पाउंड से अधिक के सभी वाहनों के लिए आवश्यक है","यह किसी भी समय अनुमत है बशर्ते आप पहले संकेत दें"],"explanation":"Miss. Code 63-3-603 बहु-लेन वाली सड़क की सबसे बाहरी बायीं लेन में लगातार गाड़ी चलाने को तब निषिद्ध करता है जब भी ऐसा करने से अन्य यातायात के प्रवाह में बाधा आती है। स्रोत: Mississippi Code 63-3-603."},"71":{"q":"मिसिसिपी CDL मैनुअल के अनुसार, जब आपका वाणिज्यिक वाहन किसी एक-तरफ़ा या विभाजित राजमार्ग के किनारे पर रुका हो, तो आप अपने तीन चेतावनी त्रिकोण कहाँ रखते हैं?","options":["आते हुए यातायात की ओर 10, 100, और 200 फीट पर (सभी पीछे की ओर)","25 फीट आगे, वाहन के पास, और 25 फीट पीछे","एक वाहन के पास और दो 50 फीट पीछे अगल-बगल","वाहन के आगे और पीछे दोनों ओर 10, 100, और 200 फीट पर"],"explanation":"मिसिसिपी CDL मैनुअल (49 CFR 392.22 के अनुसार) एक-तरफ़ा या विभाजित राजमार्ग पर आते हुए यातायात की ओर 10, 100, और 200 फीट पर त्रिकोण रखने का निर्देश देता है। स्रोत: Mississippi CDL Manual / 49 CFR 392.22."},"72":{"q":"मिसिसिपी CDL मैनुअल के अनुसार, दोनों दिशाओं में यातायात ले जाने वाली दो-लेन वाली अविभाजित सड़क पर, रुके हुए वाणिज्यिक वाहन के लिए चेतावनी उपकरण कहाँ रखे जाने चाहिए?","options":["तीनों वाहन के पीछे 10 फीट के भीतर","वाहन के 10 फीट के भीतर, साथ ही 100 फीट पीछे और 100 फीट आगे","केवल एक उपकरण, वाहन के 200 फीट पीछे","वाहन के 50 फीट और 500 फीट पीछे"],"explanation":"मिसिसिपी CDL मैनुअल (49 CFR 392.22 के अनुसार) दो-लेन वाली दो-तरफ़ा सड़क पर वाहन के 10 फीट के भीतर एक उपकरण और लगभग 100 फीट पीछे तथा 100 फीट आगे उपकरण रखने की आवश्यकता निर्धारित करता है। स्रोत: Mississippi CDL Manual / 49 CFR 392.22."},"73":{"q":"मिसिसिपी CDL मैनुअल के अनुसार, किसी वाणिज्यिक वाहन के सड़क या किनारे पर रुकने के बाद, चालक को कितने समय के भीतर आपातकालीन चेतावनी उपकरण लगाने चाहिए?","options":["5 सेकंड के भीतर","10 मिनट के भीतर","30 मिनट के भीतर","1 घंटे के भीतर"],"explanation":"मिसिसिपी CDL मैनुअल (49 CFR 392.22 के अनुसार) रुकने के 10 मिनट के भीतर चेतावनी उपकरण रखने की आवश्यकता निर्धारित करता है; हैज़र्ड फ्लैशर्स का उपयोग तुरंत और त्रिकोण लगाए जाने तक किया जाता है। स्रोत: Mississippi CDL Manual / 49 CFR 392.22."},"74":{"q":"राज्य भर में तिरछे चलने वाला कौन-सा मिसिसिपी मार्ग वाणिज्यिक ट्रकों (एक-टन से अधिक निर्धारित क्षमता वाले) को इसका उपयोग करने से प्रतिबंधित करता है?","options":["Interstate 55","U.S. Highway 49","The Natchez Trace Parkway","Interstate 20"],"explanation":"The Natchez Trace Parkway, एक संघीय रूप से प्रशासित दर्शनीय मार्ग, वाणिज्यिक वाहनों और एक-टन से अधिक निर्धारित क्षमता वाले ट्रकों पर प्रतिबंध लगाता है। स्रोत: 36 CFR 7.43 / National Park Service."},"75":{"q":"मिसिसिपी में, ओवरसाइज़ परमिट की आवश्यकता पड़ने से पहले निर्दिष्ट राजमार्गों पर अनुमत अधिकतम कानूनी वाहन चौड़ाई क्या है?","options":["8 फीट 0 इंच","8 फीट 6 इंच","9 फीट 0 इंच","10 फीट 0 इंच"],"explanation":"निर्दिष्ट राजमार्गों पर मिसिसिपी की कानूनी अधिकतम चौड़ाई 8 फीट 6 इंच है; इससे अधिक चौड़े भार के लिए ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Mississippi DOT oversize/overweight permit rules."},"76":{"q":"मिसिसिपी में, ओवरवेट परमिट की आवश्यकता पड़ने से पहले अंतरराज्यीय प्रणाली पर अधिकतम कानूनी सकल वाहन वजन क्या है?","options":["73,280 पाउंड","80,000 पाउंड","88,000 पाउंड","100,000 पाउंड"],"explanation":"मिसिसिपी अंतरराज्यीय प्रणाली पर अधिकतम कानूनी सकल वजन की 80,000 पाउंड की संघीय सीमा का पालन करता है; इससे अधिक होने पर MDOT से ओवरवेट परमिट की आवश्यकता होती है। स्रोत: Mississippi DOT overweight permit rules."},"77":{"q":"मिसिसिपी में कौन-सी एजेंसी वाणिज्यिक चालक लाइसेंस जारी करती है और राज्य में CDL परीक्षण का संचालन करती है?","options":["Mississippi Department of Public Safety (DPS), अपने Driver Service Bureau के माध्यम से","Mississippi Department of Transportation (MDOT)","जिस काउंटी में चालक रहता है वहाँ का Circuit Clerk का कार्यालय","Federal Motor Carrier Safety Administration (FMCSA)"],"explanation":"मिसिसिपी CDL, Mississippi Department of Public Safety (DPS) द्वारा अपने Driver Service Bureau के माध्यम से जारी किए जाते हैं और CDL परीक्षण संचालित किए जाते हैं। MDOT सड़कों और परमिटों को संभालता है, लाइसेंसिंग को नहीं, और FMCSA संघीय मानक निर्धारित करता है परंतु राज्य लाइसेंस जारी नहीं करता। स्रोत: MS DPS Driver Service Bureau; Miss. Code Title 63, Chapter 1."},"78":{"q":"मिसिसिपी CDL ज्ञान (लिखित) परीक्षाओं में न्यूनतम उत्तीर्ण अंक क्या है?","options":["80%","70%","75%","90%"],"explanation":"मिसिसिपी प्रत्येक आवश्यक CDL ज्ञान परीक्षा में न्यूनतम 80% अंक की आवश्यकता रखता है, जो संघीय AAMVA परीक्षण मानक के अनुरूप है। स्रोत: MS DPS / Mississippi CDL Manual."},"79":{"q":"पहली बार के मिसिसिपी CDL आवेदक को आवश्यक ज्ञान या कौशल परीक्षण देने से पहले कौन-सा प्रशिक्षण पूरा करना आवश्यक है?","options":["FMCSA-पंजीकृत प्रशिक्षण प्रदाता से Entry-Level Driver Training (ELDT)","MDOT द्वारा अनुमोदित एक रक्षात्मक ड्राइविंग पाठ्यक्रम","किसी सामुदायिक कॉलेज में 40-घंटे का कक्षा पाठ्यक्रम","Mississippi Trucking Association के साथ दर्ज की गई एक प्रशिक्षुता"],"explanation":"7 फरवरी 2022 से, पहली बार के CDL आवेदकों को आवश्यक कौशल या ज्ञान परीक्षण देने से पहले FMCSA की Training Provider Registry में सूचीबद्ध प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना आवश्यक है। स्रोत: MS DPS Driver Service Bureau; FMCSA ELDT rule (49 CFR Part 380)."},"80":{"q":"CDL कौशल परीक्षण देने से पहले मिसिसिपी Commercial Learner's Permit (CLP) को कितने समय तक धारण करना आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 10 दिन","कम से कम 60 दिन"],"explanation":"मिसिसिपी उस संघीय नियम का पालन करता है जिसके अनुसार CLP धारक के CDL कौशल परीक्षण के लिए पात्र होने से पहले CLP को न्यूनतम 14 दिन तक धारण करना आवश्यक है। स्रोत: MS DPS Driver Service Bureau; 49 CFR 383.25."},"81":{"q":"मिसिसिपी Commercial Learner's Permit (CLP) कितने समय तक वैध रहता है?","options":["6 महीने","1 वर्ष","30 दिन","90 दिन"],"explanation":"मिसिसिपी CLP 6 महीने (180 दिन) तक वैध रहता है, जो CLP वैधता की संघीय अधिकतम अवधि के अनुरूप है। स्रोत: MS DPS Driver Service Bureau; 49 CFR 383.25."},"82":{"q":"मिसिसिपी CDL कौशल परीक्षण में क्रम से किए जाने वाले कौन-से तीन भाग होते हैं?","options":["यात्रा-पूर्व वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","लिखित ज्ञान परीक्षण, एयर ब्रेक परीक्षण, और सड़क पर ड्राइविंग","यात्रा-पूर्व निरीक्षण, हैज़मैट संचालन, और रात में ड्राइविंग","बुनियादी वाहन नियंत्रण, कपलिंग/अनकपलिंग, और एक लिखित एंडोर्समेंट परीक्षा"],"explanation":"मिसिसिपी CDL कौशल परीक्षण के तीन भाग होते हैं: यात्रा-पूर्व वाहन निरीक्षण, बुनियादी वाहन नियंत्रण कौशल परीक्षण, और सड़क पर ड्राइविंग परीक्षण। तीनों को उत्तीर्ण करना आवश्यक है। स्रोत: MS DPS / Mississippi CDL Manual."},"83":{"q":"मिसिसिपी वाणिज्यिक चालक लाइसेंस के नवीनीकरण की आवश्यकता पड़ने से पहले उसकी अवधि (वैधता अवधि) क्या है?","options":["5 वर्ष, लाइसेंसधारी के जन्मदिन पर समाप्त होती हुई","4 वर्ष, लाइसेंसधारी के जन्मदिन पर समाप्त होती हुई","8 वर्ष, लाइसेंसधारी के जन्मदिन पर समाप्त होती हुई","2 वर्ष, चिकित्सा प्रमाणपत्र से जुड़ी हुई"],"explanation":"मिसिसिपी CDL पाँच-वर्षीय अवधि के लिए जारी किया जाता है और लाइसेंसधारी के जन्मदिन की मध्यरात्रि को समाप्त हो जाता है। स्रोत: Miss. Code Ann. Sec. 63-1-47 (and Sec. 63-1-211)."},"84":{"q":"मिसिसिपी CDL धारक अपनी समाप्ति तिथि से कितनी जल्दी लाइसेंस का नवीनीकरण कर सकता है?","options":["समाप्ति से पहले 6 महीने के भीतर किसी भी समय","केवल समाप्ति से पहले 30 दिनों के भीतर","समाप्ति से पहले 90 दिनों के भीतर किसी भी समय","केवल समाप्ति तिथि को या उसके बाद"],"explanation":"मिसिसिपी, जब तक पुनः परीक्षा की आवश्यकता न हो, आवेदन करने और आवश्यक शुल्क के भुगतान पर लाइसेंस की समाप्ति से पहले छह (6) महीनों के भीतर किसी भी समय नवीनीकरण की अनुमति देता है। स्रोत: Miss. Code Ann. Sec. 63-1-47."},"85":{"q":"जब कोई CDL आवेदक मिसिसिपी DPS के साथ अपनी ड्राइविंग के प्रकार का स्व-प्रमाणन करता है, तो चुनने के लिए कितनी स्व-प्रमाणन श्रेणियाँ उपलब्ध होती हैं?","options":["चार","दो","तीन","पाँच"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं: Non-Excepted Interstate, Excepted Interstate, Non-Excepted Intrastate, और Excepted Intrastate। आवेदक को ठीक एक चुनना आवश्यक है। स्रोत: MS DPS Driver Service Bureau Self-Certification; 49 CFR 383.71(b)."},"86":{"q":"मिसिसिपी में कौन-सी स्व-प्रमाणन श्रेणी ऐसे चालक पर लागू होती है जो राज्य की सीमाओं के पार वाहन चलाता है और जिसके लिए सभी संघीय चिकित्सा योग्यता मानकों को पूरा करना आवश्यक है?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Interstate (NI) चालक अंतरराज्यीय वाणिज्य में वाहन चलाते हैं, उन्हें सभी संघीय DOT चिकित्सा आवश्यकताओं को पूरा करना चाहिए, और एक वर्तमान चिकित्सा परीक्षक का प्रमाणपत्र फ़ाइल में रखना चाहिए। स्रोत: MS DPS Self-Certification categories; 49 CFR 383.71(b)."},"87":{"q":"जो मिसिसिपी चालक Non-Excepted Interstate के रूप में स्व-प्रमाणन करता है, उसे वैध CDL बनाए रखने के लिए DPS के साथ फ़ाइल में क्या रखना आवश्यक है?","options":["एक वर्तमान DOT चिकित्सा परीक्षक का प्रमाणपत्र","एक वर्तमान वाणिज्यिक सामान्य देयता बीमा प्रमाणपत्र","हर छह महीने में एक नवीनीकृत CLP","एक MDOT ओवरसाइज़/ओवरवेट परमिट"],"explanation":"Non-Excepted Interstate (और Non-Excepted Intrastate) चालकों को DPS के रिकॉर्ड में एक वर्तमान DOT चिकित्सा परीक्षक का प्रमाणपत्र बनाए रखना आवश्यक है; ऐसा न करने पर डाउनग्रेड होता है। स्रोत: MS DPS Medical Certification Requirements; 49 CFR 383.71/383.73."},"88":{"q":"23 जून 2025 से प्रभावी, CDL चालक का DOT चिकित्सा परीक्षा परिणाम मिसिसिपी DPS को कैसे प्रेषित किया जाता है?","options":["प्रमाणित चिकित्सा परीक्षक इसे इलेक्ट्रॉनिक रूप से FMCSA की National Registry में जमा करता है, जो इसे DPS को प्रेषित करती है","चालक Form MCSA-5876 की एक कागज़ी प्रति DPS मुख्यालय को डाक से भेजता है","चालक DPS ऑनलाइन पोर्टल के माध्यम से एक स्कैन की हुई प्रति अपलोड करता है","नियोक्ता स्थानीय DPS चालक लाइसेंस स्टेशन को एक प्रति फैक्स करता है"],"explanation":"23 जून 2025 से प्रभावी FMCSA अंतिम नियम के तहत, प्रमाणित चिकित्सा परीक्षक परीक्षा परिणाम इलेक्ट्रॉनिक रूप से National Registry को जमा करते हैं, जो उन्हें राज्य को प्रेषित करती है; मिसिसिपी परिणाम को सीधे चालक रिकॉर्ड पर पोस्ट करता है। स्रोत: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule."},"89":{"q":"23 जून 2025 के संघीय परिवर्तन के बाद, क्या कोई मिसिसिपी चालक लाइसेंस स्टेशन Medical Examiner's Certificate (Form MCSA-5876) की कागज़ी या स्कैन की हुई प्रति स्वीकार कर सकता है?","options":["नहीं; कागज़ी और स्कैन की हुई प्रतियाँ अब स्वीकार नहीं की जातीं, क्योंकि परिणाम National Registry से इलेक्ट्रॉनिक रूप से आते हैं","हाँ; कागज़ी प्रतियाँ जमा करने की प्राथमिक विधि बनी रहती हैं","हाँ, परंतु केवल यदि परीक्षा के 15 दिनों के भीतर नोटरीकृत हो","हाँ, परंतु केवल अंतर्राज्यीय (NA) चालकों के लिए"],"explanation":"23 जून 2025 से, DPS स्टेशन भौतिक या स्कैन की हुई MCSA-5876 प्रतियाँ अब स्वीकार नहीं करते; चिकित्सा परीक्षा परिणाम FMCSA की National Registry से इलेक्ट्रॉनिक रूप से प्राप्त होना चाहिए। स्रोत: MS DPS Medical Certification Requirements; FMCSA Medical Examiner's Certification Integration final rule."},"90":{"q":"मिसिसिपी जिस FMCSA नियम का पालन करता है, उसके तहत प्रमाणित चिकित्सा परीक्षक को CDL चालक का परीक्षा परिणाम National Registry में कब तक अपलोड करना आवश्यक है?","options":["परीक्षा के बाद अगले कैलेंडर दिन के अंत तक","परीक्षा के 30 दिनों के भीतर","परीक्षा के 14 दिनों के भीतर","उसी व्यावसायिक सप्ताह के अंत तक"],"explanation":"23 जून 2025 से प्रभावी नियम के तहत, प्रमाणित चिकित्सा परीक्षक को परीक्षा परिणाम परीक्षा के बाद अगले कैलेंडर दिन की मध्यरात्रि तक National Registry में इलेक्ट्रॉनिक रूप से अपलोड करना आवश्यक है। स्रोत: FMCSA Medical Examiner's Certification Integration final rule, applied by MS DPS."},"91":{"q":"यदि कोई non-excepted चालक अपने DOT चिकित्सा प्रमाणन को समाप्त होने देता है और उसे अद्यतन नहीं करता, तो मिसिसिपी CDL का क्या होता है?","options":["DPS CDL को डाउनग्रेड कर देता है, और प्रमाणन बहाल होने तक वाणिज्यिक ड्राइविंग विशेषाधिकार हटा देता है","CDL स्थायी रूप से रद्द कर दिया जाता है और बहाल नहीं किया जा सकता","अगले 5-वर्षीय नवीनीकरण तक कुछ नहीं बदलता","चालक को स्वतः Excepted Interstate के रूप में पुनर्वर्गीकृत कर दिया जाता है"],"explanation":"जो non-excepted चालक चिकित्सा प्रमाणन को वर्तमान नहीं रखता, उसे \"not-certified\" में बदल दिया जाता है, और राज्य CDL को डाउनग्रेड कर देता है, जिससे वैध प्रमाणन फिर से फ़ाइल में आने तक वाणिज्यिक विशेषाधिकार हट जाते हैं। स्रोत: MS DPS Medical Certification Requirements; 49 CFR 383.73."},"92":{"q":"किसी DPS कार्यालय में नए मिसिसिपी CDL के लिए आवेदन करते समय आमतौर पर कौन-से दस्तावेज़ आवश्यक होते हैं?","options":["पहचान/जन्म का प्रमाण, Social Security number, और मिसिसिपी निवास के दो प्रमाण","केवल एक पासपोर्ट, बिना किसी अन्य दस्तावेज़ की आवश्यकता के","एक हाई स्कूल डिप्लोमा और तीन व्यक्तिगत संदर्भ","केवल एक वाहन शीर्षक और वाणिज्यिक ऑटो बीमा का प्रमाण"],"explanation":"नए CDL आवेदक को पहचान का प्रमाण (जैसे जन्म प्रमाणपत्र), Social Security number का प्रमाण, और मिसिसिपी निवास के दो प्रमाण प्रस्तुत करने होंगे, साथ ही आवश्यक परीक्षाएँ उत्तीर्ण करनी होंगी। स्रोत: MS DPS Driver Service Bureau new CDL requirements."},"93":{"q":"अंतर्राज्यीय (राज्य के भीतर) वाणिज्यिक ड्राइविंग तक सीमित मिसिसिपी CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"एक चालक 18 वर्ष की आयु में अंतर्राज्यीय संचालन के लिए CDL प्राप्त कर सकता है, परंतु अंतरराज्यीय संचालन और खतरनाक माल के परिवहन के लिए 21 वर्ष का होना आवश्यक है। स्रोत: MS DPS / Mississippi CDL Manual; 49 CFR 383.3 / 391.11."},"94":{"q":"अंतरराज्यीय ड्राइविंग या प्लेकार्ड किए गए खतरनाक माल के परिवहन के लिए मिसिसिपी CDL प्राप्त करने हेतु न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","23 वर्ष","19 वर्ष"],"explanation":"मिसिसिपी द्वारा अपनाए गए संघीय नियमों के अनुसार चालक को अंतरराज्यीय वाणिज्य में संचालन करने और प्लेकार्ड किए गए खतरनाक माल का परिवहन करने के लिए कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: MS DPS / Mississippi CDL Manual; 49 CFR 391.11."},"95":{"q":"DPS परीक्षकों के अलावा और कौन कानूनी रूप से मिसिसिपी CDL कौशल (सड़क) परीक्षण ले सकता है?","options":["राज्य-अनुमोदित Third-Party Testers/परीक्षक","दो वर्षों के अनुभव वाला कोई भी लाइसेंस प्राप्त CDL धारक","आवेदक के संभावित नियोक्ता का सुरक्षा प्रबंधक","कोई भी FMCSA-पंजीकृत ELDT कक्षा प्रशिक्षक"],"explanation":"मिसिसिपी CDL कौशल परीक्षण को या तो DPS परीक्षकों द्वारा या DPS द्वारा बनाए गए सूची से राज्य-अनुमोदित Third-Party Testers द्वारा दिए जाने की अनुमति देता है। स्रोत: MS DPS Driver Service Bureau (Third-Party Tester program); 49 CFR 383.75."},"96":{"q":"कोई मिसिसिपी आवेदक CDL कौशल परीक्षण के केवल सड़क-पर वाले भाग में विफल रहता है परंतु यात्रा-पूर्व निरीक्षण और बुनियादी नियंत्रण वाले भागों को उत्तीर्ण कर लेता है। सामान्य परिणाम क्या होता है?","options":["आवेदक को सड़क-पर वाला भाग दोबारा देना होगा और उसे अभी CDL नहीं मिलता","आवेदक को स्वतः एक प्रतिबंधित अंतर्राज्यीय CDL मिल जाता है","तीनों कौशल भाग शुरुआत से दोबारा देने होंगे","आवेदक को CDL जारी कर दिया जाता है क्योंकि तीन में से दो भाग उत्तीर्ण हो गए"],"explanation":"CDL जारी करने के लिए तीनों कौशल घटकों (यात्रा-पूर्व निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग) को उत्तीर्ण करना आवश्यक है; किसी एक भाग में विफल रहने का अर्थ है कि उसे दोबारा देना होगा और जब तक सभी उत्तीर्ण न हों तब तक CDL जारी नहीं होता। स्रोत: MS DPS / Mississippi CDL Manual; 49 CFR 383.113."}},"ar":{"0":{"q":"على طرق ميسيسيبي السريعة، ما هو الحد الأقصى القانوني لعرض المركبة التجارية (باستثناء أجهزة السلامة المطلوبة والمرايا)؟","options":["8 أقدام و0 بوصة (96 بوصة)","8 أقدام و6 بوصات (102 بوصة)","9 أقدام و0 بوصة (108 بوصة)","10 أقدام و0 بوصة (120 بوصة)"],"explanation":"تحدد ميسيسيبي عرض المركبة بـ 8 أقدام و6 بوصات (102 بوصة)؛ ويتطلب الحمل الأعرض من ذلك تصريح حمولة زائدة الأبعاد. المصدر: Miss. Code Ann. Sec. 63-5-13 (العرض الخارجي للمركبات)؛ قواعد تصاريح مكتب الإنفاذ في MDOT."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك أي حمل، على طرق ميسيسيبي السريعة؟","options":["14 قدمًا و6 بوصات","14 قدمًا و0 بوصة","12 قدمًا و6 بوصات","13 قدمًا و6 بوصات"],"explanation":"لا يجوز لأي مركبة، فارغة أو محمّلة، أن تتجاوز ارتفاعًا قدره 13 قدمًا و6 بوصات في ميسيسيبي. المصدر: Miss. Code Ann. Sec. 63-5-17 (ارتفاع المركبات)."},"2":{"q":"في ميسيسيبي، ما هو الحد الأقصى للوزن الإجمالي (بدون أي هامش تسامح) لمركبة أو مجموعة مركبات تعمل بدون تصريح خاص؟","options":["73,280 رطلًا","76,000 رطل","80,000 رطل","88,000 رطل"],"explanation":"الحد الأقصى للوزن الإجمالي للمركبة بدون تصريح هو 80,000 رطل (وقد ينطبق هامش تسامح قدره 2% فوق ذلك). المصدر: Miss. Code Ann. Sec. 63-5-33؛ قوانين الوزن الأقصى في ميسيسيبي الصادرة عن MDOT."},"3":{"q":"ما هو الحد الأقصى للوزن الإجمالي الذي تسمح به ميسيسيبي على المحور الواحد؟","options":["24,000 رطل","22,400 رطلًا","18,000 رطل","20,000 رطل"],"explanation":"لا يجوز أن يتجاوز الوزن الإجمالي على أي محور مفرد واحد 20,000 رطل (باستثناء هامش التسامح القانوني). المصدر: Miss. Code Ann. Sec. 63-5-27 (أحمال العجلات والمحاور)؛ قوانين الوزن الأقصى في MDOT."},"4":{"q":"ما هو الحد الأقصى للوزن الإجمالي الذي تسمح به ميسيسيبي على المحور المزدوج؟","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"لا يجوز أن يتجاوز الوزن الإجمالي على أي محور مزدوج 34,000 رطل (باستثناء هامش التسامح القانوني). المصدر: Miss. Code Ann. Sec. 63-5-27؛ قوانين الوزن الأقصى في MDOT."},"5":{"q":"بموجب قانون ميسيسيبي، كيف يُعرَّف 'المحور المفرد' لأغراض الوزن؟","options":["أي محورين متتاليين تفصل بينهما مسافة تزيد على 40 بوصة","محوران أو أكثر متباعدان بمسافة 96 بوصة بالضبط","مجموعة عجلة وإطار واحدة على كل جانب من المركبة","عجلتان أو أكثر في مستوى عرضي واحد، أو ضمن مستويين متوازيين تفصل بينهما 40 بوصة"],"explanation":"المحور المفرد هو مجموعة من عجلتين أو أكثر تقع مراكزها في مستوى رأسي عرضي واحد، أو تقع بين مستويين عرضيين متوازيين تفصل بينهما 40 بوصة، عبر العرض الكامل للمركبة. المصدر: Miss. Code Ann. Sec. 63-5-27؛ قوانين الوزن الأقصى في MDOT."},"6":{"q":"كيف يُعرِّف قانون ميسيسيبي 'المحور المزدوج' لأغراض الوزن؟","options":["محوران متتاليان أو أكثر تكون المسافة بين مراكزها أكثر من 40 بوصة ولكن ليس أكثر من 96 بوصة","محوران تفصل بين مركزيهما 40 بوصة بالضبط","أي مجموعة محاور تمتد لأكثر من 96 بوصة","محوران أحدهما محور قيادة والآخر محور توجيه"],"explanation":"المحور المزدوج هو أي محورين متتاليين أو أكثر تكون المسافة بين مراكزها أكثر من 40 بوصة ولكن ليس أكثر من 96 بوصة، ولا يجوز أن يتجاوز أي محور واحد من المجموعة حد المحور المفرد. المصدر: Miss. Code Ann. Sec. 63-5-27؛ قوانين الوزن الأقصى في MDOT."},"7":{"q":"على طرق ميسيسيبي السريعة، ما هو الحد الأقصى لطول الشاحنة المفردة (المستقيمة)؟","options":["40 قدمًا","45 قدمًا","48 قدمًا","53 قدمًا"],"explanation":"لا يجوز أن تتجاوز أي مركبة مفردة (شاحنة مستقيمة) طولًا إجماليًا قدره 40 قدمًا في ميسيسيبي. المصدر: Miss. Code Ann. Sec. 63-5-19 (قيود طول المركبة)."},"8":{"q":"ما هو الحد الأقصى لطول نصف المقطورة العاملة ضمن مجموعة جرّار شاحنة/نصف مقطورة في ميسيسيبي؟","options":["48 قدمًا","53 قدمًا","57 قدمًا","60 قدمًا"],"explanation":"لا يجوز أن تتجاوز نصف المقطورة العاملة ضمن مجموعة جرّار شاحنة/نصف مقطورة 53 قدمًا في ميسيسيبي. المصدر: Miss. Code Ann. Sec. 63-5-19 (قيود طول المركبة)."},"9":{"q":"لتحديد الوزن الأقصى على أي مجموعة من محورين متتاليين أو أكثر، ما المعيار الذي تطبقه ميسيسيبي؟","options":["حد أقصى ثابت قدره 80,000 رطل بغض النظر عن التباعد","صيغة الجسور الفيدرالية (الوزن مرتبط بتباعد المحاور)","قاعدة 550 رطلًا لكل بوصة من عرض الإطار فقط","جدول تسامح تصريح الحصاد"],"explanation":"تستخدم ميسيسيبي صيغة الجسور الفيدرالية، لذا يعتمد الوزن المسموح به على مجموعة محاور على المسافة بين المحورين الأقصى للمجموعة. المصدر: جداول الوزن في Miss. Code Ann. Sec. 63-5-29/63-5-33؛ قوانين الوزن الأقصى في MDOT."},"10":{"q":"يجوز تجاوز الحد الأقصى للوزن الإجمالي في ميسيسيبي البالغ 80,000 رطل بأي هامش تسامح قانوني لمركبة تعمل بدون تصريح حصاد؟","options":["10%","5%","1%","2%"],"explanation":"لا يجوز أن يتجاوز الحد الأقصى للوزن الإجمالي للمركبة 80,000 رطل زائدًا هامش تسامح لا يزيد على 2%. المصدر: Miss. Code Ann. Sec. 63-5-33."},"11":{"q":"ما هو هامش التسامح في الوزن الذي تسمح به ميسيسيبي لمركبة تعمل بتصريح حصاد، فوق وزنها الإجمالي أو المزدوج أو المحوري المصرّح به؟","options":["2%","5%","10%","15%"],"explanation":"يُسمح لمركبة تصريح الحصاد بهامش تسامح لا يتجاوز 10% فوق وزنها الإجمالي أو المزدوج أو المحوري المصرّح به (مع مراعاة الحد الأقصى البالغ 88,000 رطل). المصدر: Miss. Code Ann. Sec. 63-5-33."},"12":{"q":"أي جهة في ميسيسيبي تصدر تصاريح الحمولة زائدة الحجم/زائدة الوزن (زائدة الأبعاد)؟","options":["وزارة النقل في ميسيسيبي، شعبة تصاريح مكتب الإنفاذ","وزارة السلامة العامة في ميسيسيبي، خدمات السائقين","لجنة الضرائب الحكومية في ميسيسيبي","مأمور المقاطعة في مقاطعة المنشأ"],"explanation":"تُصدَر تصاريح زائدة الأبعاد من قِبل شعبة التصاريح في مكتب الإنفاذ بـ MDOT، بموجب صلاحية لجنة النقل في ميسيسيبي. المصدر: قواعد تصاريح زائدة الأبعاد في MDOT (Sub-Part 6601, Chapter 03001)؛ Miss. Code Ann. Sec. 65-1-8."},"13":{"q":"في ميسيسيبي، يأذن تصريح الرحلة الواحدة لزائدة الأبعاد بالحركة لمدة لا تتجاوز كم؟","options":["24 ساعة","ثلاثة أيام متتالية","سبعة أيام متتالية","ثلاثين يومًا"],"explanation":"يأذن تصريح الرحلة الواحدة بحركة مركبة/حمل محدد لمدة لا تتجاوز ثلاثة (3) أيام متتالية. المصدر: قواعد تصاريح زائدة الأبعاد في MDOT، Sec. 213 (التعريفات)."},"14":{"q":"يُطلَب عادةً من الحمل غير القابل للتقسيم الحصول على تصريح حمولة زائدة الحجم في ميسيسيبي بمجرد أن يتجاوز عرضه أي بُعد؟","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","10 أقدام و0 بوصة","12 قدمًا و0 بوصة"],"explanation":"يُطلَب تصريح لنقل حمل يتجاوز حد العرض القانوني البالغ 8 أقدام و6 بوصات (102 بوصة). المصدر: Miss. Code Ann. Sec. 63-5-13؛ قواعد تصاريح مكتب الإنفاذ في MDOT."},"15":{"q":"بموجب قواعد تصاريح زائدة الأبعاد في ميسيسيبي، عند أي عرض للحمل تبدأ متطلبات 'ساعات النهار' الأكثر صرامة ومتطلبات المرافقة؟","options":["عرض أكبر من 12 قدمًا","عرض أكبر من 10 أقدام","عرض أكبر من 14 قدمًا","عرض أكبر من 16 قدمًا"],"explanation":"بالنسبة للأحمال التي يزيد عرضها على 12 قدمًا، تتشدد 'ساعات النهار' لتصبح من 30 دقيقة بعد شروق الشمس إلى 30 دقيقة قبل غروبها وتنطبق متطلبات مرافقة إضافية. المصدر: قواعد تصاريح زائدة الأبعاد في MDOT، Sec. 200."},"16":{"q":"تحدد ميسيسيبي أوزان المحاور المفردة والمزدوجة بحيث لا يتجاوز الوزن الإجمالي كم رطلًا لكل بوصة من عرض الإطار (مع مراعاة الحدود القصوى للمحاور)؟","options":["650 رطلًا لكل بوصة","600 رطل لكل بوصة","500 رطل لكل بوصة","550 رطلًا لكل بوصة"],"explanation":"لا يجوز أن يتجاوز الوزن الإجمالي للمحور المفرد أو المزدوج 550 رطلًا لكل بوصة من عرض الإطار (مع هامش تسامح يصل إلى 500 رطل)، على ألا يتجاوز أبدًا الحدود القصوى للمحاور البالغة 20,000/34,000 رطل. المصدر: Miss. Code Ann. Sec. 63-5-27؛ قوانين الوزن الأقصى في MDOT."},"17":{"q":"على الطرق السريعة لولاية ميسيسيبي (باستثناء نظام الطرق السريعة بين الولايات)، تُعامَل المركبة المسجلة التي تقيس أكثر من 29 قدمًا بين محوريها الأقصى، لأغراض الوزن بصيغة الجسور، كما لو أن مجموعة المحاور تلك أطول بكم؟","options":["أطول بـ 6 أقدام","أطول بـ 12 قدمًا","أطول بـ 20 قدمًا","أطول بـ 29 قدمًا"],"explanation":"بموجب نص Sec. 63-5-34 الخاص بالطرق السريعة للولاية فقط، تُعتبر هذه المركبة كأن مجموعة محاورها الأقصى متباعدة بمقدار 12 قدمًا أطول من قياسها الفعلي (لا ينطبق هذا على نظام الطرق السريعة الفيدرالي بين الولايات). المصدر: Miss. Code Ann. Sec. 63-5-34؛ قوانين الوزن الأقصى في MDOT."},"18":{"q":"لكي تحمل مجموعتان متتاليتان من المحاور المزدوجة كل منهما 34,000 رطل (دون تجاوز 80,000 رطل إجمالي) في ميسيسيبي، يجب أن تكون المسافة بين المحورين الأول والأخير للمجموعتين على الأقل كم؟","options":["30 قدمًا","34 قدمًا","36 قدمًا","40 قدمًا"],"explanation":"يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما 34,000 رطل بشرط أن تكون المسافة الإجمالية بين المحورين الأول والأخير 36 قدمًا أو أكثر، مع ألا يتجاوز الوزن الإجمالي 80,000 رطل إلا كما تسمح Sec. 63-5-33. المصدر: قوانين الوزن الأقصى في MDOT (ملاحظة الجدول III)؛ Miss. Code Ann. Sec. 63-5-33."},"19":{"q":"في ميسيسيبي، ما هو الحد الأدنى لعتبة تصنيف الوزن الإجمالي للمركبة (GVWR) الذي يضع مركبة تجارية مفردة في فئة Class A أو Class B؟","options":["26,001 رطلًا أو أكثر","10,001 رطلًا أو أكثر","18,001 رطلًا أو أكثر","33,001 رطلًا أو أكثر"],"explanation":"تُعرّف ميسيسيبي Class B بأنها أي مركبة مفردة بتصنيف GVWR قدره 26,001 رطلًا أو أكثر، وClass A بأنها مجموعة مركبات بتصنيف GVWR قدره 26,001 رطلًا أو أكثر (تجر وحدة يزيد وزنها على 10,000 رطل). المصدر: Mississippi DPS Driver Service Bureau، صفحة فئات CDL من A إلى D؛ دليل CDL في ميسيسيبي."},"20":{"q":"أي فئة CDL في ميسيسيبي مطلوبة لتشغيل أي مجموعة مركبات بتصنيف GVWR قدره 26,001 رطلًا أو أكثر، حيث تكون المركبة المسحوبة بتصنيف GVWR يزيد على 10,000 رطل؟","options":["Class B","Class A","Class C","Class D"],"explanation":"تغطي فئة Class A في ميسيسيبي مجموعات المركبات بتصنيف GVWR قدره 26,001 رطلًا أو أكثر التي تجر وحدة بتصنيف GVWR يزيد على 10,000 رطل. المصدر: Mississippi DPS Driver Service Bureau، فئات CDL من A إلى D؛ دليل CDL في ميسيسيبي."},"21":{"q":"يشغّل سائق في ميسيسيبي شاحنة مستقيمة مفردة بتصنيف 30,000 رطل GVWR لا تجر أي شيء. أي فئة CDL يتطلبها ذلك؟","options":["Class A","Class C","Class B","لا يُطلَب CDL"],"explanation":"المركبة المفردة بتصنيف GVWR قدره 26,001 رطلًا أو أكثر (لا تجر وحدة يزيد وزنها على 10,000 رطل) هي مركبة Class B في ميسيسيبي. المصدر: Mississippi DPS Driver Service Bureau، فئات CDL من A إلى D؛ دليل CDL في ميسيسيبي."},"22":{"q":"بموجب قواعد ميسيسيبي، فإن المركبة التي لا تستوفي عتبات الوزن لفئة Class A أو B تتطلب مع ذلك رخصة Class C CDL إذا كانت مصممة لنقل كم شخصًا (بمن فيهم السائق)؟","options":["8 أو أكثر","11 أو أكثر","24 أو أكثر","16 أو أكثر"],"explanation":"تنطبق فئة Class C في ميسيسيبي على مركبة دون عتبات الوزن لفئة A/B تكون مصممة لنقل 16 راكبًا أو أكثر بمن فيهم السائق، أو تحمل مواد خطرة تتطلب لوحات تحذيرية. المصدر: Mississippi DPS Driver Service Bureau، فئات CDL من A إلى D؛ دليل CDL في ميسيسيبي."},"23":{"q":"إلى جانب قاعدة الـ 16 راكبًا، ما الشرط الآخر الذي يجعل مركبة أصغر تتطلب رخصة Class C CDL في ميسيسيبي؟","options":["أنها مسجلة للاستخدام التجاري","أنها تنقل مواد خطرة بكميات تتطلب لوحات تحذيرية","أنها تعبر حدود ولاية","أنها مملوكة لشركة نقل"],"explanation":"تتطلب المركبة دون حدود الوزن لفئة A/B رخصة Class C CDL إذا استُخدمت لنقل مواد خطرة بكمية تتطلب لوحات تحذيرية. المصدر: Mississippi DPS Driver Service Bureau، فئات CDL من A إلى D؛ دليل CDL في ميسيسيبي."},"24":{"q":"أي تصديق CDL مطلوب في ميسيسيبي لنقل المواد الخطرة بكميات تتطلب لوحات تحذيرية؟","options":["تصديق N","تصديق T","تصديق H","تصديق X فقط"],"explanation":"تصديق H (HazMat) مطلوب لنقل المواد الخطرة الموسومة بلوحات تحذيرية. تصديق X هو تصديق مدمج لـ HazMat بالإضافة إلى الصهريج، وهو غير مطلوب للسائقين الذين يحتاجون HazMat فقط. المصدر: Mississippi DPS Driver Service Bureau، قائمة تصديقات CDL؛ FMCSA 49 CFR 383.93."},"25":{"q":"في ميسيسيبي، أي تصديق يأذن لحامل CDL بقيادة مركبة صهريج (ناقلة)؟","options":["تصديق T","تصديق P","تصديق S","تصديق N"],"explanation":"تصديق N هو تصديق مركبة الصهريج (الناقلة). T هو المقطورات المزدوجة/الثلاثية، وP هو الركاب، وS هو الحافلة المدرسية. المصدر: Mississippi DPS Driver Service Bureau، قائمة تصديقات CDL؛ FMCSA 49 CFR 383.93."},"26":{"q":"أي تصديق CDL في ميسيسيبي مطلوب لسحب مقطورات مزدوجة أو ثلاثية؟","options":["تصديق T","تصديق N","تصديق H","تصديق P"],"explanation":"تصديق T (المزدوجة/الثلاثية) مطلوب لسحب مقطورات مزدوجة أو ثلاثية ويُحصَل عليه باختبار معرفي فقط. المصدر: Mississippi DPS Driver Service Bureau، قائمة تصديقات CDL؛ FMCSA 49 CFR 383.93."},"27":{"q":"ماذا يمثّل تصديق X على رخصة CDL في ميسيسيبي؟","options":["تصديقًا منتهيًا في انتظار التجديد","إعفاءً من الشهادة الطبية","مزيجًا من تصديقَي HazMat (H) والصهريج (N)","تصديق معاملة بالمثل من ولاية أخرى"],"explanation":"تدرج ميسيسيبي X باعتباره التصديق المدمج لـ HazMat والصهريج، ويُصدَر عندما يكون السائق مؤهلًا لكلٍّ من H وN. المصدر: Mississippi DPS Driver Service Bureau، قائمة تصديقات CDL؛ FMCSA 49 CFR 383.93."},"28":{"q":"لقيادة حافلة مدرسية في ميسيسيبي، أي مجموعة من التصديقات يجب على حامل CDL الحصول عليها؟","options":["تصديق S (الحافلة المدرسية) فقط","تصديق P (الركاب) فقط","تصديق T (المزدوجة/الثلاثية)","كلا التصديقين P (الركاب) وS (الحافلة المدرسية)"],"explanation":"يجب على سائقي الحافلات المدرسية في ميسيسيبي حمل كلٍّ من تصديق الركاب (P) وتصديق الحافلة المدرسية (S)؛ ويُبنى تصديق S على تصديق P. المصدر: Mississippi DPS Driver Service Bureau؛ FMCSA 49 CFR 383.93."},"29":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في ميسيسيبي صالحة فقط للقيادة داخل الولاية (intrastate)؟","options":["18 عامًا","21 عامًا","19 عامًا","16 عامًا"],"explanation":"تسمح ميسيسيبي برخصة CDL في سن 18 عامًا للتجارة داخل الولاية فقط؛ وتتطلب القيادة بين الولايات سن 21 عامًا. المصدر: Mississippi DPS Driver Service Bureau؛ FMCSA 49 CFR 383.3 / 391.11."},"30":{"q":"ما هو الحد الأدنى للسن المطلوب لتشغيل مركبة آلية تجارية عبر حدود الولايات (interstate) برخصة CDL من ميسيسيبي؟","options":["18 عامًا","21 عامًا","19 عامًا","25 عامًا"],"explanation":"يجب أن يكون السائقون في سن 21 عامًا على الأقل للعمل في التجارة بين الولايات وللحصول على تصديقات HazMat أو الركاب للعمل بين الولايات. المصدر: Mississippi DPS Driver Service Bureau؛ FMCSA 49 CFR 391.11."},"31":{"q":"في ميسيسيبي، ما هو الحد الأدنى للسن المطلوب قبل أن يتمكن السائق من الحصول على تصديق HazMat (H) أو الركاب (P) للعمل بين الولايات؟","options":["18 عامًا","19 عامًا","23 عامًا","21 عامًا"],"explanation":"تتطلب ميسيسيبي أن يكون السائق في سن 21 عامًا على الأقل لإصدار تصديقات HazMat أو الركاب للتجارة بين الولايات، تماشيًا مع القواعد الفيدرالية. المصدر: Mississippi DPS Driver Service Bureau؛ FMCSA 49 CFR 383.3 / 391.11."},"32":{"q":"بعد الحصول على تصريح متعلّم تجاري (CLP) في ميسيسيبي، كم يجب أن يحتفظ السائق به قبل أن يُسمَح له بإجراء اختبار المهارات (الطريق) لرخصة CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","7 أيام على الأقل","60 يومًا على الأقل"],"explanation":"تتطلب القاعدة الفيدرالية التي تبنّتها ميسيسيبي الاحتفاظ بـ CLP لمدة 14 يومًا كحد أدنى قبل أن يتمكن المتقدم من إجراء اختبار مهارات CDL. المصدر: دليل CDL في ميسيسيبي؛ FMCSA 49 CFR 383.25."},"33":{"q":"كم تكون مدة صلاحية تصريح المتعلّم التجاري (CLP) في ميسيسيبي قبل وجوب تجديده أو الحصول على CDL؟","options":["30 يومًا","180 يومًا (6 أشهر)","سنة واحدة","90 يومًا"],"explanation":"تكون صلاحية CLP في ميسيسيبي 180 يومًا (ستة أشهر)؛ ويجوز للولايات السماح بتجديد واحد لمدة 180 يومًا إضافية. المصدر: Mississippi DPS Driver Service Bureau؛ FMCSA 49 CFR 383.25."},"34":{"q":"أي تصديق لا يُسمَح بوضعه على تصريح المتعلّم التجاري (CLP) في ميسيسيبي؟","options":["تصديق N (الصهريج)، عندما يكون الصهريج فارغًا","تصديق P (الركاب)","تصديق H (HazMat)","تصديق S (الحافلة المدرسية)"],"explanation":"تحظر القواعد الفيدرالية التي تبنّتها ميسيسيبي تصديق HazMat (H) على CLP؛ فلا يجوز أن تظهر على CLP سوى تصديقات P وS وN، مع قيود. المصدر: دليل CDL في ميسيسيبي؛ FMCSA 49 CFR 383.25."},"35":{"q":"أين يُكمِل المتقدم في ميسيسيبي الآن أخذ البصمات وفحص الخلفية الخاص بـ TSA المطلوبين لتصديق HazMat (H)؟","options":["من خلال مزود خدمات التسجيل الموحّد لـ TSA (IdentoGO)، وليس في محطة CDL المحلية التابعة لـ DPS","في أي محطة CDL محلية تابعة لـ Mississippi DPS","في مكتب السجل الوطني لـ FMCSA","في مكتب كاتب محكمة الدائرة بالمقاطعة"],"explanation":"نقلت ميسيسيبي أخذ بصمات HazMat والتسجيل إلى برنامج خدمات التسجيل الموحّد لـ TSA (IdentoGO / universalenroll.dhs.gov)؛ ولم يعد ذلك يُجرى في محطات CDL المحلية التابعة لـ DPS. المصدر: Mississippi DPS Driver Service Bureau، برنامج تسجيل HazMat لـ CDL."},"36":{"q":"منذ 7 فبراير 2022، يجب على المتقدمين لأول مرة للحصول على CDL في ميسيسيبي إكمال تدريب سائق المستوى المبتدئ (ELDT) المقدَّم من قِبل مَن؟","options":["أي كلية مجتمعية في ميسيسيبي","Mississippi DPS نفسها","مدرب داخلي تابع لصاحب عمل من أي نوع","مزود مدرج في سجل مزودي التدريب التابع لـ FMCSA"],"explanation":"اعتبارًا من 7 فبراير 2022، يجب على المتقدمين لأول مرة للحصول على CDL (وبعض الترقيات/التصديقات) إكمال ELDT من مزود مدرج في سجل مزودي التدريب التابع لـ FMCSA قبل اختبار CDL. المصدر: Mississippi DPS Driver Service Bureau؛ FMCSA 49 CFR Part 380."},"37":{"q":"عندما يصدّق المتقدم لـ CDL في ميسيسيبي ذاتيًا على نوع قيادته، أي فئة تشير إلى أنه يعمل في التجارة بين الولايات ويجب أن يستوفي متطلبات الشهادة الطبية الفيدرالية لـ DOT؟","options":["معفى بين الولايات (EI)","غير معفى بين الولايات (NI)","غير معفى داخل الولاية (NA)","معفى داخل الولاية (EA)"],"explanation":"تستخدم ميسيسيبي فئات التصديق الذاتي الفيدرالية الأربع. يعمل سائقو الفئة غير المعفاة بين الولايات (NI) عبر حدود الولايات ويجب أن يحملوا شهادة فاحص طبي صالحة من DOT. المصدر: Mississippi DPS Driver Service Bureau؛ FMCSA 49 CFR 383.71."},"38":{"q":"أي مجموعة من المستندات يجب على المتقدم لـ CDL في ميسيسيبي تقديمها لاستيفاء متطلبات الهوية/الوجود القانوني والضمان الاجتماعي والإقامة؟","options":["شهادة الثانوية العامة وبطاقة ناخب وفاتورة مرافق واحدة","جواز سفر فقط، دون الحاجة إلى إثبات إقامة","شهادة ميلاد أصلية (أو إثبات وجود قانوني)، ومستندات رقم الضمان الاجتماعي، وإثباتان للإقامة في ميسيسيبي","سند ملكية مركبة وبطاقة تأمين ورخصة صيد"],"explanation":"تتطلب ميسيسيبي إثبات الهوية/الوجود القانوني (مثل شهادة الميلاد الأصلية)، ومستندات رقم الضمان الاجتماعي، وإثباتين للإقامة، بالإضافة إلى بطاقة طبية صالحة، للتقدم للحصول على CDL. المصدر: Mississippi DPS Driver Service Bureau، متطلبات المتقدم لـ CDL."},"39":{"q":"في ميسيسيبي، ما هو الحد الأقصى لتركيز الكحول في الدم/النفس (BAC) الذي يجوز عنده للشخص قانونيًا تشغيل مركبة آلية تجارية؟","options":["0.02","0.04","0.08","0.10"],"explanation":"تتبع ميسيسيبي المعيار الفيدرالي لمركبات النقل التجاري: من غير القانوني تشغيل مركبة آلية تجارية بتركيز كحول قدره 0.04% أو أكثر. القراءة البالغة 0.04% أو أعلى تُعد أساسًا لإسقاط الأهلية لأول مخالفة كبرى. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51؛ دليل CDL في ميسيسيبي (DPS)."},"40":{"q":"يُدان حامل CDL في ميسيسيبي بمخالفة أولى لتشغيل مركبة آلية تجارية بتركيز BAC قدره 0.04% بينما لا ينقل مواد خطرة موسومة بلوحات تحذيرية. لكم تُسقَط أهلية السائق لتشغيل مركبة آلية تجارية؟","options":["6 أشهر","سنة واحدة","3 سنوات","مدى الحياة"],"explanation":"تؤدي المخالفة الكبرى الأولى (بما في ذلك قيادة مركبة آلية تجارية بتركيز BAC قدره 0.04% أو أكثر) إلى إسقاط أهلية CDL لمدة لا تقل عن سنة واحدة في ميسيسيبي. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(b)؛ دليل CDL في ميسيسيبي."},"41":{"q":"إذا ارتكب حامل CDL في ميسيسيبي مخالفة كبرى أولى (مثل القيادة تحت تأثير الكحول في مركبة آلية تجارية) أثناء نقل مواد خطرة موسومة بلوحات تحذيرية، تزداد مدة إسقاط الأهلية إلى:","options":["سنة واحدة","سنتان","3 سنوات","5 سنوات"],"explanation":"بموجب قواعد ميسيسيبي والقواعد الفيدرالية، تحمل المخالفة الكبرى الأولى المرتكبة أثناء نقل مواد خطرة موسومة بلوحات تحذيرية إسقاط أهلية لمدة 3 سنوات بدلًا من السنة الواحدة المعيارية. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(b)(2)؛ دليل CDL في ميسيسيبي."},"42":{"q":"ما هي مدة إسقاط الأهلية لحامل CDL في ميسيسيبي يُدان بمخالفة كبرى ثانية (على سبيل المثال، قيادة ثانية تحت تأثير الكحول في مركبة آلية تجارية)؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تؤدي الإدانة الثانية بأي مخالفة كبرى إلى إسقاط أهلية CDL مدى الحياة في ميسيسيبي. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(b)(3)؛ دليل CDL في ميسيسيبي."},"43":{"q":"في ميسيسيبي، ماذا يحدث لامتياز القيادة التجارية لحامل CDL إذا رفض الخضوع لاختبار كيميائي للنفس أو الدم عند طلبه قانونيًا؟","options":["يُصدَر تحذير دون إسقاط للأهلية","إسقاط الأهلية لمدة 30 يومًا","إسقاط الأهلية لمدة سنة واحدة","إسقاط الأهلية لمدة 90 يومًا"],"explanation":"يُعامَل رفض الاختبار الكيميائي كمخالفة كبرى؛ وبموجب قانون الموافقة الضمنية في ميسيسيبي تُسقَط أهلية CDL لمدة لا تقل عن سنة واحدة لأول رفض. المصدر: Miss. Code Ann. 63-11-30، 63-1-216؛ 49 CFR 383.51(b)؛ دليل CDL في ميسيسيبي."},"44":{"q":"بموجب قانون الموافقة الضمنية في ميسيسيبي، فإن السائق بتشغيله أي مركبة آلية على طريق سريع في ميسيسيبي يُعتبر أنه:","options":["تنازل عن الحق في محامٍ","أعطى موافقته على اختبار كيميائي للنفس أو الدم أو البول","وافق على عمليات تفتيش عشوائية على جانب الطريق","قبل نقاطًا تلقائية على الرخصة"],"explanation":"ينص قانون الموافقة الضمنية في ميسيسيبي على أن أي شخص يقود على طرق الولاية يُعتبر أنه أعطى موافقته على اختبار كيميائي لتحديد تركيز الكحول أو المخدرات. المصدر: Miss. Code Ann. 63-11-5، 63-11-30؛ دليل CDL في ميسيسيبي (DPS)."},"45":{"q":"كم عدد المخالفات المرورية الجسيمة (في حوادث منفصلة) ضمن فترة 3 سنوات التي تؤدي إلى إسقاط أهلية CDL لمدة 60 يومًا في ميسيسيبي؟","options":["1","2","3","4"],"explanation":"تؤدي مخالفتان مروريتان جسيمتان ضمن فترة 3 سنوات (ناشئتان عن حادثين منفصلين) إلى إسقاط الأهلية لمدة 60 يومًا. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(c)؛ دليل CDL في ميسيسيبي."},"46":{"q":"في ميسيسيبي، تؤدي الإدانة بثلاث مخالفات مرورية جسيمة ضمن فترة 3 سنوات إلى إسقاط أهلية CDL لمدة:","options":["60 يومًا","90 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي ثلاث مخالفات مرورية جسيمة ضمن 3 سنوات (حوادث منفصلة) إلى إسقاط الأهلية لمدة 120 يومًا، تُنفَّذ بالتتابع بعد أي إسقاط سابق لمدة 60 يومًا. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(c)؛ دليل CDL في ميسيسيبي."},"47":{"q":"أي مما يلي يُصنَّف كمخالفة مرورية جسيمة لحامل CDL في ميسيسيبي؟","options":["تشغيل مركبة آلية تجارية بتركيز BAC قدره 0.04% أو أكثر","تجاوز السرعة بمقدار 15 ميلًا في الساعة أو أكثر فوق الحد المقرر","رفض اختبار كيميائي","مغادرة موقع الحادث"],"explanation":"تجاوز السرعة بمقدار 15 ميلًا في الساعة أو أكثر فوق الحد هو مخالفة مرورية جسيمة. الخيارات الثلاثة الأخرى المدرجة هي مخالفات كبرى تحمل إسقاط أهلية لسنة واحدة (أو أطول)، وليست مخالفات جسيمة. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(c)؛ دليل CDL في ميسيسيبي."},"48":{"q":"أي مما يلي لا يُحتسَب كمخالفة مرورية جسيمة لحامل CDL في ميسيسيبي؟","options":["اتباع المركبة الأمامية عن قرب شديد","القيادة المتهورة","إجراء تغييرات حارة غير منتظمة أو غير سليمة","ركن مركبة آلية تجارية غير مراقبة بشكل غير سليم طوال الليل"],"explanation":"اتباع المركبة عن قرب شديد، والقيادة المتهورة، وتغييرات الحارة غير المنتظمة/غير السليمة كلها مخالفات مرورية جسيمة. أما الركن الاعتيادي لمركبة غير مراقبة فليس مدرجًا في قائمة المخالفات الجسيمة. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(c)؛ دليل CDL في ميسيسيبي."},"49":{"q":"سائق CDL في ميسيسيبي يرسل رسائل نصية أو يستخدم هاتفًا محمولًا باليد أثناء قيادة مركبة آلية تجارية يرتكب أي نوع من المخالفات؟","options":["مخالفة غير قابلة للإبلاغ","مخالفة مرورية جسيمة","مخالفة كبرى","مخالفة إيقاف عن الخدمة"],"explanation":"إرسال الرسائل النصية أو استخدام هاتف محمول باليد أثناء قيادة مركبة آلية تجارية هو مخالفة مرورية جسيمة؛ ويمكن أن تؤدي مخالفتان أو ثلاث مخالفات جسيمة من هذا النوع ضمن 3 سنوات إلى إسقاط الأهلية لمدة 60 أو 120 يومًا. المصدر: 49 CFR 383.51(c)، 392.80/392.82؛ Miss. Code Ann. 63-1-216؛ دليل CDL في ميسيسيبي."},"50":{"q":"يحمل انتهاك أول لأمر إيقاف عن الخدمة من قِبل سائق CDL في ميسيسيبي ينقل مواد خطرة موسومة بلوحات تحذيرية أو 16 راكبًا أو أكثر إسقاط أهلية لمدة:","options":["لا تقل عن 180 يومًا، ولا تزيد على سنتين","180 يومًا بالضبط","لا تقل عن 60 يومًا، ولا تزيد على سنة واحدة","مدى الحياة"],"explanation":"عندما يحدث انتهاك أول للإيقاف عن الخدمة أثناء نقل مواد خطرة موسومة بلوحات تحذيرية أو حمل 16 راكبًا أو أكثر، يكون إسقاط الأهلية لمدة لا تقل عن 180 يومًا ولا تزيد على سنتين. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(e)؛ دليل CDL في ميسيسيبي."},"51":{"q":"يُسقَط أهلية سائق CDL في ميسيسيبي يُدان بمخالفة أولى عند تقاطع سكة حديد مع طريق سريع أثناء تشغيل مركبة آلية تجارية لمدة:","options":["لا تقل عن 30 يومًا","لا تقل عن 60 يومًا","لا تقل عن 120 يومًا","سنة واحدة"],"explanation":"تؤدي المخالفة الأولى عند تقاطع سكة حديد مع طريق سريع إلى إسقاط أهلية لمدة لا تقل عن 60 يومًا. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(d)؛ دليل CDL في ميسيسيبي."},"52":{"q":"ما هي مدة إسقاط الأهلية لمخالفة ثالثة عند تقاطع سكة حديد مع طريق سريع لسائق CDL في ميسيسيبي ضمن فترة 3 سنوات؟","options":["120 يومًا","6 أشهر","سنة واحدة","مدى الحياة"],"explanation":"تؤدي المخالفة الثالثة (أو اللاحقة) عند تقاطع سكة الحديد ضمن 3 سنوات إلى إسقاط أهلية لمدة لا تقل عن سنة واحدة. التدرج هو 60 يومًا (الأولى)، و120 يومًا (الثانية)، وسنة واحدة (الثالثة). المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(d)؛ دليل CDL في ميسيسيبي."},"53":{"q":"في ميسيسيبي، حامل CDL يستخدم مركبة آلية تجارية لارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها يُسقَط أهليته لمدة:","options":["سنة واحدة","3 سنوات","10 سنوات","مدى الحياة، دون إعادة منح"],"explanation":"يؤدي استخدام مركبة آلية تجارية في ارتكاب جناية تتعلق بمواد خاضعة للرقابة إلى إسقاط أهلية مدى الحياة لا يمكن تخفيفه، على عكس بعض حالات إسقاط الأهلية مدى الحياة. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(b)؛ دليل CDL في ميسيسيبي."},"54":{"q":"أي مما يلي يُعد مخالفة كبرى (إسقاط أهلية لا يقل عن سنة واحدة) وليس مخالفة مرورية جسيمة في ميسيسيبي؟","options":["اتباع المركبة عن قرب شديد","مغادرة موقع حادث يشمل مركبة آلية تجارية","تجاوز السرعة بمقدار 15 ميلًا في الساعة فوق الحد","تغيير حارة غير سليم"],"explanation":"مغادرة موقع حادث يشمل مركبة آلية تجارية هي مخالفة كبرى تحمل إسقاط أهلية لا يقل عن سنة واحدة. الخيارات الأخرى مخالفات مرورية جسيمة. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(b)؛ دليل CDL في ميسيسيبي."},"55":{"q":"في ميسيسيبي، إذا رفض شخص اختبارًا كيميائيًا أثناء حمله CDL، فإن إسقاط أهلية الامتياز التجاري ينطبق:","options":["فقط إذا كان السائق يشغّل مركبة آلية تجارية في ذلك الوقت","فقط إذا ثبت لاحقًا أن BAC يزيد على 0.04%","حتى لو حدث الرفض أثناء قيادة مركبة شخصية (غير تجارية)","فقط بعد رفض ثانٍ"],"explanation":"يُسقَط أهلية حامل CDL لرفضه اختبارًا كيميائيًا حتى عندما يحدث الرفض أثناء تشغيل مركبة غير تجارية؛ فالإدانات والرفض في مركبة شخصية لا تزال تؤثر على CDL. المصدر: Miss. Code Ann. 63-11-30، 63-1-216؛ 49 CFR 383.51؛ دليل CDL في ميسيسيبي."},"56":{"q":"سائق CDL في ميسيسيبي يتلقى مخالفة مرورية جسيمة في مركبته الشخصية تؤدي إلى تعليق الرخصة. كيف يؤثر ذلك على CDL؟","options":["ليس له أي تأثير لأنه لم يكن مركبة آلية تجارية","لا يزال يُحتسَب نحو إسقاط أهلية CDL","يُحتسَب فقط إذا كان السائق في الخدمة","يؤثر فقط على تصديق المواد الخطرة"],"explanation":"تُحتسَب الإدانات وإجراءات الرخصة في مركبة شخصية ضد CDL؛ فتعليق/إلغاء/سحب امتياز القيادة لمخالفات جسيمة معينة يؤدي إلى إسقاط أهلية CDL. المصدر: Miss. Code Ann. 63-1-216؛ 49 CFR 383.51(b)(2)؛ دليل CDL في ميسيسيبي."},"57":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في ولاية مسيسيبي، عندما تقترب من مركبة طوارئ أو مركبة قطر متوقفة تعرض أضواءً وامضة على طريق سريع بأربع حارات حيث توجد حارتان في اتجاه سيرك، ماذا يجب عليك أن تفعل؟","options":["أن تُخلي الحارة المجاورة للمركبة المتوقفة إذا كان من الآمن فعل ذلك","أن تتوقف توقفًا تامًا حتى تغادر المركبة المتوقفة","أن تطلق نفير سيارتك بشكل مستمر أثناء تجاوز المركبة","أن تحافظ على سرعتك وتبقى في حارتك الحالية"],"explanation":"يُلزم قانون مسيسيبي Miss. Code 63-3-809 السائقين على طريق به أربع حارات على الأقل (حارتان أو أكثر في الاتجاه نفسه) بالانتقال إلى حارة غير مجاورة لمركبة الطوارئ أو الإنقاذ أو المرافق المتوقفة عندما يكون ذلك آمنًا. المصدر: Mississippi Code 63-3-809."},"58":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في ولاية مسيسيبي، إذا لم تستطع تغيير الحارة بأمان بعيدًا عن مركبة طوارئ متوقفة تعرض أضواءً وامضة، فما المطلوب منك أن تفعله بدلًا من ذلك؟","options":["أن تستمر بالحد الأقصى للسرعة المعلن دون تغيير أي شيء","أن تتوقف في حارتك وتنتظر أن يشير لك أحد رجال الشرطة بالمرور","أن تخفّض سرعتك وتتابع بحذر وتكون مستعدًا للتوقف","أن تشغّل أضواء الخطر وتتجاوز بسرعة عادية"],"explanation":"يوجّه قانون مسيسيبي Miss. Code 63-3-809 السائق الذي لا يستطيع تغيير الحارة بأمان إلى تخفيض السرعة والمتابعة بحذر واجب والاستعداد للتوقف. المصدر: Mississippi Code 63-3-809."},"59":{"q":"في ولاية مسيسيبي، تُعاقَب مخالفة قانون \"أفسح الطريق\" (63-3-809) التي لا تتسبب في أضرار أو إصابات بغرامة تصل إلى أي مبلغ؟","options":["حتى $100","حتى $250","حتى $500","حتى $1,000"],"explanation":"يحدد قانون مسيسيبي Miss. Code 63-3-809 غرامة تصل إلى $250 للمخالفة، ترتفع إلى ما يصل إلى $1,000 إذا تسببت المخالفة في أضرار مادية للمركبة المتوقفة أو إصابة جسدية لركابها. المصدر: Mississippi Code 63-3-809."},"60":{"q":"إلى جانب مركبات الطوارئ المرخّصة، أيٌّ من المركبات المتوقفة التالية التي تعرض أضواء تحذير وامضة يحميها أيضًا قانون \"أفسح الطريق\" في مسيسيبي (63-3-809)؟","options":["فقط مركبات إنفاذ القانون المميَّزة","فقط سيارات الإسعاف وآليات الإطفاء","مركبات الإنقاذ (القطر) ومركبات خدمات المرافق","فقط المركبات المملوكة لحكومة الولاية"],"explanation":"يوسّع قانون مسيسيبي Miss. Code 63-3-809 واجب الإفساح/تخفيض السرعة ليشمل مركبات الطوارئ المرخّصة المتوقفة إضافةً إلى مركبات الإنقاذ (القطر) وخدمات المرافق التي تستخدم أضواءً وامضة مرخّصة. المصدر: Mississippi Code 63-3-809."},"61":{"q":"على معظم الطرق السريعة بين الولايات في مسيسيبي، يجوز للجنة النقل في مسيسيبي (Mississippi Transportation Commission) تحديد الحد الأقصى للسرعة بما لا يزيد عن أي قيمة؟","options":["65 mph","70 mph","75 mph","80 mph"],"explanation":"يحدّ قانون مسيسيبي Miss. Code 63-3-501 الحد الأقصى للسرعة الذي يجوز للجنة النقل تعيينه على نظام الطرق السريعة بين الولايات وعلى الطرق السريعة محدودة الوصول ذات الأربع حارات أو أكثر بـ 70 mph. المصدر: Mississippi Code 63-3-501."},"62":{"q":"بموجب قانون مسيسيبي 63-3-501، حيث يُحدَّد حدّ 70 mph على طريق سريع بين الولايات أو طريق U.S. بأربع حارات، ما الحد الأدنى للسرعة الذي ينطبق على مركبة لديها قيد للحد الأقصى للسرعة قدره 70 mph؟","options":["30 mph","40 mph","45 mph","50 mph"],"explanation":"يحدد قانون مسيسيبي Miss. Code 63-3-501 حدًا أدنى للسرعة قدره 40 mph للمركبات التي لديها قيد للحد الأقصى للسرعة قدره 70 mph على هذه الطرق السريعة. المصدر: Mississippi Code 63-3-501."},"63":{"q":"بموجب قانون مسيسيبي، عندما توقف حافلة تقل ركابًا قبل عبور تقاطع سكة حديد على مستوى الطريق، يجب أن تتوقف ضمن أي مسافة من أقرب قضيب؟","options":["ضمن 50 feet ولكن ليس أقل من 15 feet","ضمن 25 feet ولكن ليس أقل من 5 feet","ضمن 75 feet ولكن ليس أقل من 25 feet","ضمن 100 feet ولكن ليس أقل من 50 feet"],"explanation":"يُلزم قانون مسيسيبي Miss. Code 63-3-1011 الحافلات والمركبات التي تنقل ركابًا بأجر والحافلات المدرسية والمركبات التي تنقل المتفجرات أو السوائل القابلة للاشتعال بالتوقف ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب. المصدر: Mississippi Code 63-3-1011."},"64":{"q":"وفقًا لدليل CDL في مسيسيبي، أيُّ المركبات التجارية يُطلب منها دائمًا التوقف عند تقاطعات السكك الحديدية على مستوى الطريق؟","options":["جميع المركبات التجارية التي يزيد وزنها عن 10,000 pounds","الحافلات التي تقل ركابًا والمركبات التي تنقل مواد خطرة موضوعًا عليها لافتات تحذير (placarded)","فقط التركيبات ذات المقطورة الثلاثية","أي مركبة تقطر مقطورة من أي نوع"],"explanation":"يُلزم دليل CDL في مسيسيبي (المطابق لـ 49 CFR 392.10 و Miss. Code 63-3-1011) الحافلات التي تقل ركابًا ومركبات المواد الخطرة الموضوع عليها لافتات تحذير بالتوقف قبل عبور القضبان، ثم النظر والإصغاء. المصدر: Mississippi CDL Manual / Miss. Code 63-3-1011."},"65":{"q":"عند وجوب التوقف عند تقاطع سكة حديد في مسيسيبي، وبعد التوقف ضمن المنطقة بين 15 و 50 feet، كيف ينبغي لسائق حافلة أو مركبة عليها لافتات تحذير أن يعبر القضبان؟","options":["بسرعة، مع التنقل تصاعديًا عبر التروس لإخلاء التقاطع بسرعة","بترس يسمح بإتمام العبور دون تغيير التروس","في وضع الحياد (neutral)، منزلقًا عبره مع ضغط القابض (الكلتش)","فقط بعد إطلاق النفير ثلاث مرات"],"explanation":"يوجّه دليل CDL في مسيسيبي السائقين إلى العبور بترس يسمح بإتمام العبور دون تغيير التروس، وعدم تغيير التروس أثناء التواجد على القضبان. المصدر: Mississippi CDL Manual (تقاطعات السكك الحديدية)."},"66":{"q":"بموجب قانون الحافلات المدرسية في مسيسيبي (قانون ناثان، Nathan's Law، 63-3-615)، إلى أي مسافة يجوز لمركبة قادمة أو متجاوِزة أن تتوقف من حافلة مدرسية تُقِل أو تُنزل أطفالًا وأضواؤها الحمراء وامضة وذراع التوقف ممدودة؟","options":["ليس أقل من 10 feet من الحافلة","ليس أقل من 25 feet من الحافلة","ليس أقل من 50 feet من الحافلة","ليس أقل من 5 feet من الحافلة"],"explanation":"يُلزم قانون مسيسيبي Miss. Code 63-3-615 السائقين القادمين أو المتجاوِزين بالتوقف على مسافة لا تقل عن 10 feet من حافلة مدرسية متوقفة لاستقبال الأطفال أو إنزالهم. المصدر: Mississippi Code 63-3-615."},"67":{"q":"على طريق سريع في مسيسيبي، في أي حالة لا يكون على السائق التوقف لحافلة مدرسية متوقفة لتُقِل أو تُنزل أطفالًا؟","options":["كلما كان السائق مسافرًا في الاتجاه المعاكس على أي طريق بحارتين","عندما تتوقف الحافلة على الطريق المقابل من طريق سريع مقسوم بأربع حارات أو أكثر مع حارتين على الأقل في اتجاهين متعاكسين","كلما كانت حركة المرور كثيفة وكان التوقف غير مريح","عندما يكون السائق على بُعد أكثر من 100 feet من الحافلة"],"explanation":"يُعفي قانون مسيسيبي Miss. Code 63-3-615 السائق على طريق سريع مقسوم بأربع حارات أو أكثر (يسمح بحارتين على الأقل لحركة المرور في اتجاهين متعاكسين) من التوقف لحافلة متوقفة في الطريق المقابل. المصدر: Mississippi Code 63-3-615."},"68":{"q":"بموجب قانون مسيسيبي 63-3-615، الغرامة عن المخالفة الأولى لتجاوز حافلة مدرسية متوقفة بشكل غير قانوني لا تقل عن أي مبلغ؟","options":["لا تقل عن $100","لا تقل عن $200","لا تقل عن $350","لا تقل عن $1,000"],"explanation":"يحدد قانون مسيسيبي Miss. Code 63-3-615 غرامة للمخالفة الأولى لا تقل عن $350 ولا تزيد عن $750 (مع احتمال السجن) لتجاوز حافلة مدرسية متوقفة بشكل غير قانوني. المصدر: Mississippi Code 63-3-615."},"69":{"q":"بموجب قواعد استخدام الحارات في مسيسيبي، أين يجب أن تُقاد مركبة تجارية تسير بسرعة أبطأ من السرعة العادية لحركة المرور على طريق سريع متعدد الحارات؟","options":["في الحارة اليمنى أو أقرب ما يكون من الحافة اليمنى للطريق","في الحارة الوسطى في جميع الأوقات","في الحارة اليسرى للابتعاد عن حركة المرور المندمجة","في أي حارة بها أقل حركة مرور"],"explanation":"يُلزم قانون مسيسيبي Miss. Code 63-3-603 المركبة التي تسير بأبطأ من السرعة العادية لحركة المرور باستخدام الحارة اليمنى أو البقاء أقرب ما يكون إلى الحافة اليمنى، باستثناء حالات التجاوز أو الاستعداد لانعطاف يسار. المصدر: Mississippi Code 63-3-603."},"70":{"q":"ماذا يقول قانون مسيسيبي 63-3-603 بشأن القيادة المستمرة في أقصى الحارة اليسرى من طريق متعدد الحارات؟","options":["مسموح للشاحنات لكنه محظور على السيارات","محظور كلما أعاق تدفق حركة المرور الأخرى","مطلوب لجميع المركبات التي يزيد وزنها عن 26,000 pounds","مسموح في أي وقت طالما أشرت أولًا"],"explanation":"يحظر قانون مسيسيبي Miss. Code 63-3-603 القيادة المستمرة في أقصى الحارة اليسرى من طريق متعدد الحارات كلما أدى ذلك إلى إعاقة تدفق حركة المرور الأخرى. المصدر: Mississippi Code 63-3-603."},"71":{"q":"وفقًا لدليل CDL في مسيسيبي، عندما تتوقف مركبتك التجارية على كتف طريق سريع باتجاه واحد أو مقسوم، أين تضع مثلثات التحذير الثلاثة؟","options":["على بُعد 10 و 100 و 200 feet باتجاه حركة المرور القادمة (جميعها إلى الخلف)","على بُعد 25 feet أمامًا، وعند المركبة، و 25 feet خلفًا","واحد عند المركبة واثنان جنبًا إلى جنب على بُعد 50 feet خلفًا","على بُعد 10 و 100 و 200 feet أمام المركبة وخلفها معًا"],"explanation":"يوجّه دليل CDL في مسيسيبي (وفقًا لـ 49 CFR 392.22) إلى وضع المثلثات على بُعد 10 و 100 و 200 feet باتجاه حركة المرور القادمة على طريق باتجاه واحد أو مقسوم. المصدر: Mississippi CDL Manual / 49 CFR 392.22."},"72":{"q":"وفقًا لدليل CDL في مسيسيبي، على طريق غير مقسوم بحارتين يحمل حركة المرور في كلا الاتجاهين، أين يجب وضع أجهزة التحذير لمركبة تجارية متوقفة؟","options":["الثلاثة جميعها ضمن 10 feet خلف المركبة","ضمن 10 feet من المركبة، بالإضافة إلى 100 feet خلفًا و 100 feet أمامًا","جهاز واحد فقط، على بُعد 200 feet خلف المركبة","على بُعد 50 feet و 500 feet خلف المركبة"],"explanation":"يُلزم دليل CDL في مسيسيبي (وفقًا لـ 49 CFR 392.22) بوضع جهاز ضمن 10 feet من المركبة وأجهزة على بُعد نحو 100 feet خلفًا و 100 feet أمامًا على طريق بحارتين باتجاهين. المصدر: Mississippi CDL Manual / 49 CFR 392.22."},"73":{"q":"وفقًا لدليل CDL في مسيسيبي، بعد توقف مركبة تجارية على طريق أو كتف، خلال كم ثانية يجب على السائق وضع أجهزة التحذير من الطوارئ؟","options":["خلال 5 seconds","خلال 10 minutes","خلال 30 minutes","خلال 1 hour"],"explanation":"يُلزم دليل CDL في مسيسيبي (وفقًا لـ 49 CFR 392.22) بوضع أجهزة التحذير خلال 10 minutes من التوقف؛ وتُستخدم أضواء الخطر الوامضة فورًا وحتى يتم وضع المثلثات. المصدر: Mississippi CDL Manual / 49 CFR 392.22."},"74":{"q":"أيُّ طريق في مسيسيبي، يمتد قطريًا عبر الولاية، يحظر على الشاحنات التجارية (تلك التي تتجاوز سعتها المقدّرة طنًا واحدًا) استخدامه؟","options":["Interstate 55","U.S. Highway 49","طريق ناتشيز تريس باركواي (Natchez Trace Parkway)","Interstate 20"],"explanation":"يحظر طريق ناتشيز تريس باركواي (Natchez Trace Parkway)، وهو طريق ذو مناظر خلابة تديره الحكومة الفيدرالية، المركبات التجارية والشاحنات التي تتجاوز سعتها المقدّرة طنًا واحدًا. المصدر: 36 CFR 7.43 / National Park Service."},"75":{"q":"في مسيسيبي، ما الحد الأقصى القانوني لعرض المركبة المسموح به على الطرق السريعة المخصّصة قبل أن يُطلب الحصول على تصريح للحمولات كبيرة الحجم (oversize)؟","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"الحد الأقصى القانوني للعرض في مسيسيبي على الطرق السريعة المخصّصة هو 8 feet 6 inches؛ والحمولات الأعرض من ذلك تتطلب تصريحًا للحمولات كبيرة الحجم (oversize). المصدر: قواعد تصاريح الحمولات كبيرة الحجم/زائدة الوزن لدى Mississippi DOT."},"76":{"q":"في مسيسيبي، ما الحد الأقصى القانوني لإجمالي وزن المركبة على نظام الطرق بين الولايات قبل أن يُطلب الحصول على تصريح للوزن الزائد (overweight)؟","options":["73,280 pounds","80,000 pounds","88,000 pounds","100,000 pounds"],"explanation":"تتّبع مسيسيبي الحد الفيدرالي البالغ 80,000 pounds كحد أقصى قانوني للوزن الإجمالي على نظام الطرق بين الولايات؛ وتجاوزه يتطلب تصريحًا للوزن الزائد من MDOT. المصدر: قواعد تصاريح الوزن الزائد لدى Mississippi DOT."},"77":{"q":"أيُّ جهة في مسيسيبي تُصدر رخص القيادة التجارية وتدير اختبارات CDL في الولاية؟","options":["وزارة السلامة العامة في مسيسيبي (Mississippi Department of Public Safety - DPS)، عبر مكتب خدمة السائقين التابع لها (Driver Service Bureau)","وزارة النقل في مسيسيبي (Mississippi Department of Transportation - MDOT)","مكتب كاتب محكمة الدائرة (Circuit Clerk) في المقاطعة التي يقيم فيها السائق","الإدارة الفيدرالية لسلامة شركات النقل بالمحركات (Federal Motor Carrier Safety Administration - FMCSA)"],"explanation":"تُصدَر رخص CDL في مسيسيبي وتُدار اختبارات CDL من قبل وزارة السلامة العامة في مسيسيبي (Mississippi Department of Public Safety - DPS) عبر مكتب خدمة السائقين التابع لها. تتولى MDOT الطرق والتصاريح وليس الترخيص، وتضع FMCSA المعايير الفيدرالية لكنها لا تصدر رخص الولايات. المصدر: MS DPS Driver Service Bureau؛ Miss. Code Title 63, Chapter 1."},"78":{"q":"ما الحد الأدنى لدرجة النجاح في اختبارات المعرفة (التحريرية) لـ CDL في مسيسيبي؟","options":["80%","70%","75%","90%"],"explanation":"تشترط مسيسيبي درجة لا تقل عن 80% في كل اختبار معرفة مطلوب لـ CDL، بما يتوافق مع معيار الاختبار الفيدرالي AAMVA. المصدر: MS DPS / Mississippi CDL Manual."},"79":{"q":"قبل أن يتمكّن متقدّم لأول مرة للحصول على CDL في مسيسيبي من إجراء اختبارات المعرفة أو المهارات المطلوبة، ما التدريب الذي يجب إكماله؟","options":["تدريب السائقين المبتدئين (Entry-Level Driver Training - ELDT) من مزوّد تدريب مسجّل لدى FMCSA","دورة قيادة دفاعية معتمدة من MDOT","دورة صفّية مدتها 40 ساعة في كلية مجتمعية","تدريب مهني مسجّل لدى جمعية النقل بالشاحنات في مسيسيبي"],"explanation":"منذ February 7, 2022، يجب على المتقدّمين لأول مرة للحصول على CDL إكمال تدريب السائقين المبتدئين (ELDT) من مزوّد مدرَج في سجل مزوّدي التدريب لدى FMCSA قبل إجراء اختبارات المهارات أو المعرفة المطلوبة. المصدر: MS DPS Driver Service Bureau؛ قاعدة ELDT الخاصة بـ FMCSA (49 CFR Part 380)."},"80":{"q":"كم من الوقت يجب الاحتفاظ برخصة المتعلّم التجارية (Commercial Learner's Permit - CLP) في مسيسيبي قبل أن يتمكّن حاملها من إجراء اختبار مهارات CDL؟","options":["14 days على الأقل","30 days على الأقل","10 days على الأقل","60 days على الأقل"],"explanation":"تتّبع مسيسيبي القاعدة الفيدرالية التي تشترط الاحتفاظ بـ CLP لمدة 14 days كحد أدنى قبل أن يصبح حاملها مؤهلًا لإجراء اختبار مهارات CDL. المصدر: MS DPS Driver Service Bureau؛ 49 CFR 383.25."},"81":{"q":"لكم من الوقت تكون رخصة المتعلّم التجارية (Commercial Learner's Permit - CLP) في مسيسيبي صالحة؟","options":["6 months","1 year","30 days","90 days"],"explanation":"تكون رخصة CLP في مسيسيبي صالحة لمدة 6 months (180 days)، بما يتوافق مع الحد الأقصى الفيدرالي لمدة صلاحية CLP. المصدر: MS DPS Driver Service Bureau؛ 49 CFR 383.25."},"82":{"q":"يتكوّن اختبار مهارات CDL في مسيسيبي من أيِّ ثلاثة أجزاء، تُؤدّى بالترتيب؟","options":["فحص المركبة قبل الرحلة، والتحكّم الأساسي بالمركبة، والقيادة على الطريق","اختبار المعرفة التحريري، واختبار الفرامل الهوائية، والقيادة على الطريق","الفحص قبل الرحلة، ومناولة المواد الخطرة، والقيادة الليلية","التحكّم الأساسي بالمركبة، والوصل/الفصل، واختبار تأييد (endorsement) تحريري"],"explanation":"يتكوّن اختبار مهارات CDL في مسيسيبي من ثلاثة أجزاء: فحص المركبة قبل الرحلة، واختبار مهارات التحكّم الأساسي بالمركبة، واختبار القيادة على الطريق. يجب اجتياز الأجزاء الثلاثة جميعها. المصدر: MS DPS / Mississippi CDL Manual."},"83":{"q":"ما مدة (فترة صلاحية) رخصة القيادة التجارية في مسيسيبي قبل وجوب تجديدها؟","options":["5 years، تنتهي في يوم ميلاد المرخّص له","4 years، تنتهي في يوم ميلاد المرخّص له","8 years، تنتهي في يوم ميلاد المرخّص له","2 years، مرتبطة بالشهادة الطبية"],"explanation":"تُصدَر رخصة CDL في مسيسيبي لمدة خمس سنوات وتنتهي عند منتصف ليل يوم ميلاد المرخّص له. المصدر: Miss. Code Ann. Sec. 63-1-47 (و Sec. 63-1-211)."},"84":{"q":"كم من الوقت قبل تاريخ انتهاء الصلاحية يجوز لحامل CDL في مسيسيبي تجديد الرخصة؟","options":["في أي وقت خلال 6 months قبل انتهاء الصلاحية","فقط خلال 30 days قبل انتهاء الصلاحية","في أي وقت خلال 90 days قبل انتهاء الصلاحية","فقط في تاريخ انتهاء الصلاحية أو بعده"],"explanation":"تسمح مسيسيبي بالتجديد في أي وقت خلال ستة (6) أشهر قبل انتهاء صلاحية الرخصة عند تقديم الطلب ودفع الرسوم المطلوبة، ما لم يُطلب إعادة الفحص. المصدر: Miss. Code Ann. Sec. 63-1-47."},"85":{"q":"عندما يُقرّ متقدّم لـ CDL ذاتيًا بنوع قيادته لدى Mississippi DPS، كم عدد فئات الإقرار الذاتي المتاحة للاختيار من بينها؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"هناك أربع فئات للإقرار الذاتي: غير المُستثناة بين الولايات (Non-Excepted Interstate)، والمُستثناة بين الولايات (Excepted Interstate)، وغير المُستثناة داخل الولاية (Non-Excepted Intrastate)، والمُستثناة داخل الولاية (Excepted Intrastate). يجب على المتقدّم اختيار واحدة بالضبط. المصدر: MS DPS Driver Service Bureau Self-Certification؛ 49 CFR 383.71(b)."},"86":{"q":"أيُّ فئة إقرار ذاتي في مسيسيبي تنطبق على سائق يعمل عبر حدود الولايات ويُطلب منه استيفاء جميع معايير التأهيل الطبي الفيدرالية؟","options":["غير المُستثناة بين الولايات (Non-Excepted Interstate - NI)","المُستثناة بين الولايات (Excepted Interstate - EI)","غير المُستثناة داخل الولاية (Non-Excepted Intrastate - NA)","المُستثناة داخل الولاية (Excepted Intrastate - EA)"],"explanation":"يعمل سائقو فئة غير المُستثناة بين الولايات (Non-Excepted Interstate - NI) في التجارة بين الولايات، ويجب أن يستوفوا جميع المتطلبات الطبية الفيدرالية لـ DOT، ويجب أن يحتفظوا بشهادة فاحص طبي سارية في الملف. المصدر: MS DPS Self-Certification categories؛ 49 CFR 383.71(b)."},"87":{"q":"السائق في مسيسيبي الذي يُقرّ ذاتيًا بأنه غير مُستثنى بين الولايات (Non-Excepted Interstate) يجب أن يحتفظ بأي شيء في الملف لدى DPS للحفاظ على CDL سارية؟","options":["شهادة فاحص طبي سارية لـ DOT","شهادة تأمين تجاري ساري للمسؤولية العامة","رخصة CLP مجدَّدة كل ستة أشهر","تصريح حمولة كبيرة الحجم/زائدة الوزن من MDOT"],"explanation":"يجب على سائقي فئة غير المُستثناة بين الولايات (Non-Excepted Interstate) (وغير المُستثناة داخل الولاية Non-Excepted Intrastate) الاحتفاظ بشهادة فاحص طبي سارية لـ DOT في السجل لدى DPS؛ والإخفاق في ذلك يتسبب في تخفيض درجة الرخصة. المصدر: MS DPS Medical Certification Requirements؛ 49 CFR 383.71/383.73."},"88":{"q":"اعتبارًا من June 23, 2025، كيف تُنقَل نتيجة الفحص الطبي لـ DOT لسائق CDL إلى Mississippi DPS؟","options":["يقدّم الفاحص الطبي المعتمد النتيجة إلكترونيًا إلى السجل الوطني (National Registry) التابع لـ FMCSA، الذي ينقلها إلى DPS","يرسل السائق نسخة ورقية من النموذج MCSA-5876 بالبريد إلى مقر DPS","يرفع السائق نسخة ممسوحة ضوئيًا عبر البوابة الإلكترونية لـ DPS","يرسل صاحب العمل نسخة بالفاكس إلى محطة رخص القيادة المحلية لـ DPS"],"explanation":"بموجب القاعدة النهائية لـ FMCSA السارية اعتبارًا من June 23, 2025، يقدّم الفاحصون الطبيون المعتمدون نتائج الفحص إلكترونيًا إلى السجل الوطني (National Registry)، الذي ينقلها إلى الولاية؛ وتنشر مسيسيبي النتيجة مباشرةً في سجل السائق. المصدر: MS DPS Medical Certification Requirements؛ القاعدة النهائية FMCSA Medical Examiner's Certification Integration."},"89":{"q":"بعد التغيير الفيدرالي بتاريخ June 23, 2025، هل يجوز لمحطة رخص القيادة في مسيسيبي قبول نسخة ورقية أو ممسوحة ضوئيًا من شهادة الفاحص الطبي (النموذج MCSA-5876)؟","options":["لا؛ لم تعد النسخ الورقية والممسوحة ضوئيًا مقبولة، إذ تأتي النتائج إلكترونيًا من السجل الوطني (National Registry)","نعم؛ تظل النسخ الورقية الطريقة الأساسية للتقديم","نعم، ولكن فقط إذا صُدِّقت لدى كاتب عدل خلال 15 days من الفحص","نعم، ولكن فقط للسائقين داخل الولاية (NA)"],"explanation":"اعتبارًا من June 23, 2025، لم تعد محطات DPS تقبل نسخ MCSA-5876 الورقية أو الممسوحة ضوئيًا؛ ويجب استلام نتيجة الفحص الطبي إلكترونيًا من السجل الوطني (National Registry) التابع لـ FMCSA. المصدر: MS DPS Medical Certification Requirements؛ القاعدة النهائية FMCSA Medical Examiner's Certification Integration."},"90":{"q":"بموجب قاعدة FMCSA التي تتّبعها مسيسيبي، بحلول أي موعد يجب على الفاحص الطبي المعتمد رفع نتيجة فحص سائق CDL إلى السجل الوطني (National Registry)؟","options":["بحلول نهاية اليوم التقويمي التالي بعد الفحص","خلال 30 days من الفحص","خلال 14 days من الفحص","بحلول نهاية أسبوع العمل نفسه"],"explanation":"بموجب القاعدة السارية اعتبارًا من June 23, 2025، يجب على الفاحص الطبي المعتمد رفع نتائج الفحص إلكترونيًا إلى السجل الوطني (National Registry) بحلول منتصف ليل اليوم التقويمي التالي للفحص. المصدر: القاعدة النهائية FMCSA Medical Examiner's Certification Integration، المطبَّقة من قبل MS DPS."},"91":{"q":"ماذا يحدث لرخصة CDL في مسيسيبي إذا سمح سائق غير مُستثنى بانقضاء شهادته الطبية لـ DOT ولم يحدّثها؟","options":["تخفّض DPS درجة CDL، فتُزيل امتيازات القيادة التجارية حتى تُستعاد الشهادة","تُلغى CDL نهائيًا ولا يمكن إعادتها","لا يتغيّر شيء حتى التجديد التالي كل 5 years","يُعاد تصنيف السائق تلقائيًا على أنه مُستثنى بين الولايات (Excepted Interstate)"],"explanation":"السائق غير المُستثنى الذي يخفق في إبقاء الشهادة الطبية سارية يُغيَّر وضعه إلى \"غير معتمد\" (not-certified)، وتخفّض الولاية درجة CDL، فتُزيل الامتيازات التجارية حتى تتوفّر شهادة سارية في الملف مجددًا. المصدر: MS DPS Medical Certification Requirements؛ 49 CFR 383.73."},"92":{"q":"ما المستندات المطلوبة عادةً عند التقدّم للحصول على CDL جديدة في مسيسيبي في مكتب DPS؟","options":["إثبات الهوية/الميلاد، ورقم الضمان الاجتماعي (Social Security number)، وإثباتان للإقامة في مسيسيبي","جواز سفر فقط، دون الحاجة إلى أي مستندات أخرى","شهادة دبلوم المدرسة الثانوية وثلاثة مراجع شخصية","سند ملكية مركبة وإثبات تأمين تجاري على السيارة فقط"],"explanation":"يجب على المتقدّم لـ CDL جديدة تقديم إثبات الهوية (مثل شهادة الميلاد)، وإثبات رقم الضمان الاجتماعي (Social Security number)، وإثباتين للإقامة في مسيسيبي، بالإضافة إلى اجتياز الاختبارات المطلوبة. المصدر: متطلبات CDL الجديدة لدى MS DPS Driver Service Bureau."},"93":{"q":"ما الحد الأدنى للعمر للحصول على CDL في مسيسيبي مقصورة على القيادة التجارية داخل الولاية (intrastate)؟","options":["18 عامًا","21 عامًا","19 عامًا","16 عامًا"],"explanation":"يجوز للسائق الحصول على CDL للتشغيل داخل الولاية عند سن 18، لكن يجب أن يكون عمره 21 للتشغيل بين الولايات ولنقل المواد الخطرة. المصدر: MS DPS / Mississippi CDL Manual؛ 49 CFR 383.3 / 391.11."},"94":{"q":"ما الحد الأدنى للعمر للحصول على CDL في مسيسيبي للقيادة بين الولايات أو لنقل مواد خطرة موضوعًا عليها لافتات تحذير (placarded)؟","options":["21 عامًا","18 عامًا","23 عامًا","19 عامًا"],"explanation":"تشترط القواعد الفيدرالية التي تتبنّاها مسيسيبي أن يكون عمر السائق 21 على الأقل للعمل في التجارة بين الولايات ولنقل المواد الخطرة الموضوع عليها لافتات تحذير. المصدر: MS DPS / Mississippi CDL Manual؛ 49 CFR 391.11."},"95":{"q":"من يجوز له قانونيًا إجراء اختبار مهارات CDL (على الطريق) في مسيسيبي إلى جانب فاحصي DPS؟","options":["الفاحصون/المختبِرون الخارجيون (Third-Party Testers) المعتمدون من الولاية","أي حامل رخصة CDL لديه سنتان من الخبرة","مدير السلامة لدى صاحب العمل المحتمل للمتقدّم","أي مدرّب صفّي لـ ELDT مسجّل لدى FMCSA"],"explanation":"تسمح مسيسيبي بإجراء اختبار مهارات CDL إما من قبل فاحصي DPS أو من قبل المختبِرين الخارجيين (Third-Party Testers) المعتمدين من الولاية من القائمة التي تحتفظ بها DPS. المصدر: MS DPS Driver Service Bureau (برنامج Third-Party Tester)؛ 49 CFR 383.75."},"96":{"q":"يخفق متقدّم في مسيسيبي في جزء القيادة على الطريق فقط من اختبار مهارات CDL لكنه يجتاز جزأي الفحص قبل الرحلة والتحكّم الأساسي. ما النتيجة العامة؟","options":["يجب على المتقدّم إعادة جزء القيادة على الطريق ولا يحصل بعد على CDL","يحصل المتقدّم تلقائيًا على CDL مقيّدة للقيادة داخل الولاية","يجب إعادة أجزاء المهارات الثلاثة جميعها من البداية","تُصدَر CDL للمتقدّم لأنه اجتاز جزأين من ثلاثة"],"explanation":"يجب اجتياز مكوّنات المهارات الثلاثة جميعها (الفحص قبل الرحلة، والتحكّم الأساسي بالمركبة، والقيادة على الطريق) للحصول على CDL؛ والإخفاق في أي جزء يعني وجوب إعادته، ولا تُصدَر CDL حتى يتم اجتياز الجميع. المصدر: MS DPS / Mississippi CDL Manual؛ 49 CFR 383.113."}}};
